                ? ' Loading profiles...'
                : ` ${amazonSelectorProfileOptions.length} profile${amazonSelectorProfileOptions.length === 1 ? '' : 's'} available.`}
            </div>
            {amazonSelectorRegistryQuery.isError === true ? (
              <div className='text-destructive'>
