const TERMINAL_EXPORT_FEEDBACK_TTL_MS = 30 * 60 * 1000;

const normalizeInventoryId = (value: string | null | undefined): string =>
  typeof value === 'string' ? value.trim() : '';

const resolveFallbackInventoryId = (
  inventories: BaseImportInventoriesResponse['inventories'] | null | undefined
): string => {
  const normalizedInventories = (Array.isArray(inventories) ? inventories : [])
    .map((entry) => ({
      id: normalizeInventoryId(entry.id),
      isDefault: entry.is_default === true,
    }))
    .filter((entry) => entry.id.length > 0);

  const defaultInventory = normalizedInventories.find((entry) => entry.isDefault === true);
  if (defaultInventory !== undefined && defaultInventory.id !== '') return defaultInventory.id;
  if (normalizedInventories.length === 1) {
    const first = normalizedInventories[0];
    return first !== undefined ? first.id : '';
  }
  return '';
};

const resolveBaseConnectionCandidates = (
  integrations: IntegrationWithConnections[] | null | undefined
): string[] => {
  const seen = new Set<string>();
  const candidates: string[] = [];

  for (const integration of Array.isArray(integrations) ? integrations : []) {
    if (integration === null || isBaseIntegrationSlug(integration.slug) === false) continue;
    for (const connection of Array.isArray(integration.connections) ? integration.connections : []) {
      const connectionId = (connection?.id ?? '').trim();
      if (connectionId === '' || seen.has(connectionId) === true) continue;
      seen.add(connectionId);
      candidates.push(connectionId);
    }
  }

  return candidates;
};

const readApiErrorPayload = (error: unknown): Record<string, unknown> | null => {
  if (!(error instanceof ApiError)) return null;
  if (error.payload === null || error.payload === undefined || typeof error.payload !== 'object' || Array.isArray(error.payload)) {
    return null;
  }
  return error.payload as Record<string, unknown>;
};

const readApiErrorCode = (error: unknown): string | null => {
  const payload = readApiErrorPayload(error);
  const code = payload?.['code'];
  return typeof code === 'string' ? code : null;
};

const readApiErrorDetails = (error: unknown): Record<string, unknown> | null => {
  const payload = readApiErrorPayload(error);
  const details = payload?.['details'];
  if (details === null || details === undefined || typeof details !== 'object' || Array.isArray(details)) return null;
  return details as Record<string, unknown>;
};

const readBaseApiErrorCode = (error: unknown): string | null => {
  const details = readApiErrorDetails(error);
  const errorCode = details?.['errorCode'];
  return typeof errorCode === 'string' ? errorCode : null;
};

const shouldIgnoreInventoryLookupError = (
  error: unknown,
  configuredInventoryId: string
): boolean => {
  if (configuredInventoryId === '') return false;

  const baseErrorCode = readBaseApiErrorCode(error);
  if (baseErrorCode === 'ERROR_USER_ACCOUNT_BLOCKED') return false;
  if (baseErrorCode === 'ERROR_UNKNOWN_METHOD') return true;

  const apiErrorCode = readApiErrorCode(error);
  if (apiErrorCode === 'TIMEOUT' || apiErrorCode === 'SERVICE_UNAVAILABLE') return true;
  if (apiErrorCode === 'INTEGRATION_ERROR' || apiErrorCode === 'API_KEY_INVALID') return false;
  if (apiErrorCode === 'UNAUTHORIZED' || apiErrorCode === 'FORBIDDEN') return false;

  if (error instanceof ApiError) {
    return error.status >= 500;
  }

  return true;
};

type QuickExportContext = {
  connectionId: string;
  inventoryId: string;
  templateId: string;
};

type ExistingSkuDecisionState = QuickExportContext & {
  sku: string;
  existingProductId: string | null;
};

type PersistedBaseQuickExportFeedback = {
  productId: string;
  runId: string | null;
  status: TriggerButtonRunFeedbackStatus;
  errorMessage?: string | null;
  expiresAt: number;
};

const TERMINAL_EXPORT_RUN_STATUSES = new Set<TriggerButtonRunFeedbackStatus>([
  'completed',
  'failed',
  'canceled',
]);

const canUseSessionStorage = (): boolean =>
  typeof window !== 'undefined' && typeof window.sessionStorage !== 'undefined';

const resolveExportFeedbackTtlMs = (status: TriggerButtonRunFeedbackStatus): number =>
  TERMINAL_EXPORT_RUN_STATUSES.has(status)
    ? TERMINAL_EXPORT_FEEDBACK_TTL_MS
    : ACTIVE_EXPORT_FEEDBACK_TTL_MS;

const readPersistedBaseQuickExportFeedbackMap = (): Record<string, PersistedBaseQuickExportFeedback> => {
  if (canUseSessionStorage() === false) return {};
  try {
    const raw = window.sessionStorage.getItem(BASE_QUICK_EXPORT_FEEDBACK_STORAGE_KEY);
    if (raw === null || raw === '') return {};
    const parsed = JSON.parse(raw) as unknown;
    if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return {};
    }

    const next: Record<string, PersistedBaseQuickExportFeedback> = {};
    const now = Date.now();

    Object.entries(parsed as Record<string, unknown>).forEach(([productId, value]) => {
      if (value === null || typeof value !== 'object' || Array.isArray(value)) return;
      const record = value as Record<string, unknown>;
      const statusValue = record['status'];
      const status =
        typeof statusValue === 'string'
          ? (statusValue as TriggerButtonRunFeedbackStatus)
          : null;
      const expiresAtValue = record['expiresAt'];
      const expiresAt =
        typeof expiresAtValue === 'number' && Number.isFinite(expiresAtValue)
          ? expiresAtValue
          : 0;
      if (status === null || expiresAt <= now) return;
      next[productId] = {
        productId,
        runId: typeof record['runId'] === 'string' && record['runId'].trim().length > 0
          ? record['runId'].trim()
          : null,
        status,
        errorMessage:
          typeof record['errorMessage'] === 'string' && record['errorMessage'].trim().length > 0
            ? record['errorMessage'].trim()
            : null,
        expiresAt,
      };
    });

    return next;
  } catch {
    return {};
  }
};

const writePersistedBaseQuickExportFeedbackMap = (
  nextMap: Record<string, PersistedBaseQuickExportFeedback>
): void => {
  if (canUseSessionStorage() === false) return;
  try {
    if (Object.keys(nextMap).length === 0) {
      window.sessionStorage.removeItem(BASE_QUICK_EXPORT_FEEDBACK_STORAGE_KEY);
      return;
    }
    window.sessionStorage.setItem(BASE_QUICK_EXPORT_FEEDBACK_STORAGE_KEY, JSON.stringify(nextMap));
  } catch {
    // Best-effort UI persistence only.
  }
};

const readPersistedBaseQuickExportFeedback = (
  productId: string
): PersistedBaseQuickExportFeedback | null => {
  const nextMap = readPersistedBaseQuickExportFeedbackMap();
  const record = nextMap[productId];
  writePersistedBaseQuickExportFeedbackMap(nextMap);
  return record !== undefined ? record : null;
};

const persistBaseQuickExportFeedback = (
  productId: string,
  runId: string | null,
  status: TriggerButtonRunFeedbackStatus,
  errorMessage?: string | null
): void => {
  if (productId.trim() === '') return;
  const nextMap = readPersistedBaseQuickExportFeedbackMap();
  nextMap[productId] = {
    productId,
    runId,
    status,
    errorMessage:
      typeof errorMessage === 'string' && errorMessage.trim().length > 0
        ? errorMessage.trim()
        : null,
    expiresAt: Date.now() + resolveExportFeedbackTtlMs(status),
  };
  writePersistedBaseQuickExportFeedbackMap(nextMap);
};

const clearPersistedBaseQuickExportFeedback = (productId: string): void => {
  if (productId.trim() === '') return;
  const nextMap = readPersistedBaseQuickExportFeedbackMap();
  if (!(productId in nextMap)) return;
  delete nextMap[productId];
  writePersistedBaseQuickExportFeedbackMap(nextMap);
};

export function BaseQuickExportButton(props: {
  product: ProductWithImages;
  status: string;
  prefetchListings: () => void;
  showMarketplaceBadge: boolean;
  onOpenIntegrations?: ((recoveryContext?: ProductListingsRecoveryContext) => void) | undefined;
}): React.JSX.Element {
  const {
    product,
    status,
    prefetchListings,
    showMarketplaceBadge,
    onOpenIntegrations,
  } = props;

  const { toast } = useToast();
  const queryClient = useQueryClient();
  const quickExportMutation = useGenericExportToBaseMutation();
  const quickExportLockRef = useRef(false);
  const trackedExportRunIdRef = useRef<string | null>(null);
  const trackedExportRunUnsubscribeRef = useRef<(() => void) | null>(null);
  const [quickExportLocked, setQuickExportLocked] = useState(false);
  const [existingSkuDecision, setExistingSkuDecision] = useState<ExistingSkuDecisionState | null>(
    null
  );
  const [linkExistingPending, setLinkExistingPending] = useState(false);
  const [trackedExportRunStatus, setTrackedExportRunStatus] =
    useState<TriggerButtonRunFeedbackStatus | null>(null);
  const [trackedExportRunContextId, setTrackedExportRunContextId] = useState<string | null>(null);
  const [trackedExportRunErrorMessage, setTrackedExportRunErrorMessage] = useState<string | null>(
    null
  );

  const stopTrackingExportRun = useCallback((): void => {
    trackedExportRunUnsubscribeRef.current?.();
    trackedExportRunUnsubscribeRef.current = null;
    trackedExportRunIdRef.current = null;
  }, []);

  const setTrackedExportStatus = useCallback(
    (
      newStatus: TriggerButtonRunFeedbackStatus | null,
      options?: { runId?: string | null; errorMessage?: string | null }
    ): void => {
      setTrackedExportRunStatus(newStatus);
      if (newStatus === null) {
        setTrackedExportRunContextId(null);
        setTrackedExportRunErrorMessage(null);
        clearPersistedBaseQuickExportFeedback(product.id);
        return;
      }
      const normalizedRunId = (options?.runId?.trim() ?? '') !== '' ? options!.runId!.trim() : null;
      setTrackedExportRunContextId(normalizedRunId);
      const normalizedErrorMessage =
        typeof options?.errorMessage === 'string' && options.errorMessage.trim().length > 0
          ? options.errorMessage.trim()
          : null;
      setTrackedExportRunErrorMessage(normalizedErrorMessage);
      persistBaseQuickExportFeedback(
        product.id,
        normalizedRunId,
        newStatus,
        normalizedErrorMessage
      );
    },
    [product.id]
  );

  useEffect(
    () => () => {
      stopTrackingExportRun();
    },
    [stopTrackingExportRun]
  );

  const handleTrackedExportRunSnapshot = useCallback(
    (runId: string, snapshot: TrackedAiPathRunSnapshot): void => {
      if (trackedExportRunIdRef.current !== runId) return;
      if (snapshot.trackingState === 'stopped' && !TERMINAL_EXPORT_RUN_STATUSES.has(snapshot.status)) {
        // Tracking ended without a terminal status (timeout or poll failure).
        // Clear state so the button falls back to the server-backed badge instead of hanging yellow.
        stopTrackingExportRun();
        setTrackedExportStatus(null);
        return;
      }
      setTrackedExportStatus(snapshot.status, {
        runId,
        errorMessage: snapshot.errorMessage,
      });
      if (
        snapshot.trackingState === 'stopped' ||
        TERMINAL_EXPORT_RUN_STATUSES.has(snapshot.status)
      ) {
        stopTrackingExportRun();
      }
    },
    [setTrackedExportStatus, stopTrackingExportRun]
  );

  const startTrackingExportRun = useCallback(
    (runId: string, initialStatus: TriggerButtonRunFeedbackStatus): void => {
      const normalizedRunId = runId.trim();
      if (normalizedRunId === '') {
        setTrackedExportStatus(initialStatus, { runId: null });
        return;
      }

      if (trackedExportRunIdRef.current !== normalizedRunId) {
        stopTrackingExportRun();
        trackedExportRunIdRef.current = normalizedRunId;
      }

      setTrackedExportStatus(initialStatus, { runId: normalizedRunId });
      if (TERMINAL_EXPORT_RUN_STATUSES.has(initialStatus)) {
        stopTrackingExportRun();
        return;
      }
      trackedExportRunUnsubscribeRef.current = subscribeToTrackedAiPathRun(
        normalizedRunId,
        (snapshot: TrackedAiPathRunSnapshot): void => {
          handleTrackedExportRunSnapshot(normalizedRunId, snapshot);
        },
        {
          initialSnapshot: {
            runId: normalizedRunId,
            status: initialStatus === 'waiting' ? 'queued' : initialStatus,
            entityId: product.id,
            entityType: 'product',
          },
        }
      );
    },
    [handleTrackedExportRunSnapshot, product.id, setTrackedExportStatus, stopTrackingExportRun]
  );

  useEffect(() => {
    const persistedFeedback = readPersistedBaseQuickExportFeedback(product.id);
    if (persistedFeedback === null) {
      return;
    }

    trackedExportRunIdRef.current = persistedFeedback.runId;
    setTrackedExportRunStatus(persistedFeedback.status);
    setTrackedExportRunContextId(persistedFeedback.runId);
    setTrackedExportRunErrorMessage(persistedFeedback.errorMessage ?? null);
    if (
      persistedFeedback.runId !== null &&
      TERMINAL_EXPORT_RUN_STATUSES.has(persistedFeedback.status) === false
    ) {
      startTrackingExportRun(persistedFeedback.runId, persistedFeedback.status);
    }
  }, [product.id, startTrackingExportRun]);

  useEffect(() => {
    if (showMarketplaceBadge === false) return;
    if (trackedExportRunStatus === null) return;
    if (TERMINAL_EXPORT_RUN_STATUSES.has(trackedExportRunStatus) === false) return;

    // Once the list runtime confirms the product is exported, the server-backed
    // listing badge becomes the source of truth and stale terminal client-run
    // feedback should no longer override the button tone.
    stopTrackingExportRun();
    setTrackedExportStatus(null);
  }, [setTrackedExportStatus, showMarketplaceBadge, stopTrackingExportRun, trackedExportRunStatus]);

  const resolveQuickExportContext = async (): Promise<QuickExportContext | null> => {
    try {
      const [preferredConnection, defaultInventory, integrationsWithConnections] =
        await Promise.all([
        fetchQueryV2<BaseDefaultConnectionPreferenceResponse>(queryClient, {
          queryKey: normalizeQueryKey(integrationSelectionQueryKeys.defaultConnection),
          queryFn: async () => await fetchPreferredBaseConnection(),
          staleTime: INTEGRATION_SELECTION_STALE_TIME_MS,
          meta: {
            source: 'products.columns.buttons.BaseQuickExport.resolveContext.preferredConnection',
            operation: 'detail',
            resource: 'integrations.default-connection',
            domain: 'integrations',
            queryKey: normalizeQueryKey(integrationSelectionQueryKeys.defaultConnection),
            tags: ['integrations', 'default-connection', 'fetch'],
            description: 'Loads integrations default connection.'},
        })(),
        fetchQueryV2<BaseDefaultInventoryPreferenceResponse>(queryClient, {
          queryKey: normalizeQueryKey(defaultExportInventoryQueryKey),
          queryFn: async () =>
            await api.get<BaseDefaultInventoryPreferenceResponse>(
              '/api/v2/integrations/exports/base/default-inventory'
            ),
          staleTime: INTEGRATION_SELECTION_STALE_TIME_MS,
          meta: {
            source: 'products.columns.buttons.BaseQuickExport.resolveContext.defaultInventory',
            operation: 'detail',
            resource: 'integrations.default-inventory',
            domain: 'integrations',
            queryKey: normalizeQueryKey(defaultExportInventoryQueryKey),
            tags: ['integrations', 'default-inventory', 'fetch'],
            description: 'Loads integrations default inventory.'},
        })(),
        fetchQueryV2<IntegrationWithConnections[]>(queryClient, {
          queryKey: normalizeQueryKey(integrationSelectionQueryKeys.withConnections),
          queryFn: async () => await fetchIntegrationsWithConnections(),
          staleTime: INTEGRATION_SELECTION_STALE_TIME_MS,
          meta: {
            source: 'products.columns.buttons.BaseQuickExport.resolveContext.integrationsWithConnections',
            operation: 'list',
            resource: 'integrations.with-connections',
            domain: 'integrations',
            queryKey: normalizeQueryKey(integrationSelectionQueryKeys.withConnections),
            tags: ['integrations', 'with-connections', 'fetch'],
            description: 'Loads integrations with connections for one-click export fallback.',
          },
        })().catch(() => [] as IntegrationWithConnections[]),
        ]);

      const preferredConnectionId = (preferredConnection?.connectionId?.trim() ?? '');
      const availableBaseConnectionIds = resolveBaseConnectionCandidates(integrationsWithConnections);
      let connectionId = preferredConnectionId;

      if (connectionId === '') {
        connectionId =
          availableBaseConnectionIds.length === 1 ? availableBaseConnectionIds[0] ?? '' : '';
      } else if (
        availableBaseConnectionIds.length > 0 &&
        availableBaseConnectionIds.includes(connectionId) === false
      ) {
        connectionId =
          availableBaseConnectionIds.length === 1 ? availableBaseConnectionIds[0] ?? '' : '';
      }

      if (connectionId === '') {
        toast('Set a default Base.com connection first.', { variant: 'error' });
        return null;
      }

      if (connectionId !== preferredConnectionId) {
        void api
          .post<BaseDefaultConnectionPreferenceResponse>(
            '/api/v2/integrations/exports/base/default-connection',
            { connectionId }
          )
          .catch(() => undefined);
      }

      const configuredInventoryId = normalizeInventoryId(defaultInventory?.inventoryId);
      let fallbackInventoryId = '';
      let availableInventoryIds = new Set<string>();

      try {
        const inventoriesResponse = await api.post<BaseImportInventoriesResponse>(
          '/api/v2/integrations/imports/base',
          {
            action: 'inventories',
            connectionId,
          } satisfies BaseImportInventoriesPayload
        );
        fallbackInventoryId = resolveFallbackInventoryId(inventoriesResponse.inventories);
        availableInventoryIds = new Set(
          (Array.isArray(inventoriesResponse.inventories) ? inventoriesResponse.inventories : [])
            .map((entry) => normalizeInventoryId(entry.id))
            .filter((value) => value.length > 0)
        );
      } catch (error) {
        if (shouldIgnoreInventoryLookupError(error, configuredInventoryId) === false) {
          throw error;
        }
      }

      let inventoryId = configuredInventoryId;

      if (inventoryId === '') {
        inventoryId = fallbackInventoryId;
      } else if (availableInventoryIds.size > 0 && availableInventoryIds.has(inventoryId) === false) {
        inventoryId = fallbackInventoryId;
      }

      if (inventoryId === '') {
        const message = configuredInventoryId !== ''
          ? 'Configured Base.com inventory is not available for this connection. Open Export Settings and select a valid inventory.'
          : 'Specific Base.com inventory is not configured. Open Export Settings and set inventory.';
        toast(message, { variant: 'error' });
        return null;
      }

      if (inventoryId !== configuredInventoryId) {
        void api
          .post<BaseDefaultInventoryPreferenceResponse>(
            '/api/v2/integrations/exports/base/default-inventory',
            { inventoryId }
          )
          .catch(() => undefined);
      }

      let templateId = '';
      try {
        const scopedTemplate = await api.get<BaseActiveTemplatePreferenceResponse>(
          `/api/v2/integrations/exports/base/active-template?connectionId=${encodeURIComponent(connectionId)}&inventoryId=${encodeURIComponent(inventoryId)}`
        );
        templateId = scopedTemplate?.templateId?.trim() ?? '';
      } catch {
        // Best-effort only. Export can proceed without a scoped template.
      }

      return {
        connectionId,
        inventoryId,
        templateId,
      };
    } catch (error) {
      logClientError(error);
      toast(
        error instanceof Error && error.message.trim().length > 0
          ? error.message
          : 'Failed to load Base.com export defaults.',
        { variant: 'error' }
      );
      return null;
    }
  };

  const runQuickExportMutation = async (context: QuickExportContext): Promise<void> => {
    const payload: {
      productId: string;
      connectionId: string;
      inventoryId: string;
      templateId?: string;
      requestId?: string;
    } = {
      productId: product.id,
      connectionId: context.connectionId,
      inventoryId: context.inventoryId,
      requestId: `one-click:${product.id}:${context.connectionId}:${context.inventoryId}:${Math.floor(Date.now() / 30000)}`,
    };

    if (context.templateId !== '') {
      payload.templateId = context.templateId;
    }

    try {
      const response = await quickExportMutation.mutateAsync(payload);
      const normalizedRunId = response?.runId?.trim() ?? '';
      const initialRunStatus: TriggerButtonRunFeedbackStatus =
        response?.status === 'completed' || response?.status === 'failed'
          ? response.status
          : 'queued';

      if (normalizedRunId !== '') {
        startTrackingExportRun(normalizedRunId, initialRunStatus);
      } else if ((response?.status ?? null) !== null) {
        setTrackedExportStatus(initialRunStatus, { runId: null });
      }

      prefetchListings();
      toast(
        response?.status === 'queued'
          ? 'Base.com export queued.'
          : 'Base.com export started.',
        { variant: 'success' }
      );
    } catch (error) {
      logClientError(error);
      const message = error instanceof Error ? error.message : 'Failed to export to Base.com.';
      toast(message, { variant: 'error' });
    }
  };

  const runQuickExport = async (): Promise<void> => {
    const preflightError = getBaseExportPreflightError(product.categoryId);
    if (preflightError !== null) {
      toast(preflightError, { variant: 'error' });
      return;
    }

    if (
      quickExportLockRef.current === true ||
      quickExportMutation.isPending === true ||
      oneClickExportInFlight.has(product.id) === true
    ) {
      return;
    }

    quickExportLockRef.current = true;
    setQuickExportLocked(true);
    oneClickExportInFlight.add(product.id);

    try {
      const context = await resolveQuickExportContext();
      if (context === null) {
        quickExportLockRef.current = false;
        setQuickExportLocked(false);
        oneClickExportInFlight.delete(product.id);
        return;
      }

      if (showMarketplaceBadge === false) {
        const sku = (product.sku ?? '').trim();
        if (sku !== '') {
          let skuCheck: BaseProductSkuCheckResponse;
          try {
            skuCheck = await api.post<BaseProductSkuCheckResponse>(
              `/api/v2/integrations/products/${product.id}/base/sku-check`,
              {
                connectionId: context.connectionId,
                inventoryId: context.inventoryId,
              } satisfies BaseProductSkuCheckPayload
            );
          } catch (error) {
            logClientError(error);
            const message =
              error instanceof Error
                ? error.message
                : 'Failed to verify SKU in Base.com. Export was not started.';
            toast(message, { variant: 'error' });
            quickExportLockRef.current = false;
            setQuickExportLocked(false);
            oneClickExportInFlight.delete(product.id);
            return;
          }

          if (skuCheck.exists === true) {
            setExistingSkuDecision({
              ...context,
              sku: (skuCheck.sku ?? sku).trim() !== '' ? skuCheck.sku!.trim() : sku,
              existingProductId: (skuCheck.existingProductId?.trim() ?? '') !== '' ? skuCheck.existingProductId!.trim() : null,
            });
            quickExportLockRef.current = false;
            setQuickExportLocked(false);
            oneClickExportInFlight.delete(product.id);
            return;
          }
        }
      }

      await runQuickExportMutation(context);
      quickExportLockRef.current = false;
      setQuickExportLocked(false);
      oneClickExportInFlight.delete(product.id);
    } catch (error) {
      quickExportLockRef.current = false;
      setQuickExportLocked(false);
      oneClickExportInFlight.delete(product.id);
      throw error;
    }
  };

  const handleCloseDecisionModal = (): void => {
    if (linkExistingPending === true) return;
    setExistingSkuDecision(null);
  };

  const handleSetupNewConnection = (): void => {
    setExistingSkuDecision(null);
    if (onOpenIntegrations !== undefined) {
      onOpenIntegrations();
      return;
    }
    toast('Open integrations to set up a new Base.com connection.', {
      variant: 'info',
    });
  };

  const handleLinkExistingProduct = async (): Promise<void> => {
    if (existingSkuDecision === null) return;
    if (linkExistingPending === true) return;

    const externalListingId = (existingSkuDecision.existingProductId?.trim() ?? '');
    if (externalListingId === '') {
      toast('Existing Base.com product ID is missing. Use "Set up new connection" instead.', {
        variant: 'error',
      });
      return;
    }

    setLinkExistingPending(true);
    try {
      await api.post<BaseProductLinkExistingResponse>(
        `/api/v2/integrations/products/${product.id}/base/link-existing`,
        {
          connectionId: existingSkuDecision.connectionId,
          inventoryId: existingSkuDecision.inventoryId,
          externalListingId,
        } satisfies BaseProductLinkExistingPayload
      );

      prefetchListings();
      await invalidateProductListingsAndBadges(queryClient, product.id);
      setExistingSkuDecision(null);
      toast('Linked to existing Base.com product.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      const message =
        error instanceof Error
          ? error.message
          : 'Failed to link product to existing Base.com listing.';
      toast(message, { variant: 'error' });
    } finally {
      setLinkExistingPending(false);
    }
  };

  const label = 'One-click export to Base.com';

  const trackedExportPresentation = trackedExportRunStatus !== null
    ? resolveTriggerButtonRunFeedbackPresentation(trackedExportRunStatus)
    : null;
  const trackedExportInFlight =
    trackedExportRunStatus !== null && TERMINAL_EXPORT_RUN_STATUSES.has(trackedExportRunStatus) === false;
  const quickExportPending = quickExportMutation.isPending === true || quickExportLocked === true || trackedExportInFlight === true;
  const resolvedButtonStatus = trackedExportRunStatus ?? status;
  const normalizedResolvedButtonStatus = normalizeMarketplaceStatus(resolvedButtonStatus);
  const isFailureState = FAILURE_STATUSES.has(normalizedResolvedButtonStatus);
  const isServerInProgressState =
    PENDING_STATUSES.has(normalizedResolvedButtonStatus) ||
    PROCESSING_STATUSES.has(normalizedResolvedButtonStatus);
  const shouldManageExistingListing =
    isFailureState === false &&
    isServerInProgressState === false &&
    (showMarketplaceBadge === true || SUCCESS_STATUSES.has(normalizedResolvedButtonStatus));
  const shouldUseFilledMarketplaceTone = showMarketplaceBadge === true || trackedExportRunStatus !== null;

  let resolvedLabel = label;
  if (isFailureState === true) {
    resolvedLabel = `Open Base.com recovery options (${resolvedButtonStatus}).`;
  } else if (shouldManageExistingListing === true) {
    resolvedLabel = `Manage Base.com listing (${resolvedButtonStatus}).`;
  } else if (trackedExportPresentation !== null) {
    resolvedLabel = `Base.com export ${trackedExportPresentation.label.toLowerCase()}.`;
  }

  const recoveryContext: ProductListingsRecoveryContext | undefined = isFailureState === true
    ? createBaseRecoveryContext({
      status: resolvedButtonStatus,
      runId: trackedExportRunContextId,
      failureReason: trackedExportRunErrorMessage,
    })
    : undefined;

  return (
    <>
      <Button
        type='button'
        disabled={quickExportPending}
        onClick={(): void => {
          if (isFailureState === true) {
            if (onOpenIntegrations !== undefined) {
              onOpenIntegrations(recoveryContext);
            }
            return;
          }
          if (shouldManageExistingListing === true) {
            if (onOpenIntegrations !== undefined) {
              onOpenIntegrations();
            }
            return;
          }
          runQuickExport().catch((error: unknown) => {
            logClientError(error);
          });
        }}
        onMouseEnter={prefetchListings}
        onFocus={prefetchListings}
        variant='ghost'
        size='icon'
        aria-label={resolvedLabel}
        title={resolvedLabel}
        className={cn(
          'size-8 rounded-full border border-transparent bg-transparent p-0 hover:bg-transparent',
          showMarketplaceBadge === false && quickExportPending === true && 'cursor-not-allowed opacity-60',
          getMarketplaceButtonClass(resolvedButtonStatus, shouldUseFilledMarketplaceTone, 'base')
        )}
      >
        <span
          aria-hidden='true'
          className='text-[9px] font-black uppercase leading-none tracking-tight'
        >
          {quickExportPending === true ? '...' : 'BL'}
        </span>
      </Button>

      <AppModal
        open={existingSkuDecision !== null}
        onOpenChange={(open) => {
          if (open === false) handleCloseDecisionModal();
        }}
        onClose={handleCloseDecisionModal}
        title='SKU already exists in Base.com'
        subtitle='Choose whether to link this product or start a new connection flow.'
        size='sm'
      >
        <div className='space-y-4'>
          <p className='text-sm text-gray-300'>
            SKU <span className='font-mono text-white'>{existingSkuDecision?.sku ?? '—'}</span>{' '}
            already exists in the selected Base.com inventory.
          </p>

          <InsetPanel radius='compact' padding='sm' className='text-xs text-gray-300'>
            Existing Base product ID:{' '}
            <span className='font-mono text-white'>
              {existingSkuDecision?.existingProductId ?? 'Unavailable'}
            </span>
          </InsetPanel>

          {existingSkuDecision?.existingProductId === null || existingSkuDecision?.existingProductId === undefined || existingSkuDecision.existingProductId === '' ? (
            <p className='text-xs text-amber-300'>
              Could not resolve existing Base.com product ID. Linking is disabled. Use "Set up new
              connection".
            </p>
          ) : null}

          <div className='flex items-center justify-end gap-2 border-t border-border/60 pt-2'>
            <Button
              type='button'
              variant='outline'
              onClick={handleCloseDecisionModal}
              disabled={linkExistingPending}
            >
              Cancel
            </Button>
            <Button
              type='button'
              variant='outline'
              onClick={handleSetupNewConnection}
              disabled={linkExistingPending}
            >
              Set up new connection
            </Button>
            <Button
              type='button'
              onClick={(): void => {
                handleLinkExistingProduct().catch((error: unknown) => {
                  logClientError(error);
                });
              }}
              disabled={linkExistingPending === true || (existingSkuDecision?.existingProductId ?? '') === ''}
            >
              {linkExistingPending === true ? 'Linking...' : 'Link existing product'}
            </Button>
          </div>
        </div>
      </AppModal>
    </>
  );
}

import type { ProductWithImages } from '@/shared/contracts/products/product';

export type ProductNameKey = 'name_en' | 'name_pl' | 'name_de';

const NAME_KEY_TO_LANGUAGE_CODE: Record<ProductNameKey, string> = {
  name_en: 'en',
  name_pl: 'pl',
  name_de: 'de',
};

export const toTrimmedString = (value: unknown): string => {
  if (typeof value !== 'string') return '';
  return value.trim();
};

const toRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

const toDisplayString = (value: unknown): string => {
  if (typeof value === 'string') return value.trim();
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  if (typeof value === 'boolean') return value ? 'true' : 'false';
  return '';
};

const toDisplayListString = (value: unknown): string => {
  if (Array.isArray(value)) {
    const parts = value.map((entry: unknown) => toDisplayListString(entry)).filter(Boolean);
    return parts.join(', ');
  }
  return toDisplayString(value);
};

const splitDisplaySegments = (value: string): string[] =>
  value
    .split('|')
    .map((segment: string) => segment.trim())
    .filter(Boolean);

export const getProductNameValue = (
  product: ProductWithImages,
  key: ProductNameKey
): string | undefined => {
  const value = product[key];
  if (typeof value === 'string' && value.trim().length > 0) return value;

  const localizedName = toTrimmedString(toRecord(product.name)?.[NAME_KEY_TO_LANGUAGE_CODE[key]]);
  return localizedName || undefined;
};

export const getProductDisplayName = (product: ProductWithImages): string =>
  getProductNameValue(product, 'name_en') ??
  getProductNameValue(product, 'name_pl') ??
  getProductNameValue(product, 'name_de') ??
  'Product';

export const getImageFilepath = (imageFile: unknown): string | undefined => {
  if (!imageFile || typeof imageFile !== 'object') return undefined;
  const filepath = (imageFile as { filepath?: unknown }).filepath;
  return typeof filepath === 'string' && filepath.trim().length > 0 ? filepath : undefined;
};

const getProductParameterDisplayValue = (parameter: unknown, key: ProductNameKey): string => {
  const record = toRecord(parameter);
  if (!record) return '';

  const directValue = toDisplayListString(record['value']);
  const valuesByLanguageRecord = toRecord(record['valuesByLanguage']) ?? {};
  const preferredLanguageCode = NAME_KEY_TO_LANGUAGE_CODE[key];

  for (const candidate of [preferredLanguageCode, 'en', 'pl', 'de', 'default']) {
    const localizedValue = toDisplayListString(valuesByLanguageRecord[candidate]);
    if (localizedValue) return localizedValue;
  }

  for (const candidate of [preferredLanguageCode, 'en', 'pl', 'de']) {
    const legacyLocalizedValue = toDisplayListString(record[`value_${candidate}`]);
    if (legacyLocalizedValue) return legacyLocalizedValue;
  }

  for (const localizedValue of Object.values(valuesByLanguageRecord)) {
    const normalizedValue = toDisplayListString(localizedValue);
    if (normalizedValue) return normalizedValue;
  }

  return directValue;
};

export const getProductListDisplayName = (
  product: ProductWithImages,
  key: ProductNameKey,
): string => {
  const rawBaseName = getProductNameValue(product, key) ?? '';
  if (!rawBaseName) return '';

  const parsedNameParts = rawBaseName
    .split('|')
    .map((part: string) => part.trim())
    .filter(Boolean);

  // If the product already has a composed title, treat it as canonical.
  // Rebuilding it from parameters can replace correct locale-specific segments
  // with incomplete fallback parameter values from another language.
  if (parsedNameParts.length > 1) {
    return rawBaseName;
  }

  const baseName = parsedNameParts[0] || rawBaseName;

  const seenValues = new Set<string>([baseName.trim().toLowerCase()]);
  const parameterValues = Array.isArray(product.parameters)
    ? product.parameters.reduce((acc: string[], parameter: unknown) => {
        const resolvedValue = getProductParameterDisplayValue(parameter, key).trim();
        if (!resolvedValue) return acc;

        for (const segment of splitDisplaySegments(resolvedValue)) {
          const signature = segment.toLowerCase();
          if (!segment || seenValues.has(signature)) continue;
          seenValues.add(signature);
          acc.push(segment);
        }
        return acc;
      }, [])
    : [];

  return parameterValues.length > 0 ? [baseName, ...parameterValues].join(' | ') : baseName;
};

const OPAQUE_CATEGORY_ID_PATTERN =
  /^(?:[a-f0-9]{24}|[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12})$/i;
export const UNASSIGNED_PRODUCT_CATEGORY_LABEL = 'Unassigned';

const CATEGORY_NAME_KEYS_BY_LOCALE: Record<ProductNameKey, string[]> = {
  name_en: ['name_en', 'name', 'name_pl', 'name_de'],
  name_pl: ['name_pl', 'name', 'name_en', 'name_de'],
  name_de: ['name_de', 'name', 'name_en', 'name_pl'],
};

const resolveProductCategoryRecord = (product: ProductWithImages): Record<string, unknown> | null => {
  const record = toRecord(product);
  if (!record) return null;
  return toRecord(record['category']);
};

const resolveCategoryLabelFromRecord = (
  categoryRecord: Record<string, unknown> | null,
  preferredLocale: ProductNameKey
): string => {
  if (!categoryRecord) return '';
  const keys = CATEGORY_NAME_KEYS_BY_LOCALE[preferredLocale] ?? CATEGORY_NAME_KEYS_BY_LOCALE.name_en;
  for (const key of keys) {
    const value = toTrimmedString(categoryRecord[key]);
    if (value) return value;
  }
  return '';
};

export const resolveProductCategoryId = (product: ProductWithImages): string => {
  const direct = toTrimmedString(product.categoryId);
  if (direct) return direct;

  const categoryRecord = resolveProductCategoryRecord(product);
  if (!categoryRecord) return '';

  return (
    toTrimmedString(categoryRecord['id']) ||
    toTrimmedString(categoryRecord['_id']) ||
    toTrimmedString(categoryRecord['categoryId'])
  );
};

export const resolveProductCategoryLabel = (
  product: ProductWithImages,
  categoryNameById: ReadonlyMap<string, string>,
  preferredLocale: ProductNameKey = 'name_en'
): string => {
  const normalizedCategoryId = resolveProductCategoryId(product);
  const categoryRecord = resolveProductCategoryRecord(product);
  const directLabel = resolveCategoryLabelFromRecord(categoryRecord, preferredLocale);
  const resolvedLookupLabel = normalizedCategoryId
    ? toTrimmedString(categoryNameById.get(normalizedCategoryId))
    : '';

  if (directLabel) return directLabel;
  if (resolvedLookupLabel) return resolvedLookupLabel;
  if (!normalizedCategoryId) return UNASSIGNED_PRODUCT_CATEGORY_LABEL;
  return OPAQUE_CATEGORY_ID_PATTERN.test(normalizedCategoryId) ? '—' : normalizedCategoryId;
};

export const isUnassignedProductCategoryLabel = (label: string): boolean =>
  label.trim() === UNASSIGNED_PRODUCT_CATEGORY_LABEL;

export const resolveEffectiveDefaultPriceGroupId = (
  product: ProductWithImages,
  catalogDefaultPriceGroupIdByCatalogId: ReadonlyMap<string, string>
): string | null => {
  const directDefaultPriceGroupId = toTrimmedString(product.defaultPriceGroupId);
  if (directDefaultPriceGroupId) {
    return directDefaultPriceGroupId;
  }

  const productCatalogId =
    toTrimmedString(product.catalogId) ||
    toTrimmedString(product.catalogs?.[0]?.catalogId);
  if (!productCatalogId) {
    return null;
  }

  const catalogDefaultPriceGroupId = toTrimmedString(
    catalogDefaultPriceGroupIdByCatalogId.get(productCatalogId)
  );
  return catalogDefaultPriceGroupId || null;
};

export const hasImportedProductOrigin = (product: ProductWithImages): boolean =>
  typeof product.importSource === 'string' && product.importSource.trim().length > 0;

export const hasFilledMarketplaceCopy = (product: ProductWithImages): boolean => {
  const overrides = Array.isArray(product.marketplaceContentOverrides)
    ? product.marketplaceContentOverrides
    : [];

  return overrides.some((entry) => {
    const hasIntegration = Array.isArray(entry.integrationIds)
      ? entry.integrationIds.some((integrationId: string) => toTrimmedString(integrationId) !== '')
      : false;
    const hasCopy = toTrimmedString(entry.title) !== '' || toTrimmedString(entry.description) !== '';

    return hasIntegration && hasCopy;
  });
};

export const hasEnglishProductTitle = (product: ProductWithImages): boolean =>
  Boolean(getProductNameValue(product, 'name_en'));

export const hasEnglishProductDescription = (product: ProductWithImages): boolean =>
  toTrimmedString(product.description_en) !== '' ||
  toTrimmedString(toRecord(product.description)?.['en']) !== '';

export const hasPolishProductTitle = (product: ProductWithImages): boolean =>
  Boolean(getProductNameValue(product, 'name_pl'));

export const hasPolishProductDescription = (product: ProductWithImages): boolean =>
  toTrimmedString(product.description_pl) !== '' ||
  toTrimmedString(toRecord(product.description)?.['pl']) !== '';
import {
  SUCCESS_STATUSES,
  CLOSED_STATUSES,
  PENDING_STATUSES,
  PROCESSING_STATUSES,
  FAILURE_STATUSES,
  normalizeMarketplaceStatus,
} from '@/features/integrations/utils/marketplace-status';

export {
  SUCCESS_STATUSES,
  CLOSED_STATUSES,
  PENDING_STATUSES,
  PROCESSING_STATUSES,
  FAILURE_STATUSES,
  normalizeMarketplaceStatus,
};

export const resolveMarketplaceStatusWithLocalFeedback = ({
  serverStatus,
  localFeedbackStatus,
  submitting = false,
}: {
  serverStatus: string;
  localFeedbackStatus: string | null;
  submitting?: boolean;
}): string => {
  const normalizedServerStatus = normalizeMarketplaceStatus(serverStatus);
  const normalizedLocalFeedbackStatus = normalizeMarketplaceStatus(localFeedbackStatus ?? '');
  const hasServerStatus =
    normalizedServerStatus.length > 0 && normalizedServerStatus !== 'not_started';

  if (submitting) {
    return 'processing';
  }

  if (
    normalizedLocalFeedbackStatus === 'completed' &&
    !SUCCESS_STATUSES.has(normalizedServerStatus)
  ) {
    return 'active';
  }

  if (
    (normalizedLocalFeedbackStatus === 'processing' ||
      normalizedLocalFeedbackStatus === 'queued') &&
    FAILURE_STATUSES.has(normalizedServerStatus)
  ) {
    return normalizedLocalFeedbackStatus;
  }

  if (
    FAILURE_STATUSES.has(normalizedLocalFeedbackStatus) &&
    (PENDING_STATUSES.has(normalizedServerStatus) ||
      PROCESSING_STATUSES.has(normalizedServerStatus))
  ) {
    return normalizedLocalFeedbackStatus;
  }

  if (hasServerStatus) {
    return normalizedServerStatus;
  }

  return normalizedLocalFeedbackStatus || 'not_started';
};

export const getStatusToneClass = (value: string): string => {
  const normalized = normalizeMarketplaceStatus(value);
  if (SUCCESS_STATUSES.has(normalized)) {
    return 'border-emerald-400/60 text-emerald-200 hover:border-emerald-300/70 hover:text-emerald-100';
  }
  if (PENDING_STATUSES.has(normalized)) {
    return 'border-amber-400/60 text-amber-200 hover:border-amber-300/70 hover:text-amber-100';
  }
  if (PROCESSING_STATUSES.has(normalized)) {
    return 'border-cyan-400/60 text-cyan-200 hover:border-cyan-300/70 hover:text-cyan-100';
  }
  if (CLOSED_STATUSES.has(normalized)) {
    return 'border-blue-500/70 text-blue-200 hover:border-blue-400/80 hover:text-blue-100';
  }
  if (FAILURE_STATUSES.has(normalized)) {
    return 'border-rose-400/60 text-rose-200 hover:border-rose-300/70 hover:text-rose-100';
  }
  return 'border-gray-500/50 text-gray-300 hover:border-gray-400/60 hover:text-gray-200';
};

export const getMarketplaceButtonClass = (
  value: string,
  manageMode: boolean,
  marketplace: 'base' | 'tradera' | 'playwright' | 'vinted'
): string => {
  if (!manageMode) {
    return getStatusToneClass(value);
  }
  const normalized = normalizeMarketplaceStatus(value);
  if (SUCCESS_STATUSES.has(normalized)) {
    return 'border-emerald-400/70 bg-emerald-500/15 text-emerald-100 hover:border-emerald-300/80 hover:bg-emerald-500/25';
  }
  if (PENDING_STATUSES.has(normalized)) {
    return 'border-amber-400/70 bg-amber-500/15 text-amber-100 hover:border-amber-300/80 hover:bg-amber-500/25';
  }
  if (PROCESSING_STATUSES.has(normalized)) {
    return 'border-cyan-400/70 bg-cyan-500/15 text-cyan-100 hover:border-cyan-300/80 hover:bg-cyan-500/25';
  }
  if (CLOSED_STATUSES.has(normalized)) {
    return 'border-blue-700/80 bg-blue-950/45 text-blue-100 hover:border-blue-600/90 hover:bg-blue-900/45';
  }
  if (FAILURE_STATUSES.has(normalized)) {
    return 'border-rose-400/70 bg-rose-500/15 text-rose-100 hover:border-rose-300/80 hover:bg-rose-500/25';
  }
  if (marketplace === 'playwright') {
    return 'border-fuchsia-400/70 bg-fuchsia-500/15 text-fuchsia-100 hover:border-fuchsia-300/80 hover:bg-fuchsia-500/25';
  }
  if (marketplace === 'vinted') {
    return 'border-teal-400/70 bg-teal-500/15 text-teal-100 hover:border-teal-300/80 hover:bg-teal-500/25';
  }
  return 'border-sky-400/70 bg-sky-500/15 text-sky-100 hover:border-sky-300/80 hover:bg-sky-500/25';
};

'use client';

import type {
  ProductScanRecord,
  ProductScanSupplierPrice,
} from '@/shared/contracts/product-scans';
import { Button } from '@/shared/ui/button';
import { resolveProductScan1688ApplyPolicySummary } from '@/features/products/components/scans/ProductScan1688Details';

type ProductScan1688ApplyField = 'supplierName' | 'supplierLink' | 'priceComment';

export type ProductScan1688FormBindings = {
  getTextFieldValue: (
    field: ProductScan1688ApplyField
  ) => string | null | undefined;
  applyTextField: (field: ProductScan1688ApplyField, value: string) => void;
  imageLinks?: string[] | null;
  imageBase64s?: string[] | null;
  setImageLinkAt?: (index: number, value: string) => void;
  setImageBase64At?: (index: number, value: string) => void;
};

type ProductScan1688ApplyPanelProps = {
  scan: Pick<ProductScanRecord, 'url' | 'supplierDetails' | 'supplierEvaluation'>;
  formBindings: ProductScan1688FormBindings | null;
};

const normalizeComparableText = (value: string | null | undefined): string | null => {
  if (typeof value !== 'string') {
    return null;
  }

  const normalized = value.trim();
  return normalized.length > 0 ? normalized : null;
};

const buildInlineSummary = (...values: Array<string | null | undefined>): string | null => {
  const entries = values
    .map((value) => normalizeComparableText(value))
    .filter((value): value is string => Boolean(value));

  return entries.length > 0 ? entries.join(' · ') : null;
};

const formatSupplierPriceTier = (price: ProductScanSupplierPrice): string | null =>
  buildInlineSummary(
    price.label,
    price.amount && price.currency ? `${price.amount} ${price.currency}` : price.amount,
    price.rangeStart && price.rangeEnd ? `${price.rangeStart} - ${price.rangeEnd}` : null,
    price.moq ? `MOQ ${price.moq}` : null,
    price.unit
  );

const buildSupplierProductLinkValue = (
  scan: Pick<ProductScanRecord, 'url' | 'supplierDetails'>
): string | null =>
  normalizeComparableText(scan.supplierDetails?.supplierProductUrl) ??
  normalizeComparableText(scan.url);

const buildSupplierStoreLinkValue = (
  scan: Pick<ProductScanRecord, 'supplierDetails'>
): string | null => normalizeComparableText(scan.supplierDetails?.supplierStoreUrl);

const buildSupplierPriceCommentValue = (
  scan: Pick<ProductScanRecord, 'supplierDetails'>
): string | null => {
  const primaryPrice =
    normalizeComparableText(scan.supplierDetails?.priceText) ??
    normalizeComparableText(scan.supplierDetails?.priceRangeText);
  const summary = buildInlineSummary(
    primaryPrice,
    scan.supplierDetails?.moqText
  );
  if (summary) {
    return summary;
  }

  const firstTier = Array.isArray(scan.supplierDetails?.prices)
    ? scan.supplierDetails.prices
        .map((price: ProductScanSupplierPrice) => formatSupplierPriceTier(price))
        .find((value): value is string => Boolean(value))
    : null;

  return firstTier ?? null;
};

const buildSupplierPriceTierValues = (
  scan: Pick<ProductScanRecord, 'supplierDetails'>
): string[] => {
  const seen = new Set<string>();
  const tiers: string[] = [];

  for (const price of Array.isArray(scan.supplierDetails?.prices) ? scan.supplierDetails.prices : []) {
    const formattedTier = formatSupplierPriceTier(price);
    if (!formattedTier || seen.has(formattedTier)) {
      continue;
    }
    seen.add(formattedTier);
    tiers.push(formattedTier);
  }

  return tiers;
};

const buildDetailedSupplierPriceCommentValue = (
  scan: Pick<ProductScanRecord, 'supplierDetails'>
): string | null => {
  const tiers = buildSupplierPriceTierValues(scan);
  if (tiers.length === 0) {
    return null;
  }

  return tiers.join('; ');
};

const normalizeSupplierImageUrls = (
  scan: Pick<ProductScanRecord, 'supplierDetails'>
): string[] => {
  const urls = new Set<string>();

  for (const image of Array.isArray(scan.supplierDetails?.images) ? scan.supplierDetails.images : []) {
    const normalized = normalizeComparableText(image?.url);
    if (!normalized) {
      continue;
    }
    urls.add(normalized);
  }

  return Array.from(urls);
};

const buildReplacedImageSlots = (supplierImageUrls: string[], slotCount: number): string[] => {
  const next = new Array<string>(slotCount).fill('');
  supplierImageUrls.slice(0, slotCount).forEach((url, index) => {
    next[index] = url;
  });
  return next;
};

const buildAppendedImageSlots = (
  supplierImageUrls: string[],
  currentImageLinkSlots: string[]
): string[] => {
  const next = [...currentImageLinkSlots];
  const seenUrls = new Set(currentImageLinkSlots.filter((entry) => entry.length > 0));
  const emptySlotIndexes = next
    .map((entry, index) => (entry.length === 0 ? index : -1))
    .filter((index) => index >= 0);

  let emptySlotPointer = 0;
  for (const supplierUrl of supplierImageUrls) {
    if (seenUrls.has(supplierUrl)) {
      continue;
    }

    const targetIndex = emptySlotIndexes[emptySlotPointer];
    if (targetIndex == null) {
      break;
    }

    next[targetIndex] = supplierUrl;
    seenUrls.add(supplierUrl);
    emptySlotPointer += 1;
  }

  return next;
};

const normalizeSlotArray = (value: string[] | null | undefined, slotCount: number): string[] => {
  const next = new Array<string>(slotCount).fill('');
  if (!Array.isArray(value)) {
    return next;
  }

  value.slice(0, slotCount).forEach((entry, index) => {
    next[index] = normalizeComparableText(entry) ?? '';
  });
  return next;
};

const haveEqualSlots = (left: string[], right: string[]): boolean =>
  left.length === right.length && left.every((entry, index) => entry === right[index]);

export function ProductScan1688ApplyPanel(
  props: ProductScan1688ApplyPanelProps
): React.JSX.Element | null {
  const { scan, formBindings } = props;

  if (!formBindings) {
    return null;
  }

  const evaluationBanner = resolveProductScan1688ApplyPolicySummary(scan);
  const blockActions = evaluationBanner?.blockActions === true;
  const supplierName = normalizeComparableText(scan.supplierDetails?.supplierName);
  const supplierProductLink = buildSupplierProductLinkValue(scan);
  const supplierStoreLink = buildSupplierStoreLinkValue(scan);
  const supplierLink = supplierProductLink ?? supplierStoreLink;
  const priceComment = buildSupplierPriceCommentValue(scan);
  const detailedPriceComment = buildDetailedSupplierPriceCommentValue(scan);
  const supplierPriceTiers = buildSupplierPriceTierValues(scan);
  const extractedImageUrls = normalizeSupplierImageUrls(scan);

  const currentSupplierName =
    normalizeComparableText(formBindings.getTextFieldValue('supplierName')) ?? null;
  const currentSupplierLink =
    normalizeComparableText(formBindings.getTextFieldValue('supplierLink')) ?? null;
  const currentPriceComment =
    normalizeComparableText(formBindings.getTextFieldValue('priceComment')) ?? null;

  const imageSlotCount = Math.max(
    Array.isArray(formBindings.imageLinks) ? formBindings.imageLinks.length : 0,
    Array.isArray(formBindings.imageBase64s) ? formBindings.imageBase64s.length : 0
  );
  const currentImageLinkSlots = normalizeSlotArray(formBindings.imageLinks, imageSlotCount);
  const currentImageBase64Slots = normalizeSlotArray(formBindings.imageBase64s, imageSlotCount);
  const nextAppendedImageLinkSlots = buildAppendedImageSlots(
    extractedImageUrls,
    currentImageLinkSlots
  );
  const nextReplacedImageLinkSlots = buildReplacedImageSlots(extractedImageUrls, imageSlotCount);
  const hasCurrentImageBase64s = currentImageBase64Slots.some((entry) => entry.length > 0);
  const emptyImageSlotCount = currentImageLinkSlots.filter((entry) => entry.length === 0).length;
  const appendableImageUrlCount = nextAppendedImageLinkSlots.filter(
    (entry, index) => entry !== currentImageLinkSlots[index]
  ).length;
  const canApplySupplierName = Boolean(supplierName && supplierName !== currentSupplierName);
  const canApplySupplierLink = Boolean(supplierLink && supplierLink !== currentSupplierLink);
  const canApplySupplierProductLink = Boolean(
    supplierProductLink &&
      supplierProductLink !== currentSupplierLink
  );
  const canApplySupplierStoreLink = Boolean(
    supplierStoreLink &&
      supplierStoreLink !== supplierProductLink &&
      supplierStoreLink !== currentSupplierLink
  );
  const canApplyPriceComment = Boolean(priceComment && priceComment !== currentPriceComment);
  const canApplyDetailedPriceComment = Boolean(
    detailedPriceComment &&
      detailedPriceComment !== currentPriceComment &&
      detailedPriceComment !== priceComment
  );
  const canAppendImageUrls =
    extractedImageUrls.length > 0 &&
    imageSlotCount > 0 &&
    typeof formBindings.setImageLinkAt === 'function' &&
    (!haveEqualSlots(currentImageLinkSlots, nextAppendedImageLinkSlots) || hasCurrentImageBase64s);
  const canReplaceImageUrls =
    extractedImageUrls.length > 0 &&
    imageSlotCount > 0 &&
    typeof formBindings.setImageLinkAt === 'function' &&
    (!haveEqualSlots(currentImageLinkSlots, nextReplacedImageLinkSlots) || hasCurrentImageBase64s);
  const pendingActionCount = [
    canApplySupplierName,
    canApplySupplierLink,
    canApplyPriceComment,
    canApplyDetailedPriceComment,
    canAppendImageUrls,
    canReplaceImageUrls,
  ].filter(Boolean).length;

  const hasAnyAction = Boolean(
    canApplySupplierName ||
      canApplySupplierLink ||
      canApplyPriceComment ||
      canApplyDetailedPriceComment ||
      canAppendImageUrls ||
      canReplaceImageUrls
  );

  if (!hasAnyAction && !evaluationBanner) {
    return null;
  }

  return (
    <div className='space-y-2 rounded-md border border-border/50 bg-background/70 px-3 py-3'>
      <div className='flex flex-wrap items-center justify-between gap-2'>
        <div className='space-y-1'>
          <p className='text-[11px] font-medium uppercase tracking-wide text-muted-foreground'>
            Apply to product form
          </p>
          <p className='text-xs text-muted-foreground'>
            {blockActions
              ? 'Apply actions blocked by AI rejection'
              : `${pendingActionCount} pending supplier update${pendingActionCount === 1 ? '' : 's'}`}
          </p>
        </div>
        {!blockActions ? (
          <Button
            type='button'
            variant='outline'
            size='sm'
            onClick={() => {
              if (canApplySupplierName && supplierName) {
                formBindings.applyTextField('supplierName', supplierName);
              }
              if (canApplySupplierLink && supplierLink) {
                formBindings.applyTextField('supplierLink', supplierLink);
              }
              if (canApplyDetailedPriceComment && detailedPriceComment) {
                formBindings.applyTextField('priceComment', detailedPriceComment);
              } else if (canApplyPriceComment && priceComment) {
                formBindings.applyTextField('priceComment', priceComment);
              }
              if (canAppendImageUrls) {
                nextAppendedImageLinkSlots.forEach((value, index) => {
                  formBindings.setImageLinkAt?.(index, value);
                  if (value !== currentImageLinkSlots[index] || currentImageBase64Slots[index]) {
                    formBindings.setImageBase64At?.(index, '');
                  }
                });
              }
            }}
            className='h-7 px-2 text-xs'
          >
            Apply All Supplier Data
          </Button>
        ) : null}
      </div>

      {evaluationBanner ? (
        <div
          className={`rounded-md border px-3 py-2 text-sm ${
            evaluationBanner.tone === 'destructive'
              ? 'border-destructive/40 bg-destructive/5 text-destructive'
              : 'border-amber-500/40 bg-amber-500/5 text-amber-200'
          }`}
        >
          <p className='font-medium'>{evaluationBanner.label}</p>
          <p className='mt-1 text-xs'>{evaluationBanner.detail}</p>
        </div>
      ) : null}

      {!blockActions && supplierName ? (
        <div className='flex flex-wrap items-start justify-between gap-3'>
          <div className='min-w-0 space-y-1'>
            <p className='text-sm font-medium text-foreground'>Supplier name</p>
            <p className='text-xs text-muted-foreground'>Current: {currentSupplierName ?? 'Not set'}</p>
            <p className='text-xs text-muted-foreground'>1688: {supplierName}</p>
          </div>
          <Button
            type='button'
            variant='outline'
            size='sm'
            disabled={!canApplySupplierName}
            onClick={() => formBindings.applyTextField('supplierName', supplierName)}
            className='h-7 px-2 text-xs'
          >
            Use Supplier Name
          </Button>
        </div>
      ) : null}

      {!blockActions && supplierLink ? (
        <div className='flex flex-wrap items-start justify-between gap-3'>
          <div className='min-w-0 space-y-1'>
            <p className='text-sm font-medium text-foreground'>Supplier links</p>
            <p className='text-xs text-muted-foreground'>Current: {currentSupplierLink ?? 'Not set'}</p>
            {supplierProductLink ? (
              <p className='break-all text-xs text-muted-foreground'>
                Product page: {supplierProductLink}
              </p>
            ) : null}
            {supplierStoreLink ? (
              <p className='break-all text-xs text-muted-foreground'>
                Store page: {supplierStoreLink}
              </p>
            ) : null}
          </div>
          <div className='flex flex-wrap gap-2'>
            {supplierProductLink ? (
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={!canApplySupplierProductLink}
                onClick={() => formBindings.applyTextField('supplierLink', supplierProductLink)}
                className='h-7 px-2 text-xs'
              >
                Use Product Link
              </Button>
            ) : null}
            {supplierStoreLink && supplierStoreLink !== supplierProductLink ? (
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={!canApplySupplierStoreLink}
                onClick={() => formBindings.applyTextField('supplierLink', supplierStoreLink)}
                className='h-7 px-2 text-xs'
              >
                Use Store Link
              </Button>
            ) : null}
            {!supplierProductLink && supplierStoreLink ? (
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={!canApplySupplierLink}
                onClick={() => formBindings.applyTextField('supplierLink', supplierStoreLink)}
                className='h-7 px-2 text-xs'
              >
                Use Supplier Link
              </Button>
            ) : null}
          </div>
        </div>
      ) : null}

      {!blockActions && (priceComment || supplierPriceTiers.length > 0) ? (
        <div className='flex flex-wrap items-start justify-between gap-3'>
          <div className='min-w-0 space-y-1'>
            <p className='text-sm font-medium text-foreground'>Price comment</p>
            <p className='text-xs text-muted-foreground'>Current: {currentPriceComment ?? 'Not set'}</p>
            {priceComment ? (
              <p className='text-xs text-muted-foreground'>Summary: {priceComment}</p>
            ) : null}
            {supplierPriceTiers.length > 0 ? (
              <div className='space-y-1 pt-1'>
                <p className='text-xs text-muted-foreground'>Extracted price tiers:</p>
                <ul className='space-y-1 text-xs text-muted-foreground'>
                  {supplierPriceTiers.slice(0, 4).map((tierValue, index) => (
                    <li key={`${tierValue}-${index}`} className='flex flex-wrap items-center gap-2'>
                      <span className='inline-flex items-center rounded-md border border-border/60 px-2 py-0.5'>
                        Tier {index + 1}
                      </span>
                      <span>{tierValue}</span>
                    </li>
                  ))}
                </ul>
              </div>
            ) : null}
          </div>
          <div className='flex flex-wrap gap-2'>
            {priceComment ? (
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={!canApplyPriceComment}
                onClick={() => formBindings.applyTextField('priceComment', priceComment)}
                className='h-7 px-2 text-xs'
              >
                Use Price Summary
              </Button>
            ) : null}
            {detailedPriceComment ? (
              <Button
                type='button'
                variant='outline'
                size='sm'
                disabled={!canApplyDetailedPriceComment}
                onClick={() => formBindings.applyTextField('priceComment', detailedPriceComment)}
                className='h-7 px-2 text-xs'
              >
                Use Full Price Breakdown
              </Button>
            ) : null}
            {supplierPriceTiers.slice(0, 4).map((tierValue, index) => (
              <Button
                key={`${tierValue}-${index}`}
                type='button'
                variant='outline'
                size='sm'
                disabled={tierValue === currentPriceComment}
                onClick={() => formBindings.applyTextField('priceComment', tierValue)}
                className='h-7 px-2 text-xs'
              >
                Use Tier {index + 1}
              </Button>
            ))}
          </div>
        </div>
      ) : null}

      {!blockActions && extractedImageUrls.length > 0 && imageSlotCount > 0 ? (
        <div className='flex flex-wrap items-start justify-between gap-3'>
          <div className='min-w-0 space-y-1'>
            <p className='text-sm font-medium text-foreground'>Image URL slots</p>
            <p className='text-xs text-muted-foreground'>
              Current URLs: {currentImageLinkSlots.filter((entry) => entry.length > 0).length}
            </p>
            <p className='text-xs text-muted-foreground'>
              1688 extracted: {Math.min(extractedImageUrls.length, imageSlotCount)} of {imageSlotCount} slots
            </p>
            <p className='text-xs text-muted-foreground'>
              Empty slots: {emptyImageSlotCount} · Appendable URLs: {appendableImageUrlCount}
            </p>
            <p className='text-xs text-muted-foreground'>
              Append fills empty URL slots first. Replace overwrites URL/base64 slot values. Uploaded file slots stay untouched.
            </p>
          </div>
          <div className='flex flex-wrap gap-2'>
            <Button
              type='button'
              variant='outline'
              size='sm'
              disabled={!canAppendImageUrls}
              onClick={() => {
                nextAppendedImageLinkSlots.forEach((value, index) => {
                  formBindings.setImageLinkAt?.(index, value);
                  if (value !== currentImageLinkSlots[index] || currentImageBase64Slots[index]) {
                    formBindings.setImageBase64At?.(index, '');
                  }
                });
              }}
              className='h-7 px-2 text-xs'
            >
              Append Image URLs
            </Button>
            <Button
              type='button'
              variant='outline'
              size='sm'
              disabled={!canReplaceImageUrls}
              onClick={() => {
                nextReplacedImageLinkSlots.forEach((value, index) => {
                  formBindings.setImageLinkAt?.(index, value);
                  formBindings.setImageBase64At?.(index, '');
                });
              }}
              className='h-7 px-2 text-xs'
            >
              Replace Image URLs
            </Button>
          </div>
        </div>
      ) : null}
    </div>
  );
}

'use client';

import { Search } from 'lucide-react';
import { useMemo, useState } from 'react';

import type {
  ProductScanAmazonDetails as ProductScanAmazonDetailsValue,
  ProductScanAmazonEvaluationResult,
  ProductScanRecord,
  ProductScanStep,
} from '@/shared/contracts/product-scans';
import { CopyButton } from '@/shared/ui/copy-button';
import { Input } from '@/shared/ui/input';

type DetailField = {
  label: string;
  value: string | null | undefined;
};

type AmazonDetails = NonNullable<ProductScanAmazonDetailsValue>;
type AmazonAttribute = AmazonDetails['attributes'][number];
type AmazonExtractionProvenance = {
  candidateId: string | null;
  candidateRank: number | null;
  inputSourceLabel: string | null;
  retryOf: string | null;
  reusedProbe: boolean;
  extractionResultLabel: string | null;
};
type AmazonRejectedCandidateHistoryEntry = {
  attempt: number;
  candidateId: string | null;
  candidateRank: number | null;
  url: string | null;
  rejectionKind: 'language' | 'product';
  confidenceLabel: string | null;
  modelId: string | null;
  reason: string | null;
  mismatch: string | null;
  message: string | null;
};

export type AmazonRejectedCandidateBreakdown = {
  totalCount: number;
  languageRejectedCount: number;
  productRejectedCount: number;
};

export type AmazonScanQualitySummary = {
  primaryLabel: 'Strong match' | 'Partial extraction' | 'Scraped info';
  usedFallback: boolean;
  usedCaptcha: boolean;
};

const hasText = (value: string | null | undefined): value is string =>
  typeof value === 'string' && value.trim().length > 0;

const resolveDetailFields = (
  fields: DetailField[]
): Array<{ label: string; value: string }> => {
  const result: Array<{ label: string; value: string }> = [];
  for (const field of fields) {
    if (hasText(field.value)) {
      result.push({
        label: field.label,
        value: field.value.trim(),
      });
    }
  }
  return result;
};

const resolveAttributeSourceLabel = (value: string | null | undefined): string => {
  const normalized = hasText(value) ? value.trim() : 'other';
  if (normalized === 'detail_bullets') return 'Detail Bullets';
  if (normalized === 'technical_details') return 'Technical Details';
  if (normalized === 'product_details') return 'Product Details';
  if (normalized === 'technical_specifications') return 'Technical Specifications';
  if (normalized === 'product_overview') return 'Product Overview';
  return normalized
    .replace(/[_-]+/g, ' ')
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
};

const groupAmazonAttributesBySource = (
  details: ProductScanAmazonDetailsValue | null | undefined
): Array<{ source: string; entries: AmazonAttribute[] }> => {
  if (details === null || details === undefined || details.attributes.length === 0) {
    return [];
  }

  const grouped = new Map<string, AmazonAttribute[]>();
  for (const entry of details.attributes) {
    const source = resolveAttributeSourceLabel(entry.source);
    const existingEntries = grouped.get(source) ?? [];
    existingEntries.push(entry);
    grouped.set(source, existingEntries);
  }

  const sourceOrder = new Map<string, number>([
    ['Product Overview', 0],
    ['Product Details', 1],
    ['Technical Details', 2],
    ['Technical Specifications', 3],
    ['Detail Bullets', 4],
  ]);

  return Array.from(grouped.entries())
    .map(([source, entries]) => ({
      source,
      entries: [...entries].sort((left, right) =>
        left.label.localeCompare(right.label, undefined, { sensitivity: 'base' })
      ),
    }))
    .sort((left, right) => {
      const leftRank = sourceOrder.get(left.source) ?? Number.MAX_SAFE_INTEGER;
      const rightRank = sourceOrder.get(right.source) ?? Number.MAX_SAFE_INTEGER;
      if (leftRank !== rightRank) {
        return leftRank - rightRank;
      }
      return left.source.localeCompare(right.source, undefined, { sensitivity: 'base' });
    });
};

const matchesAttributeQuery = (attribute: AmazonAttribute, query: string): boolean => {
  if (query === '') {
    return true;
  }

  const haystack = [attribute.label, attribute.value, attribute.key, attribute.source]
    .filter((v): v is string => hasText(v))
    .join(' ')
    .toLowerCase();

  return haystack.includes(query);
};

const formatResultCode = (value: string | null | undefined): string | null => {
  if (hasText(value)) {
    return value
      .trim()
      .replace(/[_-]+/g, ' ')
      .replace(/\b\w/g, (letter) => letter.toUpperCase());
  }
  return null;
};

const resolveInputSourceLabel = (value: string | null | undefined): string | null => {
  if (hasText(value)) {
    const trimmed = value.trim();
    return trimmed === 'url' ? 'URL input' : trimmed === 'file' ? 'File input' : trimmed;
  }
  return null;
};

const resolveAmazonEvaluationStatusLabel = (
  value: ProductScanAmazonEvaluationResult['status'] | null | undefined
): string | null => {
  if (typeof value !== 'string' || value.trim().length === 0) {
    return null;
  }
  if (value === 'approved') return 'AI approved';
  if (value === 'rejected') return 'AI rejected';
  if (value === 'skipped') return 'AI skipped';
  return 'AI failed';
};

const formatEvaluationConfidence = (value: number | null | undefined): string | null =>
  typeof value === 'number' && Number.isFinite(value) ? `${Math.round(value * 100)}%` : null;

const formatAmazonPageLanguage = (value: string | null | undefined): string | null => {
  if (hasText(value)) {
    const normalized = value.trim().toLowerCase();
    if (normalized === 'en') return 'English';
    if (normalized === 'en-us') return 'English (US)';
    if (normalized === 'en-gb') return 'English (UK)';
    if (normalized === 'de') return 'German';
    if (normalized === 'fr') return 'French';
    if (normalized === 'es') return 'Spanish';
    if (normalized === 'it') return 'Italian';
    if (normalized === 'pl') return 'Polish';
    if (normalized === 'nl') return 'Dutch';
    if (normalized === 'sv') return 'Swedish';
    if (normalized === 'ja') return 'Japanese';
    return normalized.toUpperCase();
  }
  return null;
};

const resolveStepDetailValue = (
  step: Pick<ProductScanStep, 'details'>,
  label: string
): string | null => {
  const detail = step.details.find((entry) => entry.label === label);
  if (detail && hasText(detail.value)) {
    return detail.value.trim();
  }
  return null;
};

const resolveLatestAmazonEvaluationStep = (
  steps: readonly ProductScanStep[] | null | undefined
): ProductScanStep | null => {
  if (steps) {
    return [...steps].reverse().find((step) => step.key === 'amazon_ai_evaluate') ?? null;
  }
  return null;
};

const resolveAmazonExtractionProvenance = (
  steps: readonly ProductScanStep[] | null | undefined
): AmazonExtractionProvenance | null => {
  const normalizedSteps: readonly ProductScanStep[] = steps ?? [];
  if (normalizedSteps.length === 0) {
    return null;
  }

  const reversedSteps = [...normalizedSteps].reverse();
  const amazonExtractStep =
    reversedSteps.find((step) => step.key === 'amazon_extract' && step.status === 'completed') ??
    reversedSteps.find((step) => step.key === 'amazon_extract');
  const amazonProbeStep = reversedSteps.find((step) => step.key === 'amazon_probe') ?? null;
  const googleUploadStep =
    reversedSteps.find(
      (step) =>
        step.key === 'google_upload' &&
        step.status === 'completed' &&
        ((amazonExtractStep?.candidateId ?? '') === '' || step.candidateId === amazonExtractStep?.candidateId)
    ) ??
    reversedSteps.find((step) => step.key === 'google_upload' && step.status === 'completed') ??
    reversedSteps.find((step) => step.key === 'google_upload');

  const extractCandidateId = amazonExtractStep?.candidateId;
  const uploadCandidateId = googleUploadStep?.candidateId;
  const candidateId = (typeof extractCandidateId === 'string' && extractCandidateId.trim() !== '' ? extractCandidateId.trim() : null) ??
    (typeof uploadCandidateId === 'string' && uploadCandidateId.trim() !== '' ? uploadCandidateId.trim() : null);
  const candidateRank =
    typeof amazonExtractStep?.candidateRank === 'number' && Number.isFinite(amazonExtractStep.candidateRank)
      ? amazonExtractStep.candidateRank
      : null;
  const inputSourceLabel = resolveInputSourceLabel(googleUploadStep?.inputSource);
  const uploadRetryOf = googleUploadStep?.retryOf;
  const retryOf = (typeof uploadRetryOf === 'string' && uploadRetryOf.trim() !== '' ? uploadRetryOf.trim() : null);
  const reusedProbe = amazonProbeStep?.resultCode === 'probe_reused';
  const extractionResultLabel =
    formatResultCode(amazonExtractStep?.resultCode) ?? formatResultCode(googleUploadStep?.resultCode);

  if (candidateId === null && candidateRank === null && inputSourceLabel === null && retryOf === null && reusedProbe === false && extractionResultLabel === null) {
    return null;
  }

  return {
    candidateId,
    candidateRank,
    inputSourceLabel,
    retryOf,
    reusedProbe,
    extractionResultLabel,
  };
};

const resolveRejectedAmazonCandidateHistory = (
  steps: readonly ProductScanStep[] | null | undefined
): AmazonRejectedCandidateHistoryEntry[] => {
  const normalizedSteps = steps ?? [];
  return normalizedSteps
    .filter(
      (step) =>
        step.key === 'amazon_ai_evaluate' &&
        (step.resultCode === 'candidate_rejected' ||
          step.resultCode === 'candidate_language_rejected')
    )
    .map((step) => {
      const stepCandidateId = step.candidateId;
      const stepUrl = step.url;
      const stepMessage = step.message;
      return {
        attempt:
          typeof step.attempt === 'number' && Number.isFinite(step.attempt) ? step.attempt : 1,
        candidateId: (typeof stepCandidateId === 'string' && stepCandidateId.trim() !== '' ? stepCandidateId.trim() : null),
        candidateRank:
          typeof step.candidateRank === 'number' && Number.isFinite(step.candidateRank)
            ? step.candidateRank
            : null,
        url: (typeof stepUrl === 'string' && stepUrl.trim() !== '' ? stepUrl.trim() : null) ?? resolveStepDetailValue(step, 'Candidate URL'),
        rejectionKind:
          step.resultCode === 'candidate_language_rejected'
            ? ('language' as const)
            : ('product' as const),
        confidenceLabel: resolveStepDetailValue(step, 'Confidence'),
        modelId: resolveStepDetailValue(step, 'Model'),
        reason:
          resolveStepDetailValue(step, 'Reason') ??
          resolveStepDetailValue(step, 'Language reason'),
        mismatch: resolveStepDetailValue(step, 'Mismatch'),
        message: (typeof stepMessage === 'string' && stepMessage.trim() !== '' ? stepMessage.trim() : null),
      };
    })
    .sort((left, right) => left.attempt - right.attempt);
};

export const resolveRejectedAmazonCandidateBreakdown = (
  steps: readonly ProductScanStep[] | null | undefined
): AmazonRejectedCandidateBreakdown => {
  const history = resolveRejectedAmazonCandidateHistory(steps);
  const languageRejectedCount = history.filter((entry) => entry.rejectionKind === 'language').length;

  return {
    totalCount: history.length,
    languageRejectedCount,
    productRejectedCount: history.length - languageRejectedCount,
  };
};

export const resolveRejectedAmazonCandidateCount = (
  steps: readonly ProductScanStep[] | null | undefined
): number => resolveRejectedAmazonCandidateBreakdown(steps).totalCount;

export const resolveAmazonScanRecommendationReason = (
  scan: Pick<ProductScanRecord, 'asin' | 'title' | 'description' | 'amazonDetails' | 'steps'>
): string | null => {
  const quality = resolveAmazonScanQualitySummary(scan);
  const rejectedCandidateBreakdown = resolveRejectedAmazonCandidateBreakdown(scan.steps);
  const rejectedCandidateCount = rejectedCandidateBreakdown.totalCount;
  const rejectedLanguageCount = rejectedCandidateBreakdown.languageRejectedCount;
  const rejectedSuffix =
    rejectedLanguageCount > 0
      ? ` (${rejectedLanguageCount} non-English)`
      : '';

  if (quality === null) {
    if (rejectedCandidateCount > 0) {
      return `Best available result after ${rejectedCandidateCount} rejected candidate${
        rejectedCandidateCount === 1 ? '' : 's'
      }`;
    }
    return 'Best available result';
  }

  if (quality.primaryLabel === 'Strong match') {
    if (rejectedCandidateCount > 0) {
      return `Strong match after ${rejectedCandidateCount} rejected candidate${
        rejectedCandidateCount === 1 ? '' : 's'
      }${rejectedSuffix}`;
    }

    if (quality.usedFallback === false && quality.usedCaptcha === false) {
      return 'Strongest clean match';
    }

    return 'Strongest recovered match';
  }

  if (quality.primaryLabel === 'Partial extraction') {
    if (rejectedCandidateCount > 0) {
      return `Partial extraction after ${rejectedCandidateCount} rejected candidate${
        rejectedCandidateCount === 1 ? '' : 's'
      }${rejectedSuffix}`;
    }

    if (quality.usedFallback === false && quality.usedCaptcha === false) {
      return 'Clean partial extraction';
    }

    return 'Best partial extraction';
  }

  if (rejectedCandidateCount > 0) {
    return `Best scraped result after ${rejectedCandidateCount} rejected candidate${
      rejectedCandidateCount === 1 ? '' : 's'
    }${rejectedSuffix}`;
  }

  return 'Best scraped result';
};

export const resolvePreferredAmazonExtractedScans = (
  scans: ProductScanRecord[]
): ProductScanRecord[] => {
  const extractedScans = scans.filter(
    (scan) => hasProductScanAmazonDetails(scan.amazonDetails) || hasText(scan.asin)
  );

  const resolveQualityPriority = (scan: ProductScanRecord): number => {
    const quality = resolveAmazonScanQualitySummary(scan);
    if (quality === null) {
      return 0;
    }

    const primaryScore =
      quality.primaryLabel === 'Strong match'
        ? 300
        : quality.primaryLabel === 'Partial extraction'
          ? 200
          : 100;

    return primaryScore + (quality.usedFallback === false ? 5 : 0) + (quality.usedCaptcha === false ? 2 : 0);
  };

  const resolveSortTimestamp = (scan: ProductScanRecord): number => {
    const parsed = new Date(scan.updatedAt ?? scan.createdAt ?? 0).getTime();
    return Number.isFinite(parsed) ? parsed : 0;
  };

  return [...extractedScans].sort((left, right) => {
    const qualityDifference = resolveQualityPriority(right) - resolveQualityPriority(left);
    if (qualityDifference !== 0) {
      return qualityDifference;
    }

    const rejectionDifference =
      resolveRejectedAmazonCandidateCount(left.steps) -
      resolveRejectedAmazonCandidateCount(right.steps);
    if (rejectionDifference !== 0) {
      return rejectionDifference;
    }

    const timestampDifference = resolveSortTimestamp(right) - resolveSortTimestamp(left);
    if (timestampDifference !== 0) {
      return timestampDifference;
    }

    return left.id.localeCompare(right.id);
  });
};

export const resolveAmazonScanQualitySummary = (
  scan: Pick<ProductScanRecord, 'asin' | 'title' | 'description' | 'amazonDetails'> & {
    steps?: ProductScanStep[] | null;
  }
): AmazonScanQualitySummary | null => {
  const provenance = resolveAmazonExtractionProvenance(scan.steps);
  const normalizedSteps: readonly ProductScanStep[] = Array.isArray(scan.steps) ? scan.steps : [];
  const hasAsin = hasText(scan.asin);
  const hasExtractedDetails = hasProductScanAmazonDetails(scan.amazonDetails);
  const hasListingText = hasText(scan.title) || hasText(scan.description);
  const usedCaptcha = normalizedSteps.some((step) => step.key === 'google_captcha');

  if (hasAsin === false && hasExtractedDetails === false && hasListingText === false && usedCaptcha === false && (provenance?.retryOf ?? '') === '') {
    return null;
  }

  return {
    primaryLabel: hasAsin === true
      ? 'Strong match'
      : hasExtractedDetails === true || hasListingText === true
        ? 'Partial extraction'
        : 'Scraped info',
    usedFallback: (provenance?.retryOf ?? '') !== '',
    usedCaptcha,
  };
};

const resolveAmazonScanQualityModifierLabel = (
  scan: Pick<ProductScanRecord, 'asin' | 'title' | 'description' | 'amazonDetails'> & {
    steps?: ProductScanStep[] | null;
  }
): string | null => {
  const quality = resolveAmazonScanQualitySummary(scan);
  if (quality === null) {
    return null;
  }

  const rejectedCandidateBreakdown = resolveRejectedAmazonCandidateBreakdown(scan.steps);
  const rejectedCandidateCount = rejectedCandidateBreakdown.totalCount;
  if (rejectedCandidateCount > 0) {
    const languageSuffix =
      rejectedCandidateBreakdown.languageRejectedCount > 0
        ? ` (${rejectedCandidateBreakdown.languageRejectedCount} non-English)`
        : '';
    return `After ${rejectedCandidateCount} rejected candidate${
      rejectedCandidateCount === 1 ? '' : 's'
    }${languageSuffix}`;
  }

  if (quality.usedFallback === false && quality.usedCaptcha === false) {
    return 'Clean path';
  }

  if (quality.usedFallback === true || quality.usedCaptcha === true) {
    return 'Recovered path';
  }

  return null;
};

