                {stopLabel ? <StatusBadge status={stopLabel} variant='info' size='sm' /> : null}
              </div>
              <div className='mt-2 grid grid-cols-1 gap-2 text-xs md:grid-cols-3'>
                <div>
                  <div className='mb-1 text-[10px] font-semibold uppercase tracking-wide text-gray-400'>
                    Input
                  </div>
                  <div className='break-all font-mono text-gray-100'>{step.inputValue || '(empty)'}</div>
                </div>
                <div>
                  <div className='mb-1 text-[10px] font-semibold uppercase tracking-wide text-gray-400'>
                    Replacement
                  </div>
                  <div className='break-all font-mono text-gray-100'>
                    {step.replacementValue || '(none)'}
                  </div>
                </div>
                <div>
                  <div className='mb-1 text-[10px] font-semibold uppercase tracking-wide text-gray-400'>
                    Output
                  </div>
                  <div className='break-all font-mono text-gray-100'>{step.outputValue || '(empty)'}</div>
                </div>
              </div>
              <div className='mt-2 flex flex-wrap gap-2'>
                <StatusBadge
                  status={step.launchMatched ? 'Launch matched' : 'Launch blocked'}
                  variant={step.launchMatched ? 'success' : 'warning'}
                  size='sm'
                />
                <StatusBadge
                  status={
                    step.allowWithoutRegexMatch && !step.regexMatched
                      ? 'Regex skipped'
                      : step.regexMatched
                        ? 'Regex matched'
                        : 'Regex no match'
                  }
                  variant={step.regexMatched ? 'success' : 'warning'}
                  size='sm'
                />
                <StatusBadge
                  status={step.replacementEnabledForScope ? 'Replacement active' : 'Replacement off'}
                  variant={step.replacementEnabledForScope ? 'info' : 'warning'}
                  size='sm'
                />
                <StatusBadge status={`Executions ${step.executions}`} variant='neutral' size='sm' />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export function ValidatorPatternModalSimulatorSection(): React.JSX.Element {
  const {
    formData,
    modalSemanticState,
    testResult,
    simulatorScope,
    setSimulatorScope,
    simulatorValues,
    setSimulatorValue,
    simulatorCategoryFixtures,
    setSimulatorCategoryFixtures,
  } = useValidatorSettingsContext();

  const simulatorInputs = React.useMemo(
    () => buildValidatorPatternSimulatorInputs(formData),
    [formData]
  );
  const semanticUi = React.useMemo(
    () => getProductValidationSemanticOperationUiMetadata(modalSemanticState?.operation),
    [modalSemanticState?.operation]
  );
  const result = testResult as ValidatorPatternSimulationResult;

  return (
    <FormSection
      title='Simulator'
      description={
        semanticUi?.simulatorDescription ??
        'Preview how the current pattern would resolve and apply without touching live product data.'
      }
      variant='subtle'
      className='p-4'
    >
      <div className='space-y-4'>
        <div className='grid grid-cols-1 gap-4 md:grid-cols-2'>
          <FormField label='Validation Scope'>
            <SelectSimple
              size='sm'
              value={simulatorScope}
              onValueChange={(value: string): void => setSimulatorScope(value as typeof simulatorScope)}
              options={[...VALIDATION_SCOPE_OPTIONS]}
              ariaLabel='Validation Scope'
              title='Validation Scope'
            />
          </FormField>
          {simulatorInputs.map((input) => (
            <FormField key={input.key} label={input.label}>
              <Input
                className='h-9'
                value={simulatorValues[input.key] ?? ''}
                onChange={(event: React.ChangeEvent<HTMLInputElement>): void =>
                  setSimulatorValue(input.key, event.target.value)
                }
                placeholder={input.placeholder}
                aria-label={input.label}
                title={input.label}
              />
            </FormField>
          ))}
        </div>

        {formData.target === 'category' ? (
          <FormField
            label={semanticUi?.categoryFixturesLabel ?? 'Category Fixtures'}
            description={
              semanticUi?.categoryFixturesDescription ??
              'Optional. One category per line: `id|name|name_en|name_pl|name_de`.'
            }
          >
            <Textarea
              className='min-h-[88px] font-mono text-[12px]'
              value={simulatorCategoryFixtures}
              onChange={(event: React.ChangeEvent<HTMLTextAreaElement>): void =>
                setSimulatorCategoryFixtures(event.target.value)
              }
              placeholder={
                semanticUi?.categoryFixturesPlaceholder ??
                'category-1|Keychains|Keychains|Breloki|Schlusselanhanger'
              }
              aria-label={semanticUi?.categoryFixturesLabel ?? 'Category Fixtures'}
              title={semanticUi?.categoryFixturesLabel ?? 'Category Fixtures'}
            />
          </FormField>
        ) : null}

        {renderResultStatus(result)}
        {renderSequenceTrace(result)}
      </div>
    </FormSection>
  );
}

'use client';

import { useQueryClient } from '@tanstack/react-query';
import { useCallback, useMemo, useState } from 'react';

import {
  useCreateValidationPatternMutation,
  useDeleteValidationPatternMutation,
  useReorderValidationPatternsMutation,
  useUpdateValidatorSettingsMutation,
  useUpdateValidationPatternMutation,
  useValidationPatterns,
  useValidatorSettings,
} from '@/features/products/hooks/useProductSettingsQueries';
import { useProducers } from '@/features/products/hooks/useProductMetadata';
import type { ProductValidationDenyBehavior, ProductValidationInstanceDenyBehaviorMap, ProductValidationPattern, ProductValidationSemanticState, ProductValidationTarget, ProductValidationInstanceScope, SequenceGroupDraft } from '@/shared/contracts/products/validation';
import type { PatternFormData } from '@/shared/contracts/products/drafts';
import {
  type CreateProductValidationPatternInput as CreateValidationPatternPayload,
  type ReorderProductValidationPatternUpdate as ReorderValidationPatternUpdatePayload,
} from '@/shared/contracts/products/validation';
import { normalizeProductValidationInstanceDenyBehaviorMap } from '@/shared/lib/products/utils/validator-instance-behavior';
import { encodeDynamicReplacementRecipe } from '@/shared/lib/products/utils/validator-replacement-recipe';
import {
  getProductValidationSemanticState,
  getProductValidationSemanticTransition,
} from '@/shared/lib/products/utils/validator-semantic-state';
import { useToast } from '@/shared/ui/toast';

import {
  logClientCatch,
  logClientError,
} from '@/shared/utils/observability/client-error-logger';

import {
  buildPatternPayloadDiff,
  buildValidationPayload,
  parseStrictInt,
} from './controller-diff-utils';
import { buildFormDataFromPattern } from './controller-form-utils';
import { createSequenceActions } from './controller-sequence-actions';
import {
  buildDynamicRecipeFromForm,
  buildDuplicateLabel,
  buildSequenceGroups,
  canCompileRegex,
  EMPTY_FORM,
  sortPatternsBySequence,
  REPLACEMENT_FIELD_OPTIONS,
  getSourceFieldOptionsForTarget,
  isLocaleTarget,
  normalizeReplacementFields,
  formatReplacementFields,
  getReplacementFieldsForTarget,
} from './helpers';
import { buildAndSimulateValidatorPatternPreview } from './validator-pattern-simulator';

/**
 * Coordinates validator settings queries, pattern-editing state, and modal actions for the validator settings UI.
 */
export function useValidatorSettingsController() {
  const queryClient = useQueryClient();
  const patternsQuery = useValidationPatterns();
  const settingsQuery = useValidatorSettings();
  const producersQuery = useProducers();
  const { toast } = useToast();

  const patterns = patternsQuery.data ?? [];
  const settings = settingsQuery.data;

  const orderedPatterns = useMemo(() => sortPatternsBySequence(patterns), [patterns]);

  const [showModal, setShowModal] = useState(false);
  const [editingPattern, setEditingPattern] = useState<ProductValidationPattern | null>(null);
  const [modalSemanticStateSeed, setModalSemanticState] =
    useState<ProductValidationSemanticState | null>(null);
  const [formData, setFormData] = useState<PatternFormData>(EMPTY_FORM);
  const [simulatorScope, setSimulatorScope] = useState<ProductValidationInstanceScope>('product_edit');
  const [simulatorValues, setSimulatorValues] = useState<Record<string, string>>({});
  const [simulatorCategoryFixtures, setSimulatorCategoryFixtures] = useState<string>('');
  const [groupDrafts, setGroupDrafts] = useState<Record<string, SequenceGroupDraft>>({});
  const [draggedPatternId, setDraggedPatternId] = useState<string | null>(null);
  const [dragOverPatternId, setDragOverPatternId] = useState<string | null>(null);
  const [patternToDelete, setPatternToDelete] = useState<ProductValidationPattern | null>(null);

  const createPattern = useCreateValidationPatternMutation();
  const updatePattern = useUpdateValidationPatternMutation();
  const deletePattern = useDeleteValidationPatternMutation();
  const reorderPatterns = useReorderValidationPatternsMutation();
  const updateSettings = useUpdateValidatorSettingsMutation();

  const sequenceGroups = useMemo(() => buildSequenceGroups(orderedPatterns), [orderedPatterns]);

  const modalSemanticState = useMemo((): ProductValidationSemanticState | null => {
    const parsedSequence =
      formData.sequence.trim().length === 0 ? null : parseStrictInt(formData.sequence);
    if (formData.sequence.trim().length > 0 && (parsedSequence === null || parsedSequence < 0)) {
      return modalSemanticStateSeed;
    }

    const parsedMaxExecutions = parseStrictInt(formData.maxExecutions);
    if (parsedMaxExecutions === null || parsedMaxExecutions < 1 || parsedMaxExecutions > 20) {
      return modalSemanticStateSeed;
    }

    const parsedValidationDebounceMs = parseStrictInt(formData.validationDebounceMs);
    if (
      parsedValidationDebounceMs === null ||
      parsedValidationDebounceMs < 0 ||
      parsedValidationDebounceMs > 30_000
    ) {
      return modalSemanticStateSeed;
    }

    let replacementValue: string | null = null;
    if (formData.replacementMode === 'dynamic') {
      const recipe = buildDynamicRecipeFromForm(formData);
      if (!recipe) return modalSemanticStateSeed;
      replacementValue = encodeDynamicReplacementRecipe(recipe);
    } else {
      replacementValue = formData.replacementValue.length > 0 ? formData.replacementValue : null;
    }

    return (
      buildValidationPayload({
        formData,
        sequenceGroups,
        editingPattern,
        semanticState: modalSemanticStateSeed,
        replacementValue,
        parsedSequence,
        parsedMaxExecutions,
        parsedValidationDebounceMs,
      }).semanticState ?? null
    );
  }, [editingPattern, formData, modalSemanticStateSeed, sequenceGroups]);

  const modalSemanticTransition = useMemo(
    () =>
      getProductValidationSemanticTransition({
        previous: modalSemanticStateSeed,
        current: modalSemanticState,
      }),
    [modalSemanticState, modalSemanticStateSeed]
  );

  const sequenceScopedPatternIds = useMemo(() => {
    const ids = new Set<string>();
    sequenceGroups.forEach((group) => {
      group.patternIds.forEach((patternId) => ids.add(patternId));
    });
    return ids;
  }, [sequenceGroups]);

  const firstPatternIdByGroup = useMemo(() => {
    const map = new Map<string, string>();
    sequenceGroups.forEach((group, groupId) => {
      if (group.patternIds.length > 0) {
        map.set(groupId, group.patternIds[0]!);
      }
    });
    return map;
  }, [sequenceGroups]);

  const resetSimulator = useCallback((): void => {
    setSimulatorScope('product_edit');
    setSimulatorValues({});
    setSimulatorCategoryFixtures('');
  }, []);

  const testResult = useMemo(
    () =>
      buildAndSimulateValidatorPatternPreview({
        formData,
        sequenceGroups,
        orderedPatterns,
        editingPattern,
        modalSemanticState,
        validationScope: simulatorScope,
        simulatorValues,
        categoryFixturesText: simulatorCategoryFixtures,
        producers: producersQuery.data ?? [],
      }),
    [
      editingPattern,
      formData,
      modalSemanticState,
      producersQuery.data,
      orderedPatterns,
      sequenceGroups,
      simulatorCategoryFixtures,
      simulatorScope,
      simulatorValues,
    ]
  );

  const setSimulatorValue = useCallback((key: string, value: string): void => {
    setSimulatorValues((prev) => {
      if (prev[key] === value) return prev;
      return {
        ...prev,
        [key]: value,
      };
    });
  }, []);

  const getGroupDraft = useCallback(
    (groupId: string): SequenceGroupDraft => {
      const existing = groupDrafts[groupId];
      if (existing) return existing;
      const group = sequenceGroups.get(groupId);
      return {
        label: group?.label ?? '',
        debounceMs: String(group?.debounceMs ?? 0),
      };
    },
    [groupDrafts, sequenceGroups]
  );

  const {
    handleMoveGroup,
    handleReorderInGroup: _ignoredHandleReorderInGroup,
    handleMoveToGroup,
    handleRemoveFromGroup,
    handleCreateGroup,
    handleRenameGroup,
    handleUpdateGroupDebounce,
    handleCreateSkuAutoIncrementSequence,
    handleCreateLatestPriceStockSequence,
    handleCreateNameLengthMirrorPattern,
    handleCreateNameCategoryMirrorPattern,
    handleCreateStarGaterProducerPattern,
    handleCreateNameMirrorPolishSequence,
    handleSaveSequenceGroup,
    handleUngroup,
  } = createSequenceActions({
    patterns,
    orderedPatterns,
    sequenceGroups,
    getGroupDraft,
    setGroupDrafts,
    createPattern,
    updatePattern,
    queryClient,
    notifySuccess: (msg) => {
      toast(msg, { variant: 'success' });
    },
    notifyError: (msg) => {
      toast(msg, { variant: 'error' });
    },
    notifyInfo: (msg) => {
      toast(msg, { variant: 'info' });
    },
  });

  const handleAddPattern = useCallback((target?: string): void => {
    setEditingPattern(null);
    setModalSemanticState(null);
    setFormData({
      ...EMPTY_FORM,
      target: (target as ProductValidationTarget) || 'name',
    });
    resetSimulator();
    setShowModal(true);
  }, [resetSimulator]);

  const handleEditPattern = useCallback((pattern: ProductValidationPattern): void => {
    setEditingPattern(pattern);
    setModalSemanticState(getProductValidationSemanticState(pattern));
    setFormData(buildFormDataFromPattern(pattern));
    resetSimulator();
    setShowModal(true);
  }, [resetSimulator]);

  const handleDuplicatePattern = useCallback(
    (pattern: ProductValidationPattern): void => {
      setEditingPattern(null);
      setModalSemanticState(getProductValidationSemanticState(pattern));
      const duplicated = buildFormDataFromPattern(pattern);
      duplicated.label = buildDuplicateLabel(
        pattern.label,
        new Set(patterns.map((p) => p.label.toLowerCase()))
      );
      setFormData(duplicated);
      resetSimulator();
      setShowModal(true);
    },
    [patterns, resetSimulator]
  );

  const handleSavePattern = async (): Promise<void> => {
    if (!formData.label.trim() || !formData.regex.trim() || !formData.message.trim()) {
      toast('Please fill in all required fields.', { variant: 'error' });
      return;
    }

    if (!canCompileRegex(formData.regex, formData.flags)) {
      toast('Invalid regular expression.', { variant: 'error' });
      return;
    }

    try {
      const parsedSequence =
        formData.sequence.trim().length === 0 ? null : parseStrictInt(formData.sequence);
      if (formData.sequence.trim().length > 0 && (parsedSequence === null || parsedSequence < 0)) {
        toast('Sequence must be a whole number greater than or equal to 0.', { variant: 'error' });
        return;
      }

      const parsedMaxExecutions = parseStrictInt(formData.maxExecutions);
      if (parsedMaxExecutions === null || parsedMaxExecutions < 1 || parsedMaxExecutions > 20) {
        toast('Max executions must be a whole number between 1 and 20.', { variant: 'error' });
        return;
      }

      const parsedValidationDebounceMs = parseStrictInt(formData.validationDebounceMs);
      if (
        parsedValidationDebounceMs === null ||
        parsedValidationDebounceMs < 0 ||
        parsedValidationDebounceMs > 30_000
      ) {
        toast('Debounce must be a whole number between 0 and 30000.', { variant: 'error' });
        return;
      }

      let replacementValue: string | null = null;
      if (formData.replacementMode === 'dynamic') {
        const recipe = buildDynamicRecipeFromForm(formData);
        if (!recipe) {
          toast('Dynamic replacer config is incomplete.', { variant: 'error' });
          return;
        }
        replacementValue = encodeDynamicReplacementRecipe(recipe);
      } else {
        replacementValue = formData.replacementValue.length > 0 ? formData.replacementValue : null;
      }

      const payload = buildValidationPayload({
        formData,
        sequenceGroups,
        editingPattern,
        semanticState: modalSemanticState,
        replacementValue,
        parsedSequence,
        parsedMaxExecutions,
        parsedValidationDebounceMs,
      });

      if (editingPattern) {
        const changedPayload = buildPatternPayloadDiff(editingPattern, payload);
        if (Object.keys(changedPayload).length === 0) {
          toast('No changes to save.', { variant: 'info' });
          setShowModal(false);
          setModalSemanticState(null);
          return;
        }
        await updatePattern.mutateAsync({ id: editingPattern.id, data: changedPayload });
        toast('Pattern updated.', { variant: 'success' });
      } else {
        await createPattern.mutateAsync(payload as CreateValidationPatternPayload);
        toast('Pattern created.', { variant: 'success' });
      }
      setShowModal(false);
      setModalSemanticState(null);
    } catch (error) {
      logClientCatch(error, {
        source: 'useValidatorSettingsController',
        action: 'savePattern',
        editingId: editingPattern?.id,
      });
      toast(error instanceof Error ? error.message : 'Failed to save pattern.', {
        variant: 'error',
      });
    }
  };

  const handleTogglePattern = useCallback(
    async (pattern: ProductValidationPattern): Promise<void> => {
      try {
        await updatePattern.mutateAsync({
          id: pattern.id,
          data: { enabled: !pattern.enabled },
        });
        toast(`Pattern ${!pattern.enabled ? 'enabled' : 'disabled'}.`, {
          variant: 'success',
        });
      } catch (error) {
        logClientCatch(error, {
          source: 'useValidatorSettingsController',
          action: 'togglePattern',
          patternId: pattern.id,
        });
        toast(error instanceof Error ? error.message : 'Failed to update pattern.', {
          variant: 'error',
        });
      }
    },
    [updatePattern.mutateAsync, toast]
  );

  const handleDeletePattern = useCallback(
    async (id: string): Promise<void> => {
      try {
        await deletePattern.mutateAsync(id);
        toast('Pattern deleted.', { variant: 'success' });
      } catch (error) {
        logClientCatch(error, {
          source: 'useValidatorSettingsController',
          action: 'deletePattern',
          patternId: id,
        });
        toast(error instanceof Error ? error.message : 'Failed to delete pattern.', {
          variant: 'error',
        });
      }
    },
    [deletePattern.mutateAsync, toast]
  );

  const handleUpdateSettings = async (
    updates: Partial<{
      enabledByDefault: boolean;
      formatterEnabledByDefault: boolean;
      instanceDenyBehavior: ProductValidationInstanceDenyBehaviorMap;
    }>
  ): Promise<void> => {
    try {
      await updateSettings.mutateAsync(updates);
      toast('Settings updated.', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'useValidatorSettingsController',
        action: 'updateSettings',
      });
      toast(error instanceof Error ? error.message : 'Failed to update settings.', {
        variant: 'error',
      });
    }
  };

  const handleToggleDefault = async (enabled: boolean): Promise<void> => {
    await handleUpdateSettings({ enabledByDefault: enabled });
  };

  const handleToggleFormatterDefault = async (enabled: boolean): Promise<void> => {
    await handleUpdateSettings({ formatterEnabledByDefault: enabled });
  };

  const handleInstanceBehaviorChange = async (
    scope: ProductValidationInstanceScope,
    behavior: ProductValidationDenyBehavior
  ): Promise<void> => {
    const nextMap = normalizeProductValidationInstanceDenyBehaviorMap({
      ...(settings?.instanceDenyBehavior ?? {}),
      [scope]: behavior,
    });
    await handleUpdateSettings({ instanceDenyBehavior: nextMap });
  };

  const handleReorder = useCallback(
    async (patternId: string, targetIndex: number): Promise<void> => {
      const nextPatterns = [...patterns];
      const currentIndex = nextPatterns.findIndex((p) => p.id === patternId);
      if (currentIndex === -1) return;

      const [moved] = nextPatterns.splice(currentIndex, 1);
      if (!moved) return;
      nextPatterns.splice(targetIndex, 0, moved);

      const updates: ReorderValidationPatternUpdatePayload[] = nextPatterns.map((p, index) => ({
        id: p.id,
        sequence: (index + 1) * 10,
      }));

      try {
        await reorderPatterns.mutateAsync({ updates });
      } catch (error) {
        logClientCatch(error, {
          source: 'useValidatorSettingsController',
          action: 'reorder',
          patternId,
        });
        toast(error instanceof Error ? error.message : 'Failed to reorder patterns.', {
          variant: 'error',
        });
      }
    },
    [patterns, reorderPatterns.mutateAsync, toast]
  );

  const handleReorderGroupInGroup = useCallback(
    async (_groupId: string, patternId: string, targetIndex: number): Promise<void> => {
      // This is simplified but should satisfy the component's need for now
      await handleReorder(patternId, targetIndex);
    },
    [handleReorder]
  );

  const handleDragStart = useCallback((e: unknown, patternId: string): void => {
    const dragEvent = e as DragEvent;
    if (dragEvent.dataTransfer) {
      dragEvent.dataTransfer.setData('patternId', patternId);
    }
  }, []);

  const handleDrop = useCallback(
    (pattern: ProductValidationPattern, e: unknown): void => {
      const dragEvent = e as DragEvent;
      if (!dragEvent.dataTransfer) return;
      const draggedId =
        dragEvent.dataTransfer.getData('text/plain') || dragEvent.dataTransfer.getData('patternId');
      if (!draggedId || draggedId === pattern.id) return;

      const targetIndex = orderedPatterns.findIndex((p) => p.id === pattern.id);
      if (targetIndex === -1) return;

      const targetGroupId = sequenceScopedPatternIds.has(pattern.id)
        ? pattern.sequenceGroupId?.trim() || null
        : null;
      if (!targetGroupId) {
        void handleReorder(draggedId, targetIndex);
        return;
      }

      const targetGroup = sequenceGroups.get(targetGroupId);
      const targetGroupLabel =
        targetGroup?.label ?? pattern.sequenceGroupLabel ?? 'Sequence / Group';
      const targetGroupDebounceMs = targetGroup?.debounceMs ?? pattern.sequenceGroupDebounceMs ?? 0;

      const nextPatterns = [...patterns];
      const currentIndex = nextPatterns.findIndex((p) => p.id === draggedId);
      if (currentIndex === -1) return;

      const [moved] = nextPatterns.splice(currentIndex, 1);
      if (!moved) return;
      nextPatterns.splice(targetIndex, 0, moved);

      const updates: ReorderValidationPatternUpdatePayload[] = nextPatterns.map((p, index) => {
        const base: ReorderValidationPatternUpdatePayload = {
          id: p.id,
          sequence: (index + 1) * 10,
        };

        if (p.id !== draggedId) return base;

        return {
          ...base,
          sequenceGroupId: targetGroupId,
          sequenceGroupLabel: targetGroupLabel,
          sequenceGroupDebounceMs: targetGroupDebounceMs,
        };
      });

      void reorderPatterns
        .mutateAsync({ updates })
        .then(() => {
          toast('Pattern attached to sequence.', { variant: 'success' });
        })
        .catch((error: unknown) => {
          logClientError(error, {
            context: {
              source: 'useValidatorSettingsController',
              action: 'dropToSequence',
              draggedId,
              targetId: pattern.id,
              targetGroupId,
            },
          });
          toast(error instanceof Error ? error.message : 'Failed to attach pattern to sequence.', {
            variant: 'error',
          });
        });
    },
    [
      orderedPatterns,
      handleReorder,
      sequenceGroups,
      patterns,
      reorderPatterns.mutateAsync,
      sequenceScopedPatternIds,
      toast,
    ]
  );

  const summary = useMemo(
    () => ({
      total: patterns.length,
      enabled: patterns.filter((p) => p.enabled).length,
      replacementEnabled: patterns.filter((p) => p.replacementEnabled).length,
    }),
    [patterns]
  );

  return {
    patterns,
    settings,
    summary,
    orderedPatterns,
    enabledByDefault: settings?.enabledByDefault ?? true,
    formatterEnabledByDefault: settings?.formatterEnabledByDefault ?? false,
    instanceDenyBehavior: normalizeProductValidationInstanceDenyBehaviorMap(
      settings?.instanceDenyBehavior ?? {}
    ),
    loading: patternsQuery.isLoading || settingsQuery.isLoading,
    isUpdating:
      createPattern.isPending ||
      updatePattern.isPending ||
      deletePattern.isPending ||
      reorderPatterns.isPending ||
      updateSettings.isPending,
    settingsBusy: updateSettings.isPending,
    patternActionsPending:
      createPattern.isPending || updatePattern.isPending || deletePattern.isPending,
    reorderPending: reorderPatterns.isPending,
    showModal,
    setShowModal,
    closeModal: () => {
      setShowModal(false);
      setModalSemanticState(null);
    },
    editingPattern,
    modalSemanticState,
    modalSemanticTransition,
    formData,
    setFormData,
    testResult,
    simulatorScope,
    setSimulatorScope,
    simulatorValues,
    setSimulatorValue,
    simulatorCategoryFixtures,
    setSimulatorCategoryFixtures,
    handleSave: handleSavePattern,
    handleSavePattern,
    handleTogglePattern,
    handleDeletePattern,
    handleUpdateSettings,
    handleToggleDefault,
    handleToggleFormatterDefault,
    handleInstanceBehaviorChange,
    handleEditPattern,
    handleDuplicatePattern,
    handleAddPattern,
    handleDragStart,
    handleDrop,
    replacementFieldOptions: REPLACEMENT_FIELD_OPTIONS,
    sourceFieldOptions: getSourceFieldOptionsForTarget(formData.target),
    createPatternPending: createPattern.isPending,
    updatePatternPending: updatePattern.isPending,
    // Helpers
    isLocaleTarget,
    normalizeReplacementFields,
    getReplacementFieldsForTarget,
    getSourceFieldOptionsForTarget,
    formatReplacementFields,
    // Drag state
    draggedPatternId,
    setDraggedPatternId,
    dragOverPatternId,
    setDragOverPatternId,
    handlePatternDrop: handleDrop,
    // Sequence group actions
    sequenceGroups,
    firstPatternIdByGroup,
    getSequenceGroupId: (p: ProductValidationPattern) =>
      sequenceScopedPatternIds.has(p.id) ? p.sequenceGroupId : null,
    handleMoveGroup,
    handleReorderInGroup: handleReorderGroupInGroup,
    handleMoveToGroup,
    handleRemoveFromGroup,
    handleCreateGroup,
    handleRenameGroup,
    handleUpdateGroupDebounce,
    // Specialized creation
    onCreateSkuAutoIncrementSequence: handleCreateSkuAutoIncrementSequence,
    onCreateLatestPriceStockSequence: handleCreateLatestPriceStockSequence,
    handleCreateNameLengthMirrorPattern,
    handleCreateNameCategoryMirrorPattern,
    handleCreateStarGaterProducerPattern,
    handleCreateNameMirrorPolishSequence,
    handleSaveSequenceGroup,
    handleUngroup,
    // Deletion
    patternToDelete,
    setPatternToDelete,
    // Drafts
    groupDrafts,
    setGroupDrafts,
    getGroupDraft,
    openCreate: handleAddPattern,
    openEdit: handleEditPattern,
  };
}

// Validator pattern simulator: UI logic for running validator patterns locally
// in the admin settings. This module wires the simulator input shapes to the
// validation engine, normalizes patterns, and guards against unsafe replacement
// executions in the browser.
import type { DynamicReplacementSourceMode, ProductValidationInstanceScope, ProductValidationPattern, ProductValidationSemanticState } from '@/shared/contracts/products/validation';
import type { PatternFormData, SequenceGroupView, ValidatorPatternSimulatorInput } from '@/shared/contracts/products/drafts';
import type { ProductCategory } from '@/shared/contracts/products/categories';
import type { Producer } from '@/shared/contracts/products/producers';
import {
  isPatternEnabledForValidationScope,
  isPatternReplacementEnabledForValidationScope,
} from '@/shared/lib/products/utils/validator-instance-behavior';
import { encodeDynamicReplacementRecipe } from '@/shared/lib/products/utils/validator-replacement-recipe';
import {
  allowsPatternExecutionWithoutRegexMatch,
  applyResolvedReplacement,
  isPatternLocaleMatch,
  isReplacementAllowedForField,
  normalizePatternChainMode,
  normalizePatternMaxExecutions,
  resolveFieldTargetAndLocale,
  sortValidatorPatterns,
  resolvePatternReplacementValue,
  shouldLaunchPattern,
} from '@/features/products/validation-engine/core';
import { applyValidatorFieldReplacement } from '@/features/products/lib/applyValidatorFieldReplacement';
import {
  buildProducerNameById,
  formatProducerDisplayValue,
} from '@/features/products/lib/resolveValidatorProducerReplacement';
import {
  PRODUCT_VALIDATION_REPLACEMENT_FIELD_LABELS,
  PRODUCT_VALIDATION_SOURCE_FIELD_OPTIONS,
  buildProductValidationSourceValues,
} from '@/features/products/lib/validatorSourceFields';
import { getReplacementFieldsForProductValidationTarget } from '@/features/products/lib/validatorTargetAdapters';

import { buildValidationPayload, parseStrictInt } from './controller-diff-utils';
import { buildDynamicRecipeFromForm, canCompileRegex } from './helpers';

export type ValidatorPatternSimulationResult = {
  status: 'invalid' | 'ready';
  error: string | null;
  fieldName: string;
  fieldLabel: string;
  validationScope: ProductValidationInstanceScope;
  patternEnabledForScope: boolean;
  replacementEnabledForScope: boolean;
  launchMatched: boolean;
  regexMatched: boolean;
  allowWithoutRegexMatch: boolean;
  replacementValue: string | null;
  applied: boolean;
  outputValue: string | number | null;
  outputDisplayValue: string | null;
  notes: string[];
  sequenceTrace: ValidatorPatternSequenceTraceStep[];
  sequenceGroupLabel: string | null;
};

export type ValidatorPatternSequenceTraceStep = {
  patternId: string;
  label: string;
  sequence: number | null;
  isPreviewPattern: boolean;
  inputValue: string;
  outputValue: string;
  launchMatched: boolean;
  regexMatched: boolean;
  allowWithoutRegexMatch: boolean;
  replacementEnabledForScope: boolean;
  replacementValue: string | null;
  executions: number;
  applied: boolean;
  skipReason:
    | 'disabled'
    | 'out_of_scope'
    | 'launch_blocked'
    | 'regex_no_match'
    | 'replacement_disabled'
    | 'replacement_unresolved'
    | null;
  stopReason:
    | 'chain_stop_on_match'
    | 'chain_stop_on_replace'
    | 'pass_output_disabled'
    | null;
};

const SOURCE_FIELD_LABEL_MAP = new Map(
  PRODUCT_VALIDATION_SOURCE_FIELD_OPTIONS.map((option) => [option.value, option.label])
);

const DEFAULT_SCOPE: ProductValidationInstanceScope = 'product_edit';

const resolveSimulatorFieldName = (target: string, locale: string): string => {
  if (target === 'name' || target === 'description') {
    const normalizedLocale = locale.trim().toLowerCase() || 'en';
    return `${target}_${normalizedLocale}`;
  }
  return getReplacementFieldsForProductValidationTarget(target)[0] ?? 'sku';
};

const getFieldLabel = (fieldName: string): string =>
  SOURCE_FIELD_LABEL_MAP.get(fieldName) ??
  PRODUCT_VALIDATION_REPLACEMENT_FIELD_LABELS[fieldName] ??
  fieldName;

const makeSimulatorInputKey = (sourceMode: DynamicReplacementSourceMode, fieldName: string): string =>
  `${sourceMode}:${fieldName}`;

export const buildValidatorPatternSimulatorInputs = (
  formData: PatternFormData
): ValidatorPatternSimulatorInput[] => {
  const currentFieldName = resolveSimulatorFieldName(formData.target, formData.locale);
  const inputs: ValidatorPatternSimulatorInput[] = [
    {
      key: makeSimulatorInputKey('current_field', currentFieldName),
      fieldName: currentFieldName,
      sourceMode: 'current_field',
      label: `Current ${getFieldLabel(currentFieldName)}`,
      placeholder: 'Current field value',
    },
  ];
  const seen = new Set<string>([makeSimulatorInputKey('current_field', currentFieldName)]);

  const addInput = (sourceMode: DynamicReplacementSourceMode, fieldName: string, labelPrefix: string) => {
    const normalizedFieldName = fieldName.trim();
    if (!normalizedFieldName) return;
    if (sourceMode === 'current_field') return;
    if (sourceMode === 'form_field' && normalizedFieldName === currentFieldName) return;
    const key = makeSimulatorInputKey(sourceMode, normalizedFieldName);
    if (seen.has(key)) return;
    seen.add(key);
    inputs.push({
      key,
      fieldName: normalizedFieldName,
      sourceMode,
      label: `${labelPrefix} ${getFieldLabel(normalizedFieldName)}`,
      placeholder:
        sourceMode === 'latest_product_field'
          ? 'Latest product source value'
          : 'Source value',
    });
  };

  addInput(formData.sourceMode, formData.sourceField, 'Source');
  if (formData.launchEnabled) {
    addInput(formData.launchSourceMode, formData.launchSourceField, 'Launch');
  }

  return inputs;
};

const parseCategoryFixtureLine = (line: string, index: number): ProductCategory | null => {
  const parts = line
    .split('|')
    .map((part) => part.trim())
    .filter((part) => part.length > 0);
  if (parts.length === 0) return null;

  const id = parts[0] ?? `sim-category-${index + 1}`;
  const name = parts[1] ?? parts[0] ?? `Category ${index + 1}`;

  return {
    id,
    name,
    name_en: parts[2] ?? name,
    name_pl: parts[3] ?? name,
    name_de: parts[4] ?? name,
    color: null,
    parentId: null,
    catalogId: 'simulator',
    createdAt: '',
    updatedAt: '',
  };
};

export const parseValidatorPatternSimulatorCategoryFixtures = (
  value: string
): ProductCategory[] =>
  value
    .split('\n')
    .map((line, index) => parseCategoryFixtureLine(line.trim(), index))
    .filter((category): category is ProductCategory => category !== null);

const buildPreviewPatternFromFormData = ({
  formData,
  sequenceGroups,
  editingPattern,
  modalSemanticState,
}: {
  formData: PatternFormData;
  sequenceGroups: Map<string, SequenceGroupView>;
  editingPattern: ProductValidationPattern | null;
  modalSemanticState: ProductValidationSemanticState | null;
}):
  | { error: string; pattern: null }
  | {
      error: null;
      pattern: ProductValidationPattern;
    } => {
  if (!formData.regex.trim()) {
    return { error: 'Enter a regex to preview the pattern.', pattern: null };
  }
  if (!canCompileRegex(formData.regex, formData.flags)) {
    return { error: 'Regex is invalid.', pattern: null };
  }

  const parsedSequence =
    formData.sequence.trim().length === 0 ? null : parseStrictInt(formData.sequence);
  if (formData.sequence.trim().length > 0 && (parsedSequence === null || parsedSequence < 0)) {
    return { error: 'Sequence must be a whole number greater than or equal to 0.', pattern: null };
  }

  const parsedMaxExecutions = parseStrictInt(formData.maxExecutions);
  if (parsedMaxExecutions === null || parsedMaxExecutions < 1 || parsedMaxExecutions > 20) {
    return { error: 'Max executions must be a whole number between 1 and 20.', pattern: null };
  }

  const parsedValidationDebounceMs = parseStrictInt(formData.validationDebounceMs);
  if (
    parsedValidationDebounceMs === null ||
    parsedValidationDebounceMs < 0 ||
    parsedValidationDebounceMs > 30_000
  ) {
    return { error: 'Debounce must be a whole number between 0 and 30000.', pattern: null };
  }

  let replacementValue: string | null = null;
  if (formData.replacementMode === 'dynamic') {
    const recipe = buildDynamicRecipeFromForm(formData);
    if (!recipe) {
      return { error: 'Dynamic replacer config is incomplete.', pattern: null };
    }
    replacementValue = encodeDynamicReplacementRecipe(recipe);
  } else {
    replacementValue = formData.replacementValue.length > 0 ? formData.replacementValue : null;
  }

  const payload = buildValidationPayload({
    formData,
    sequenceGroups,
    editingPattern,
    semanticState: modalSemanticState,
    replacementValue,
    parsedSequence,
    parsedMaxExecutions,
    parsedValidationDebounceMs,
  });

  return {
    error: null,
    pattern: {
      id: editingPattern?.id ?? '__preview__',
      createdAt: editingPattern?.createdAt ?? '',
      updatedAt: editingPattern?.updatedAt ?? '',
      label: payload.label ?? '',
      target: payload.target ?? 'name',
      locale: payload.locale ?? null,
      regex: payload.regex ?? '',
      flags: payload.flags ?? null,
      message: payload.message ?? '',
      severity: payload.severity ?? 'warning',
      enabled: payload.enabled ?? true,
      replacementEnabled: payload.replacementEnabled ?? false,
      replacementAutoApply: payload.replacementAutoApply ?? false,
      skipNoopReplacementProposal: payload.skipNoopReplacementProposal ?? true,
      replacementValue: payload.replacementValue ?? null,
      replacementFields: payload.replacementFields ?? [],
      replacementAppliesToScopes: payload.replacementAppliesToScopes ?? [
        'draft_template',
        'product_create',
        'product_edit',
      ],
      runtimeEnabled: payload.runtimeEnabled ?? false,
      runtimeType: payload.runtimeType ?? 'none',
      runtimeConfig: payload.runtimeConfig ?? null,
      postAcceptBehavior: payload.postAcceptBehavior ?? 'revalidate',
      denyBehaviorOverride: payload.denyBehaviorOverride ?? null,
      validationDebounceMs: payload.validationDebounceMs ?? 0,
      sequenceGroupId: payload.sequenceGroupId ?? null,
      sequenceGroupLabel: payload.sequenceGroupLabel ?? null,
      sequenceGroupDebounceMs: payload.sequenceGroupDebounceMs ?? 0,
      sequence: payload.sequence ?? null,
      chainMode: payload.chainMode ?? 'continue',
      maxExecutions: payload.maxExecutions ?? 1,
      passOutputToNext: payload.passOutputToNext ?? true,
      launchEnabled: payload.launchEnabled ?? false,
      launchAppliesToScopes: payload.launchAppliesToScopes ?? [
        'draft_template',
        'product_create',
        'product_edit',
      ],
      launchScopeBehavior: payload.launchScopeBehavior ?? 'gate',
      launchSourceMode: payload.launchSourceMode ?? 'current_field',
      launchSourceField: payload.launchSourceField ?? null,
      launchOperator: payload.launchOperator ?? 'equals',
      launchValue: payload.launchValue ?? null,
      launchFlags: payload.launchFlags ?? null,
      appliesToScopes: payload.appliesToScopes ?? ['draft_template', 'product_create', 'product_edit'],
      semanticState: payload.semanticState ?? null,
    },
  };
};

const buildSequenceTracePatterns = ({
  previewPattern,
  orderedPatterns,
  editingPattern,
  fieldName,
}: {
  previewPattern: ProductValidationPattern;
  orderedPatterns: ProductValidationPattern[];
  editingPattern: ProductValidationPattern | null;
  fieldName: string;
}): ProductValidationPattern[] => {
  const groupId = previewPattern.sequenceGroupId?.trim() ?? '';
  if (!groupId) return [previewPattern];

  const { locale: fieldLocale } = resolveFieldTargetAndLocale(fieldName);
  const filtered = orderedPatterns.filter((pattern) => {
    const patternGroupId = pattern.sequenceGroupId?.trim() ?? '';
    if (patternGroupId !== groupId) return false;
    if (pattern.target !== previewPattern.target) return false;
    if (!isPatternLocaleMatch(pattern.locale ?? null, fieldLocale)) return false;
    return isReplacementAllowedForField(pattern, fieldName);
  });

  const withoutEdited = editingPattern
    ? filtered.filter((pattern) => pattern.id !== editingPattern.id)
    : filtered;

  return sortValidatorPatterns([...withoutEdited, previewPattern]);
};

const buildSequenceTrace = ({
  tracePatterns,
  previewPattern,
  fieldValue,
  validationScope,
  values,
  latestProductValues,
}: {
  tracePatterns: ProductValidationPattern[];
  previewPattern: ProductValidationPattern;
  fieldValue: string;
  validationScope: ProductValidationInstanceScope;
  values: Record<string, unknown>;
  latestProductValues: Record<string, unknown> | null;
}): {
  steps: ValidatorPatternSequenceTraceStep[];
  finalValue: string;
} => {
  const steps: ValidatorPatternSequenceTraceStep[] = [];
  let candidateValue = fieldValue;

  for (const pattern of tracePatterns) {
    const inputValue = candidateValue;
    const patternEnabledForScope =
      pattern.enabled &&
      isPatternEnabledForValidationScope(pattern.appliesToScopes, validationScope);
    const replacementEnabledForScope = isPatternReplacementEnabledForValidationScope(
      pattern.replacementAppliesToScopes,
      validationScope
    );
    const allowWithoutRegexMatch = allowsPatternExecutionWithoutRegexMatch(pattern);

    let launchMatched = false;
    let regexMatched = false;
    let replacementValue: string | null = null;
    let executions = 0;
    let applied = false;
    let outputValue = inputValue;
    let skipReason: ValidatorPatternSequenceTraceStep['skipReason'] = null;
    let stopReason: ValidatorPatternSequenceTraceStep['stopReason'] = null;

    if (!pattern.enabled) {
      skipReason = 'disabled';
    } else if (!patternEnabledForScope) {
      skipReason = 'out_of_scope';
    } else {
      const maxExecutions = normalizePatternMaxExecutions(pattern);
      let matched = false;
      let replaced = false;

      for (let execution = 0; execution < maxExecutions; execution += 1) {
        launchMatched = shouldLaunchPattern({
          pattern,
          validationScope,
          fieldValue: candidateValue,
          values,
          latestProductValues,
        });
        if (!launchMatched) {
          if (executions === 0) skipReason = 'launch_blocked';
          break;
        }

        try {
          regexMatched = new RegExp(pattern.regex, pattern.flags ?? undefined).test(candidateValue);
        } catch {
          regexMatched = false;
        }

        if (!regexMatched && !allowWithoutRegexMatch) {
          if (executions === 0) skipReason = 'regex_no_match';
          break;
        }

        matched = true;
        executions += 1;
        const replacement = replacementEnabledForScope
          ? resolvePatternReplacementValue({
              pattern,
              fieldValue: candidateValue,
              values,
              latestProductValues,
            })
          : null;
        replacementValue = replacement?.value ?? null;

        if (!replacementEnabledForScope) {
          skipReason = 'replacement_disabled';
          break;
        }
        if (!replacement) {
          skipReason = 'replacement_unresolved';
          break;
        }
        const replacedValue = applyResolvedReplacement({
          value: candidateValue,
          pattern,
          replacement,
        });
        outputValue = replacedValue;
        if (replacedValue === candidateValue) {
          break;
        }

        applied = true;
        replaced = true;
        candidateValue = replacedValue;
      }

      const chainMode = normalizePatternChainMode(pattern);
      if (matched && chainMode === 'stop_on_match') {
        stopReason = 'chain_stop_on_match';
      } else if (replaced && chainMode === 'stop_on_replace') {
        stopReason = 'chain_stop_on_replace';
      } else if (replaced && pattern.passOutputToNext === false) {
        stopReason = 'pass_output_disabled';
      }
    }

    steps.push({
      patternId: pattern.id,
      label: pattern.label,
      sequence: pattern.sequence ?? null,
      isPreviewPattern: pattern.id === previewPattern.id,
      inputValue,
      outputValue,
      launchMatched,
      regexMatched,
      allowWithoutRegexMatch,
      replacementEnabledForScope,
      replacementValue,
      executions,
      applied,
      skipReason,
      stopReason,
    });

    if (stopReason) break;
  }

  return {
    steps,
    finalValue: candidateValue,
  };
};

const buildCategoryNameById = (categories: ProductCategory[]): Map<string, string> =>
  new Map(
    categories
      .map((category) => [category.id, category.name] as const)
      .filter(([id, name]) => Boolean(id) && Boolean(name))
  );

const toStringValue = (value: unknown): string => {
  if (typeof value === 'string') return value;
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  return '';
};

export const simulateValidatorPatternPreview = ({
  pattern,
  formData,
  validationScope = DEFAULT_SCOPE,
  simulatorValues,
  categoryFixturesText,
  producers,
}: {
  pattern: ProductValidationPattern;
  formData: PatternFormData;
  validationScope?: ProductValidationInstanceScope;
  simulatorValues: Record<string, string>;
  categoryFixturesText: string;
  producers?: ReadonlyArray<Producer>;
}): ValidatorPatternSimulationResult => {
  const currentFieldName = resolveSimulatorFieldName(formData.target, formData.locale);
  const currentFieldLabel = getFieldLabel(currentFieldName);
  const currentFieldKey = makeSimulatorInputKey('current_field', currentFieldName);
  const currentFieldValue = simulatorValues[currentFieldKey] ?? '';
  const categories = parseValidatorPatternSimulatorCategoryFixtures(categoryFixturesText);
  const categoryNameById = buildCategoryNameById(categories);
  const producerNameById = buildProducerNameById(producers);
  const descriptors = buildValidatorPatternSimulatorInputs(formData);

  const rawFormValues: Record<string, unknown> = {
    [currentFieldName]: currentFieldValue,
  };
  const latestProductValues: Record<string, unknown> = {};

  for (const descriptor of descriptors) {
    const inputValue = simulatorValues[descriptor.key] ?? '';
    if (descriptor.sourceMode === 'latest_product_field') {
      latestProductValues[descriptor.fieldName] = inputValue;
      continue;
    }
    rawFormValues[descriptor.fieldName] = inputValue;
  }

  const values = {
    ...buildProductValidationSourceValues({
      baseValues: rawFormValues,
      categories,
      producers,
      selectedCategoryId:
        currentFieldName === 'categoryId' ? currentFieldValue : toStringValue(rawFormValues['categoryId']),
      selectedCatalogIds: [],
      fallbackCatalogId: 'simulator',
    }),
    ...Object.fromEntries(
      descriptors
        .filter((descriptor) => descriptor.sourceMode === 'form_field')
        .map((descriptor) => [descriptor.fieldName, simulatorValues[descriptor.key] ?? ''])
    ),
  };

  const notes: string[] = [];
  const patternEnabledForScope = isPatternEnabledForValidationScope(
    pattern.appliesToScopes,
    validationScope
  );
  const replacementEnabledForScope = isPatternReplacementEnabledForValidationScope(
    pattern.replacementAppliesToScopes,
    validationScope
  );
  const allowWithoutRegexMatch = allowsPatternExecutionWithoutRegexMatch(pattern);

  let regexMatched = false;
  try {
    regexMatched = new RegExp(pattern.regex, pattern.flags ?? undefined).test(currentFieldValue);
  } catch (error) {
    return {
      status: 'invalid',
      error: error instanceof Error ? error.message : 'Invalid regular expression.',
      fieldName: currentFieldName,
      fieldLabel: currentFieldLabel,
      validationScope,
      patternEnabledForScope,
      replacementEnabledForScope,
      launchMatched: false,
      regexMatched: false,
      allowWithoutRegexMatch,
      replacementValue: null,
      applied: false,
      outputValue: null,
      outputDisplayValue: null,
      notes,
      sequenceTrace: [],
      sequenceGroupLabel: null,
    };
  }

  if (!patternEnabledForScope) {
    notes.push(`Pattern is disabled for ${validationScope}.`);
  }
  if (!replacementEnabledForScope) {
    notes.push(`Replacement is disabled for ${validationScope}.`);
  }
  if (pattern.runtimeEnabled && pattern.runtimeType !== 'none') {
    notes.push('Runtime replacement preview is not evaluated in the simulator.');
  }
  if (pattern.target === 'category' && categories.length === 0) {
    notes.push('Add category fixtures to preview label-to-category resolution.');
  }
  if (pattern.target === 'producer' && (producers?.length ?? 0) === 0) {
    notes.push('Producer replacement preview waits for producers metadata to load.');
  }

  const launchMatched = shouldLaunchPattern({
    pattern,
    validationScope,
    fieldValue: currentFieldValue,
    values,
    latestProductValues,
  });

  if (!launchMatched) {
    notes.push('Launch conditions did not match.');
  }
  if (!regexMatched && !allowWithoutRegexMatch) {
    notes.push('Regex did not match the current field value.');
  }

  const replacement = launchMatched
    ? resolvePatternReplacementValue({
        pattern,
        fieldValue: currentFieldValue,
        values,
        latestProductValues,
      })
    : null;
  const nextFieldValue =
    launchMatched && replacementEnabledForScope
      ? applyResolvedReplacement({
          value: currentFieldValue,
          pattern,
          replacement,
        })
      : currentFieldValue;

  const simulatedCurrentValues: Record<string, unknown> = {
    ...values,
    [currentFieldName]: currentFieldValue,
  };
  let appliedOutputValue: string | number | null = toStringValue(
    simulatedCurrentValues[currentFieldName]
  );
  let appliedOutputDisplayValue: string | null =
    currentFieldName === 'categoryId'
      ? (categoryNameById.get(toStringValue(simulatedCurrentValues[currentFieldName])) ??
          toStringValue(simulatedCurrentValues[currentFieldName])) ||
        null
      : currentFieldName === 'producerIds'
        ? formatProducerDisplayValue({
            producerIds: [],
            fallbackValue: toStringValue(simulatedCurrentValues[currentFieldName]) ?? '',
          }) || null
      : toStringValue(simulatedCurrentValues[currentFieldName]) || null;

  const applied =
    launchMatched &&
    replacementEnabledForScope &&
    (regexMatched || allowWithoutRegexMatch) &&
    applyValidatorFieldReplacement({
      fieldName: currentFieldName,
      replacementValue: nextFieldValue,
      categories,
      categoryNameById,
      producers,
      producerNameById,
      getCurrentFieldValue: (fieldName) => simulatedCurrentValues[fieldName],
      setFormFieldValue: (fieldName, value) => {
        simulatedCurrentValues[fieldName] = value;
        appliedOutputValue = typeof value === 'number' ? value : toStringValue(value);
        appliedOutputDisplayValue = toStringValue(value) || null;
      },
      setCategoryId: (categoryId) => {
        simulatedCurrentValues['categoryId'] = categoryId ?? '';
        appliedOutputValue = categoryId ?? null;
        appliedOutputDisplayValue = categoryId
          ? (categoryNameById.get(categoryId) ?? categoryId)
          : null;
      },
      setProducerIds: (producerIds) => {
        simulatedCurrentValues['producerIds'] = producerIds;
        appliedOutputValue = formatProducerDisplayValue({
          producerIds,
          producers,
          producerNameById,
        });
        appliedOutputDisplayValue = appliedOutputValue || null;
      },
    });

  if (launchMatched && replacementEnabledForScope && !applied && pattern.target === 'category') {
    notes.push('Replacement could not be resolved to a category ID.');
  }
  if (launchMatched && replacementEnabledForScope && !applied && pattern.target === 'producer') {
    notes.push('Replacement could not be resolved to producer metadata.');
  }

  return {
    status: 'ready',
    error: null,
    fieldName: currentFieldName,
    fieldLabel: currentFieldLabel,
    validationScope,
    patternEnabledForScope,
    replacementEnabledForScope,
    launchMatched,
    regexMatched,
    allowWithoutRegexMatch,
    replacementValue: replacement?.value ?? null,
    applied,
    outputValue: appliedOutputValue,
    outputDisplayValue: appliedOutputDisplayValue,
    notes,
    sequenceTrace: [],
    sequenceGroupLabel: pattern.sequenceGroupLabel ?? null,
  };
};

export const buildAndSimulateValidatorPatternPreview = ({
  formData,
  sequenceGroups,
  orderedPatterns,
  editingPattern,
  modalSemanticState,
  validationScope = DEFAULT_SCOPE,
  simulatorValues,
  categoryFixturesText,
  producers,
}: {
  formData: PatternFormData;
  sequenceGroups: Map<string, SequenceGroupView>;
  orderedPatterns: ProductValidationPattern[];
  editingPattern: ProductValidationPattern | null;
  modalSemanticState: ProductValidationSemanticState | null;
  validationScope?: ProductValidationInstanceScope;
  simulatorValues: Record<string, string>;
  categoryFixturesText: string;
  producers?: ReadonlyArray<Producer>;
}): ValidatorPatternSimulationResult => {
  const currentFieldName = resolveSimulatorFieldName(formData.target, formData.locale);
  const currentFieldLabel = getFieldLabel(currentFieldName);
  const previewPatternResult = buildPreviewPatternFromFormData({
    formData,
    sequenceGroups,
    editingPattern,
    modalSemanticState,
  });
  if (previewPatternResult.error || !previewPatternResult.pattern) {
    return {
      status: 'invalid',
      error: previewPatternResult.error ?? 'Pattern preview could not be created.',
      fieldName: currentFieldName,
      fieldLabel: currentFieldLabel,
      validationScope,
      patternEnabledForScope: true,
      replacementEnabledForScope: true,
      launchMatched: false,
      regexMatched: false,
      allowWithoutRegexMatch: false,
      replacementValue: null,
      applied: false,
      outputValue: null,
      outputDisplayValue: null,
      notes: [],
      sequenceTrace: [],
      sequenceGroupLabel: null,
    };
  }

  const baseResult = simulateValidatorPatternPreview({
    pattern: previewPatternResult.pattern,
    formData,
    validationScope,
    simulatorValues,
    categoryFixturesText,
    producers,
  });

  if (baseResult.status !== 'ready') {
    return baseResult;
  }

  const tracePatterns = buildSequenceTracePatterns({
    previewPattern: previewPatternResult.pattern,
    orderedPatterns,
    editingPattern,
    fieldName: baseResult.fieldName,
  });
  const categories = parseValidatorPatternSimulatorCategoryFixtures(categoryFixturesText);
  const producerNameById = buildProducerNameById(producers);
  const descriptors = buildValidatorPatternSimulatorInputs(formData);
  const rawFormValues: Record<string, unknown> = {
    [baseResult.fieldName]: simulatorValues[makeSimulatorInputKey('current_field', baseResult.fieldName)] ?? '',
  };
  const latestProductValues: Record<string, unknown> = {};

  for (const descriptor of descriptors) {
    const inputValue = simulatorValues[descriptor.key] ?? '';
    if (descriptor.sourceMode === 'latest_product_field') {
      latestProductValues[descriptor.fieldName] = inputValue;
      continue;
    }
    rawFormValues[descriptor.fieldName] = inputValue;
  }

  const values = {
    ...buildProductValidationSourceValues({
      baseValues: rawFormValues,
      categories,
      producers,
      selectedCategoryId:
        baseResult.fieldName === 'categoryId'
          ? (simulatorValues[makeSimulatorInputKey('current_field', baseResult.fieldName)] ?? '')
          : toStringValue(rawFormValues['categoryId']),
      selectedCatalogIds: [],
      fallbackCatalogId: 'simulator',
    }),
    ...Object.fromEntries(
      descriptors
        .filter((descriptor) => descriptor.sourceMode === 'form_field')
        .map((descriptor) => [descriptor.fieldName, simulatorValues[descriptor.key] ?? ''])
    ),
  };

  const trace = buildSequenceTrace({
    tracePatterns,
    previewPattern: previewPatternResult.pattern,
    fieldValue:
      simulatorValues[makeSimulatorInputKey('current_field', baseResult.fieldName)] ?? '',
    validationScope,
    values,
    latestProductValues,
  });

  const categoryNameById = buildCategoryNameById(categories);
  const simulatedCurrentValues: Record<string, unknown> = {
    ...values,
    [baseResult.fieldName]:
      simulatorValues[makeSimulatorInputKey('current_field', baseResult.fieldName)] ?? '',
  };
  let traceOutputValue: string | number | null = toStringValue(
    simulatedCurrentValues[baseResult.fieldName]
  );
  let traceOutputDisplayValue: string | null =
    baseResult.fieldName === 'categoryId'
      ? (categoryNameById.get(toStringValue(simulatedCurrentValues[baseResult.fieldName])) ??
          toStringValue(simulatedCurrentValues[baseResult.fieldName])) ||
        null
      : baseResult.fieldName === 'producerIds'
        ? formatProducerDisplayValue({
            producerIds: [],
            fallbackValue:
              toStringValue(simulatedCurrentValues[baseResult.fieldName]) ?? '',
          }) || null
      : toStringValue(simulatedCurrentValues[baseResult.fieldName]) || null;

  const traceApplied = applyValidatorFieldReplacement({
    fieldName: baseResult.fieldName,
    replacementValue: trace.finalValue,
    categories,
    categoryNameById,
    producers,
    producerNameById,
    getCurrentFieldValue: (fieldName) => simulatedCurrentValues[fieldName],
    setFormFieldValue: (fieldName, value) => {
      simulatedCurrentValues[fieldName] = value;
      traceOutputValue = typeof value === 'number' ? value : toStringValue(value);
      traceOutputDisplayValue = toStringValue(value) || null;
    },
    setCategoryId: (categoryId) => {
      simulatedCurrentValues['categoryId'] = categoryId ?? '';
      traceOutputValue = categoryId ?? null;
      traceOutputDisplayValue = categoryId
        ? (categoryNameById.get(categoryId) ?? categoryId)
        : null;
    },
    setProducerIds: (producerIds) => {
      simulatedCurrentValues['producerIds'] = producerIds;
      traceOutputValue = formatProducerDisplayValue({
        producerIds,
        producers,
        producerNameById,
      });
      traceOutputDisplayValue = traceOutputValue || null;
    },
  });

  return {
    ...baseResult,
    applied: traceApplied,
    outputValue: traceOutputValue,
    outputDisplayValue: traceOutputDisplayValue,
    sequenceTrace: trace.steps,
    sequenceGroupLabel: previewPatternResult.pattern.sequenceGroupLabel ?? null,
  };
};

'use client';

// ProductFormCoreContext: provides the core react-hook-form context and
// helpers for product create/edit flows. Responsibilities:
// - Initialize form state, validation schema, and submission lifecycle
// - Offer helpers for normalization and draft bootstrapping used by form tabs
// Keep this module client-only since it integrates with browser APIs and form
// lifecycle hooks.

import { zodResolver } from '@hookform/resolvers/zod';
import {
  createContext,
  useContext,
  type BaseSyntheticEvent,
  useCallback,
  useEffect,
  useState,
  useMemo,
  useRef,
} from 'react';
import {
  type UseFormRegister,
  type UseFormSetValue,
  type UseFormGetValues,
  type FieldErrors,
  useForm,
  type Resolver,
  FormProvider,
  type UseFormReturn,
} from 'react-hook-form';

import { type ProductFormData, type ProductDraft } from '@/shared/contracts/products/drafts';
import {
  type ProductWithImages,
  type ProductNotes,
  normalizeProductMarketplaceContentOverrideDrafts,
} from '@/shared/contracts/products/product';
import { internalError } from '@/shared/errors/app-error';
import { PRODUCT_SKU_AUTO_INCREMENT_PLACEHOLDER } from '@/shared/lib/products/constants';
import {
  productCreateSchema,
  productUpdateSchema,
} from '@/shared/lib/products/validations/schemas';

const normalizeOptionalString = (value: string | null | undefined): string => value || '';

const normalizeProductFormNotes = (
  value: ProductNotes | null | undefined
): ProductNotes | undefined => {
  if (!value) return undefined;

  const text = typeof value.text === 'string' ? value.text : null;
  const color = typeof value.color === 'string' ? value.color : null;

  if (!text && !color) {
    return undefined;
  }

  return {
    text,
    color,
  };
};

export const resolveProductFormDefaultValues = ({
  product,
  draft,
  initialSku,
}: {
  product?: ProductWithImages;
  draft?: ProductDraft | null;
  initialSku?: string;
}): ProductFormData => ({
  name_en: product?.name_en || draft?.name_en || '',
  name_pl: product?.name_pl || draft?.name_pl || '',
  name_de: product?.name_de || draft?.name_de || '',
  price: product?.price ?? draft?.price ?? 0,
  sku: resolveProductFormDefaultSku({ product, draft, initialSku }),
  defaultPriceGroupId: product?.defaultPriceGroupId ?? draft?.defaultPriceGroupId ?? undefined,
  baseProductId: product?.baseProductId ?? draft?.baseProductId ?? undefined,
  importSource: product?.importSource ?? draft?.importSource ?? undefined,
  ean: normalizeOptionalString(product?.ean) || normalizeOptionalString(draft?.ean),
  gtin: normalizeOptionalString(product?.gtin) || normalizeOptionalString(draft?.gtin),
  asin: normalizeOptionalString(product?.asin) || normalizeOptionalString(draft?.asin),
  description_en:
    normalizeOptionalString(product?.description_en) || normalizeOptionalString(draft?.description_en),
  description_pl:
    normalizeOptionalString(product?.description_pl) || normalizeOptionalString(draft?.description_pl),
  description_de:
    normalizeOptionalString(product?.description_de) || normalizeOptionalString(draft?.description_de),
  supplierName:
    normalizeOptionalString(product?.supplierName) || normalizeOptionalString(draft?.supplierName),
  supplierLink:
    normalizeOptionalString(product?.supplierLink) || normalizeOptionalString(draft?.supplierLink),
  priceComment:
    normalizeOptionalString(product?.priceComment) || normalizeOptionalString(draft?.priceComment),
  stock: product?.stock ?? draft?.stock ?? 0,
  sizeLength: product?.sizeLength ?? draft?.sizeLength ?? 0,
  sizeWidth: product?.sizeWidth ?? draft?.sizeWidth ?? 0,
  weight: product?.weight ?? draft?.weight ?? 0,
  length: product?.length ?? draft?.length ?? 0,
  shippingGroupId: product?.shippingGroupId ?? draft?.shippingGroupId ?? '',
  marketplaceContentOverrides: normalizeProductMarketplaceContentOverrideDrafts(
    product?.marketplaceContentOverrides ?? draft?.marketplaceContentOverrides ?? []
  ).map((entry) => ({
    integrationIds: entry.integrationIds,
    title: entry.title ?? '',
    description: entry.description ?? '',
  })),
  notes: normalizeProductFormNotes(product?.notes ?? draft?.notes ?? undefined),
});

export interface ProductFormCoreContextType {
  register: UseFormRegister<ProductFormData>;
  hasUnsavedChanges: boolean;
  errors: FieldErrors<ProductFormData>;
  getValues: UseFormGetValues<ProductFormData>;
  selectedNoteIds: string[];
  generationError: string | null;
  normalizeNameError: string | null;
  product?: ProductWithImages | undefined;
  draft?: ProductDraft | null | undefined;
  ConfirmationModal: React.ComponentType;
  methods: UseFormReturn<ProductFormData>;
  uploading: boolean;
  uploadError: string | null;
  uploadSuccess: boolean;
  validatorSessionKey?: string;
}

export interface ProductFormCoreActionsContextType {
  handleSubmit: (e?: BaseSyntheticEvent) => Promise<void>;
  setValue: UseFormSetValue<ProductFormData>;
  toggleNote: (noteId: string) => void;
  removeNote: (noteId: string) => void;
  setGenerationError: (error: string | null) => void;
  setNormalizeNameError: (error: string | null) => void;
  setHandleSubmit: (fn: (e?: BaseSyntheticEvent) => Promise<void>) => void;
  setConfirmationModal: (component: React.ComponentType) => void;
  setHasUnsavedChanges: (value: boolean) => void;
  setUploading: (value: boolean) => void;
  setUploadError: (value: string | null) => void;
  setUploadSuccess: (value: boolean) => void;
}

type ProductFormCoreContextValue = ProductFormCoreContextType & ProductFormCoreActionsContextType;

export const ProductFormCoreStateContext = createContext<ProductFormCoreContextType | null>(null);
export const ProductFormCoreActionsContext = createContext<ProductFormCoreActionsContextType | null>(
  null
);

export const resolveProductFormDefaultSku = ({
  product,
  draft,
  initialSku,
}: {
  product?: ProductWithImages;
  draft?: ProductDraft | null;
  initialSku?: string;
}): string => {
  if (product?.sku) return product.sku;
  if (initialSku) return initialSku;
  if (draft) return PRODUCT_SKU_AUTO_INCREMENT_PLACEHOLDER;
  return '';
};

export function ProductFormCoreProvider({
  children,
  product,
  draft,
  requireSku = true,
  initialSku,
  validatorSessionKey,
}: {
  children: React.ReactNode;
  product?: ProductWithImages;
  draft?: ProductDraft | null;
  requireSku?: boolean;
  initialSku?: string;
  validatorSessionKey?: string;
}) {
  const formSchema = product || !requireSku ? productUpdateSchema : productCreateSchema;
  const defaultValues = useMemo(
    () => resolveProductFormDefaultValues({ product, draft, initialSku }),
    [draft, initialSku, product]
  );
  const defaultValuesSignature = useMemo(
    () =>
      JSON.stringify({
        productId: product?.id ?? null,
        draftId: draft?.id ?? null,
        values: defaultValues,
      }),
    [defaultValues, draft?.id, product?.id]
  );
  const methods = useForm<ProductFormData>({
    resolver: zodResolver(formSchema) as Resolver<ProductFormData>,
    defaultValues,
  });

  const [selectedNoteIds, setSelectedNoteIds] = useState<string[]>(() =>
    Array.isArray(product?.noteIds) ? product.noteIds : []
  );
  const [generationError, setGenerationError] = useState<string | null>(null);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const [handleSubmitFn, setHandleSubmitFn] = useState<(e?: BaseSyntheticEvent) => Promise<void>>(
    () => async () => {}
  );
  const [ConfirmationModal, setConfirmationModal] = useState<React.ComponentType>(() => () => null);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const [uploadSuccess, setUploadSuccess] = useState(false);
  const [normalizeNameError, setNormalizeNameError] = useState<string | null>(null);
  const hasAppliedInitialDefaultsRef = useRef(false);
  const latestDefaultValuesRef = useRef(defaultValues);

  latestDefaultValuesRef.current = defaultValues;

  useEffect(() => {
    if (!hasAppliedInitialDefaultsRef.current) {
      hasAppliedInitialDefaultsRef.current = true;
      return;
    }

    methods.reset(latestDefaultValuesRef.current, {
      keepDirtyValues: true,
    });
  }, [defaultValuesSignature, methods]);

  const updateHandleSubmit = useCallback((fn: (e?: BaseSyntheticEvent) => Promise<void>): void => {
    setHandleSubmitFn(() => fn);
  }, []);

  const updateConfirmationModal = useCallback((component: React.ComponentType): void => {
    setConfirmationModal(() => component);
  }, []);

  const toggleNote = (noteId: string): void => {
    const id = noteId.trim();
    if (!id) return;
    setSelectedNoteIds((prev: string[]) =>
      prev.includes(id) ? prev.filter((n: string) => n !== id) : [...prev, id]
    );
  };

  const removeNote = (noteId: string): void => {
    const id = noteId.trim();
    if (!id) return;
    setSelectedNoteIds((prev: string[]) => prev.filter((n: string) => n !== id));
  };

  const stateValue = useMemo(
    (): ProductFormCoreContextType => ({
      register: methods.register,
      hasUnsavedChanges,
      errors: methods.formState.errors,
      getValues: methods.getValues,
      selectedNoteIds,
      generationError,
      normalizeNameError,
      product,
      draft,
      ConfirmationModal,
      methods,
      uploading,
      uploadError,
      uploadSuccess,
      validatorSessionKey,
    }),
    [
      methods,
      hasUnsavedChanges,
      selectedNoteIds,
      generationError,
      normalizeNameError,
      product,
      draft,
      ConfirmationModal,
      uploading,
      uploadError,
      uploadSuccess,
      validatorSessionKey,
    ]
  );
  const actionsValue = useMemo(
    (): ProductFormCoreActionsContextType => ({
      handleSubmit: handleSubmitFn,
      setValue: methods.setValue,
      toggleNote,
      removeNote,
      setGenerationError,
      setNormalizeNameError,
      setHandleSubmit: updateHandleSubmit,
      setConfirmationModal: updateConfirmationModal,
      setHasUnsavedChanges,
      setUploading,
      setUploadError,
      setUploadSuccess,
    }),
    [
      handleSubmitFn,
      methods.setValue,
      toggleNote,
      removeNote,
      setGenerationError,
      setNormalizeNameError,
      updateHandleSubmit,
      updateConfirmationModal,
      setHasUnsavedChanges,
      setUploading,
      setUploadError,
      setUploadSuccess,
    ]
  );

  return (
    <ProductFormCoreActionsContext.Provider value={actionsValue}>
      <ProductFormCoreStateContext.Provider value={stateValue}>
        <FormProvider {...methods}>{children}</FormProvider>
      </ProductFormCoreStateContext.Provider>
    </ProductFormCoreActionsContext.Provider>
  );
}

export const useProductFormCoreState = (): ProductFormCoreContextType => {
  const context = useContext(ProductFormCoreStateContext);
  if (!context) {
    throw internalError('useProductFormCoreState must be used within a ProductFormCoreProvider');
  }
  return context;
};

export const useProductFormCoreActions = (): ProductFormCoreActionsContextType => {
  const context = useContext(ProductFormCoreActionsContext);
  if (!context) {
    throw internalError(
      'useProductFormCoreActions must be used within a ProductFormCoreProvider'
    );
  }
  return context;
};

export const useProductFormCore = (): ProductFormCoreContextValue => {
  const state = useProductFormCoreState();
  const actions = useProductFormCoreActions();
  return useMemo(() => ({ ...state, ...actions }), [state, actions]);
};

