// ProductFormParameterContext: manages product parameter (spec/attribute)
// state and helpers. Exposes parameter lists per-catalog and normalization
// utilities used by parameter input components.

import { createContext, useContext, useEffect, useMemo, useRef, useState } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';

import type { ProductFormData } from '@/shared/contracts/products/drafts';
import type { ProductParameter } from '@/shared/contracts/products/parameters';
import type { ProductTitleTerm, ProductTitleTermType } from '@/shared/contracts/products/title-terms';
import type { ProductParameterValue, ProductWithImages } from '@/shared/contracts/products/product';
import type { ProductDraft } from '@/shared/contracts/products/drafts';
import { internalError } from '@/shared/errors/app-error';
import {
  normalizeTitleTermName,
  splitStructuredProductName,
} from '@/shared/lib/products/title-terms';
import { decodeSimpleParameterStorageId } from '@/shared/lib/products/utils/parameter-partition';
import {
  normalizeParameterValuesByLanguage,
  resolveStoredParameterValue,
} from '@/shared/lib/products/utils/parameter-values';

import { useParameters, useSimpleParameters, useTitleTerms } from '../hooks/useProductMetadataQueries';
import { mergeParameterDefinitions } from './ProductFormParameterDefinitions';

export interface ProductFormParameterContextType {
  parameters: ProductParameter[];
  parametersLoading: boolean;
  parameterValues: ProductParameterValue[];
  addParameterValue: () => void;
  applyLocalizedParameterValues: (
    updates: Array<{ parameterId: string; languageCode: string; value: string }>
  ) => void;
  updateParameterId: (index: number, parameterId: string) => void;
  updateParameterValue: (index: number, value: string) => void;
  updateParameterValueByLanguage: (index: number, languageCode: string, value: string) => void;
  updateParameterInferenceSkip: (index: number, skip: boolean) => void;
  removeParameterValue: (index: number) => void;
}

export type ProductFormParameterStateContextType = Pick<
  ProductFormParameterContextType,
  'parameters' | 'parametersLoading' | 'parameterValues'
>;

export type ProductFormParameterActionsContextType = Pick<
  ProductFormParameterContextType,
  | 'addParameterValue'
  | 'applyLocalizedParameterValues'
  | 'updateParameterId'
  | 'updateParameterValue'
  | 'updateParameterValueByLanguage'
  | 'updateParameterInferenceSkip'
  | 'removeParameterValue'
>;

export const ProductFormParameterContext = createContext<ProductFormParameterContextType | null>(
  null
);

export const resolvePrimaryParameterValue = (
  valuesByLanguage: Record<string, string>,
  fallbackValue: string = ''
): string => resolveStoredParameterValue(valuesByLanguage, fallbackValue);

const normalizeSourceParameterValues = (
  sourceParams: ProductParameterValue[] | null | undefined
): ProductParameterValue[] => {
  if (!Array.isArray(sourceParams)) return [];

  return sourceParams.map((entry: ProductParameterValue) => {
    const valuesByLanguage = normalizeParameterValuesByLanguage(entry?.valuesByLanguage);
    const directValue = typeof entry?.value === 'string' ? entry.value : '';
    const fallbackValue = resolveStoredParameterValue(valuesByLanguage, directValue);

    return {
      parameterId: decodeSimpleParameterStorageId(
        typeof entry?.parameterId === 'string' ? entry.parameterId : ''
      ),
      value: fallbackValue,
      ...(Object.keys(valuesByLanguage).length > 0 ? { valuesByLanguage } : {}),
      ...(entry?.skipParameterInference === true ? { skipParameterInference: true } : {}),
    };
  });
};

const normalizeEditableParameterValuesByLanguage = (
  input: unknown
): Record<string, string> => {
  if (input === null || input === undefined || typeof input !== 'object' || Array.isArray(input)) {
    return {};
  }

  const entries = Object.entries(input as Record<string, unknown>)
    .map(([languageCode, rawValue]: [string, unknown]): [string, string] | null => {
      const normalizedLanguageCode = languageCode.trim().toLowerCase();
      if (
        normalizedLanguageCode.length === 0 ||
        typeof rawValue !== 'string' ||
        rawValue.length === 0
      ) {
        return null;
      }
      return [normalizedLanguageCode, rawValue];
    })
    .filter((entry: [string, string] | null): entry is [string, string] => entry !== null);

  return Object.fromEntries(entries);
};

const resolveEditableParameterValue = (
  valuesByLanguage: Record<string, string>,
  directValue: string | null | undefined = ''
): string => {
  const normalizedDirectValue = typeof directValue === 'string' ? directValue : '';
  const defaultValue = valuesByLanguage['default'];
  if (typeof defaultValue === 'string' && defaultValue.length > 0) return defaultValue;

  const localizedValues = Object.values(valuesByLanguage);
  if (localizedValues.length === 0) return normalizedDirectValue;

  return normalizedDirectValue.length > 0 && localizedValues.includes(normalizedDirectValue)
    ? normalizedDirectValue
    : '';
};

const resolveNextEditableScalarCandidate = ({
  currentScalarValue,
  previousLocalizedValue,
  hadLocalizedValues,
  nextLocalizedValue,
}: {
  currentScalarValue: string;
  previousLocalizedValue: string;
  hadLocalizedValues: boolean;
  nextLocalizedValue: string;
}): string => {
  if (currentScalarValue.length === 0) return currentScalarValue;
  if (currentScalarValue === previousLocalizedValue) return nextLocalizedValue;
  if (!hadLocalizedValues) return nextLocalizedValue;
  return currentScalarValue;
};

const applyEditableLocalizedValue = (
  currentValues: Record<string, string>,
  languageCode: string,
  nextValue: string
): Record<string, string> => {
  if (nextValue.length > 0) {
    return { ...currentValues, [languageCode]: nextValue };
  }

  return Object.fromEntries(
    Object.entries(currentValues).filter(
      ([entryLanguageCode]: [string, string]): boolean => entryLanguageCode !== languageCode
    )
  );
};

const resolveEditableLocalizedParameterEntry = ({
  current,
  languageCode,
  nextValue,
}: {
  current: ProductParameterValue;
  languageCode: string;
  nextValue: string;
}): ProductParameterValue | null => {
  const normalizedLang = languageCode.trim().toLowerCase();
  if (normalizedLang.length === 0) return null;

  const currentValues = normalizeEditableParameterValuesByLanguage(current.valuesByLanguage);
  const hadLocalizedValues = Object.keys(currentValues).length > 0;
  const previousLocalizedValue = currentValues[normalizedLang] ?? '';
  const nextValues = applyEditableLocalizedValue(currentValues, normalizedLang, nextValue);
  const currentScalarValue = typeof current.value === 'string' ? current.value : '';
  const nextScalarCandidate = resolveNextEditableScalarCandidate({
    currentScalarValue,
    previousLocalizedValue,
    hadLocalizedValues,
    nextLocalizedValue: nextValue,
  });
  const nextPrimaryValue = resolveEditableParameterValue(nextValues, nextScalarCandidate);
  const nextEntry: ProductParameterValue = {
    ...current,
    value: nextPrimaryValue,
  };

  if (Object.keys(nextValues).length > 0) {
    return { ...nextEntry, valuesByLanguage: nextValues };
  }

  return {
    parameterId: nextEntry.parameterId,
    value: nextEntry.value,
    ...(nextEntry.skipParameterInference === true ? { skipParameterInference: true } : {}),
  };
};

const serializeParameterValues = (value: ProductParameterValue[]): string => JSON.stringify(value);

type MergedParameterValuesResult = {
  values: ProductParameterValue[];
  baseIndexByValueIndex: number[];
};

const resolveStructuredLinkedTermValues = (
  value: string
): Record<ProductTitleTermType, string> => {
  const segments = splitStructuredProductName(value);
  return {
    size: segments[1] ?? '',
    material: segments[2] ?? '',
    theme: segments[4] ?? '',
  };
};

const buildTitleTermLookup = (terms: ProductTitleTerm[] | undefined): Map<string, ProductTitleTerm> => {
  const lookup = new Map<string, ProductTitleTerm>();
  (terms ?? []).forEach((term: ProductTitleTerm) => {
    const key = normalizeTitleTermName(term.name_en ?? '');
    if (!key || lookup.has(key)) return;
    lookup.set(key, term);
  });
  return lookup;
};

const resolveLinkedParameterValue = (
  parameterId: string,
  term: ProductTitleTerm
): ProductParameterValue => ({
  parameterId,
  value: term.name_en,
  valuesByLanguage: {
    en: term.name_en,
    pl: term.name_pl || term.name_en,
  },
});

const mergeLinkedParameterValues = ({
  baseValues,
  linkedParameterIds,
  linkedParameters,
  resolvedLinkedValuesById,
}: {
  baseValues: ProductParameterValue[];
  linkedParameterIds: Set<string>;
  linkedParameters: ProductParameter[];
  resolvedLinkedValuesById: Map<string, ProductParameterValue>;
}): MergedParameterValuesResult => {
  const nextValues: ProductParameterValue[] = [];
  const baseIndexByValueIndex: number[] = [];
  const usedLinkedParameterIds = new Set<string>();

  baseValues.forEach((entry: ProductParameterValue, baseIndex: number) => {
    const normalizedParameterId = typeof entry.parameterId === 'string' ? entry.parameterId.trim() : '';
    if (!normalizedParameterId || !linkedParameterIds.has(normalizedParameterId)) {
      nextValues.push(entry);
      baseIndexByValueIndex.push(baseIndex);
      return;
    }

    if (usedLinkedParameterIds.has(normalizedParameterId)) {
      return;
    }

    const linkedValue = resolvedLinkedValuesById.get(normalizedParameterId);
    if (linkedValue) {
      nextValues.push(linkedValue);
      baseIndexByValueIndex.push(baseIndex);
      usedLinkedParameterIds.add(normalizedParameterId);
    }
  });

  linkedParameters.forEach((parameter: ProductParameter) => {
    const linkedValue = resolvedLinkedValuesById.get(parameter.id);
    if (!linkedValue || usedLinkedParameterIds.has(parameter.id)) return;
    nextValues.push(linkedValue);
    baseIndexByValueIndex.push(-1);
    usedLinkedParameterIds.add(parameter.id);
  });

  return {
    values: nextValues,
    baseIndexByValueIndex,
  };
};

export function ProductFormParameterProvider({
  children,
  product,
  draft,
  selectedCatalogIds,
  onInteraction,
}: {
  children: React.ReactNode;
  product?: ProductWithImages;
  draft?: ProductDraft | null;
  selectedCatalogIds: string[];
  onInteraction?: () => void;
}) {
  const primaryCatalogId = selectedCatalogIds[0] || '';
  const formContext = useFormContext<ProductFormData>();
  const parametersQuery = useParameters(primaryCatalogId);
  const simpleParametersQuery = useSimpleParameters(primaryCatalogId);
  const sizeTermsQuery = useTitleTerms(primaryCatalogId, 'size');
  const materialTermsQuery = useTitleTerms(primaryCatalogId, 'material');
  const themeTermsQuery = useTitleTerms(primaryCatalogId, 'theme');
  const sourceParameterValues = useMemo(
    (): ProductParameterValue[] => normalizeSourceParameterValues(product?.parameters ?? draft?.parameters),
    [draft?.parameters, product?.parameters]
  );
  const parameterDefinitions = useMemo(
    (): ProductParameter[] =>
      mergeParameterDefinitions({
        parameters: parametersQuery.data ?? [],
        simpleParameters: simpleParametersQuery.data ?? [],
        parameterValues: sourceParameterValues,
        fallbackCatalogId: primaryCatalogId,
      }),
    [parametersQuery.data, primaryCatalogId, simpleParametersQuery.data, sourceParameterValues]
  );
  const sourceParameterValuesKey = useMemo(
    (): string => serializeParameterValues(sourceParameterValues),
    [sourceParameterValues]
  );

  const [baseParameterValues, setBaseParameterValues] = useState<ProductParameterValue[]>(
    sourceParameterValues
  );
  const adoptedParameterValuesKeyRef = useRef<string>(sourceParameterValuesKey);
  const watchedNameEn = useWatch({
    control: formContext?.control,
    name: 'name_en',
    disabled: !formContext?.control,
  });
  const currentStructuredName =
    (typeof watchedNameEn === 'string' ? watchedNameEn : null) ?? product?.name_en ?? draft?.name_en ?? '';

  useEffect(() => {
    const previousAdoptedKey = adoptedParameterValuesKeyRef.current;
    if (sourceParameterValuesKey === previousAdoptedKey) return;

    setBaseParameterValues((current: ProductParameterValue[]): ProductParameterValue[] => {
      const currentKey = serializeParameterValues(current);
      if (currentKey !== previousAdoptedKey) {
        return current;
      }
      adoptedParameterValuesKeyRef.current = sourceParameterValuesKey;
      return sourceParameterValues;
    });
  }, [sourceParameterValues, sourceParameterValuesKey]);

  const linkedParameters = useMemo(
    (): ProductParameter[] =>
      parameterDefinitions.filter(
        (parameter: ProductParameter): boolean => Boolean(parameter.linkedTitleTermType)
      ),
    [parameterDefinitions]
  );
  const linkedParameterIds = useMemo(
    (): Set<string> => new Set(linkedParameters.map((parameter: ProductParameter) => parameter.id)),
    [linkedParameters]
  );
  const structuredLinkedTermValues = useMemo(
    (): Record<ProductTitleTermType, string> => resolveStructuredLinkedTermValues(currentStructuredName),
    [currentStructuredName]
  );
  const titleTermLookups = useMemo(
    (): Record<ProductTitleTermType, Map<string, ProductTitleTerm>> => ({
      size: buildTitleTermLookup(sizeTermsQuery.data),
      material: buildTitleTermLookup(materialTermsQuery.data),
      theme: buildTitleTermLookup(themeTermsQuery.data),
    }),
    [materialTermsQuery.data, sizeTermsQuery.data, themeTermsQuery.data]
  );
  const resolvedLinkedValuesById = useMemo((): Map<string, ProductParameterValue> => {
    const resolved = new Map<string, ProductParameterValue>();
    linkedParameters.forEach((parameter: ProductParameter) => {
      const linkedType = parameter.linkedTitleTermType;
      if (!linkedType) return;

      const rawSegmentValue = structuredLinkedTermValues[linkedType] ?? '';
      const lookupKey = normalizeTitleTermName(rawSegmentValue);
      if (!lookupKey) return;

      const matchedTerm = titleTermLookups[linkedType].get(lookupKey);
      if (!matchedTerm) return;

      resolved.set(parameter.id, resolveLinkedParameterValue(parameter.id, matchedTerm));
    });
    return resolved;
  }, [linkedParameters, structuredLinkedTermValues, titleTermLookups]);
  const mergedParameterValues = useMemo(
    (): MergedParameterValuesResult =>
      mergeLinkedParameterValues({
        baseValues: baseParameterValues,
        linkedParameterIds,
        linkedParameters,
        resolvedLinkedValuesById,
      }),
    [baseParameterValues, linkedParameterIds, linkedParameters, resolvedLinkedValuesById]
  );
  const parameterValues = mergedParameterValues.values;
  const parameterValueIndexMap = mergedParameterValues.baseIndexByValueIndex;

  const value = useMemo((): ProductFormParameterContextType => {
    const addParameterValue = (): void => {
      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => [
        ...prev,
        { parameterId: '', value: '' },
      ]);
    };

    const applyLocalizedParameterValues = (
      updates: Array<{ parameterId: string; languageCode: string; value: string }>
    ): void => {
      const normalizedUpdates = updates
        .map((entry) => ({
          parameterId: decodeSimpleParameterStorageId(
            typeof entry.parameterId === 'string' ? entry.parameterId : ''
          ),
          languageCode:
            typeof entry.languageCode === 'string' ? entry.languageCode.trim().toLowerCase() : '',
          value: typeof entry.value === 'string' ? entry.value.trim() : '',
        }))
        .filter(
          (entry): entry is { parameterId: string; languageCode: string; value: string } =>
            entry.parameterId.length > 0 && entry.languageCode.length > 0 && entry.value.length > 0
        );
      if (normalizedUpdates.length === 0) return;

      const updateByParameterId = new Map<
        string,
        { parameterId: string; languageCode: string; value: string }
      >();
      normalizedUpdates.forEach((entry) => {
        updateByParameterId.set(entry.parameterId, entry);
      });

      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
        let changed = false;
        const next = prev.map((current: ProductParameterValue): ProductParameterValue => {
          const normalizedParameterId = decodeSimpleParameterStorageId(
            typeof current.parameterId === 'string' ? current.parameterId : ''
          );
          const match = updateByParameterId.get(normalizedParameterId);
          if (!match) return current;

          const currentValues = normalizeParameterValuesByLanguage(current.valuesByLanguage);
          const previousLocalizedValue = currentValues[match.languageCode] ?? '';
          if (previousLocalizedValue === match.value) {
            return current;
          }

          const nextValues = {
            ...currentValues,
            [match.languageCode]: match.value,
          };
          const currentScalarValue = typeof current.value === 'string' ? current.value.trim() : '';
          const nextScalarValue =
            currentScalarValue && currentScalarValue !== previousLocalizedValue
              ? currentScalarValue
              : match.value;

          changed = true;
          return {
            ...current,
            parameterId: normalizedParameterId,
            value: nextScalarValue,
            valuesByLanguage: nextValues,
          };
        });

        return changed ? next : prev;
      });
    };

    const updateParameterId = (index: number, parameterId: string): void => {
      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
        const baseIndex = parameterValueIndexMap[index] ?? index;
        if (baseIndex < 0) return prev;
        const next = [...prev];
        if (!next[baseIndex]) return prev;
        next[baseIndex] = { ...next[baseIndex], parameterId };
        return next;
      });
    };

    const updateParameterValue = (index: number, nextValue: string): void => {
      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
        const baseIndex = parameterValueIndexMap[index] ?? index;
        if (baseIndex < 0) return prev;
        const next = [...prev];
        if (!next[baseIndex]) return prev;
        next[baseIndex] = { ...next[baseIndex], value: nextValue };
        return next;
      });
    };

    const updateParameterValueByLanguage = (
      index: number,
      languageCode: string,
      nextValue: string
    ): void => {
      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
        const baseIndex = parameterValueIndexMap[index] ?? index;
        if (baseIndex < 0) return prev;
        const next = [...prev];
        const current = next[baseIndex];
        if (current === undefined) return prev;
        const nextEntry = resolveEditableLocalizedParameterEntry({
          current,
          languageCode,
          nextValue,
        });
        if (nextEntry === null) return prev;
        next[baseIndex] = nextEntry;
        return next;
      });
    };

    const updateParameterInferenceSkip = (index: number, skip: boolean): void => {
      onInteraction?.();
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
        const baseIndex = parameterValueIndexMap[index] ?? index;
        if (baseIndex < 0) return prev;
        const next = [...prev];
        const current = next[baseIndex];
        if (current === undefined || current.skipParameterInference === skip) return prev;

        if (skip) {
          next[baseIndex] = { ...current, skipParameterInference: true };
        } else {
          const nextEntry = { ...current };
          delete nextEntry.skipParameterInference;
          next[baseIndex] = nextEntry;
        }

        return next;
      });
    };

    const removeParameterValue = (index: number): void => {
      onInteraction?.();
      const baseIndex = parameterValueIndexMap[index] ?? index;
      if (baseIndex < 0) return;
      setBaseParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] =>
        prev.filter((_: ProductParameterValue, i: number): boolean => i !== baseIndex)
      );
    };

    return {
      parameters: parameterDefinitions,
      parametersLoading: parametersQuery.isLoading || simpleParametersQuery.isLoading,
      parameterValues,
      addParameterValue,
      applyLocalizedParameterValues,
      updateParameterId,
      updateParameterValue,
      updateParameterValueByLanguage,
      updateParameterInferenceSkip,
      removeParameterValue,
    };
  }, [
    onInteraction,
    parameterValueIndexMap,
    parameterValues,
    parameterDefinitions,
    parametersQuery.isLoading,
    simpleParametersQuery.isLoading,
  ]);

  return (
    <ProductFormParameterContext.Provider value={value}>
      {children}
    </ProductFormParameterContext.Provider>
  );
}

const useRequiredProductFormParameterContext = (): ProductFormParameterContextType => {
  const context = useContext(ProductFormParameterContext);
  if (!context) {
    throw internalError(
      'useProductFormParameters must be used within a ProductFormParameterProvider'
    );
  }
  return context;
};

export const useProductFormParameterState = (): ProductFormParameterStateContextType => {
  const { parameters, parametersLoading, parameterValues } = useRequiredProductFormParameterContext();
  return {
    parameters,
    parametersLoading,
    parameterValues,
  };
};

export const useProductFormParameterActions = (): ProductFormParameterActionsContextType => {
  const {
    addParameterValue,
    applyLocalizedParameterValues,
    updateParameterId,
    updateParameterValue,
    updateParameterValueByLanguage,
    removeParameterValue,
  } = useRequiredProductFormParameterContext();
  return {
    addParameterValue,
    applyLocalizedParameterValues,
    updateParameterId,
    updateParameterValue,
    updateParameterValueByLanguage,
    removeParameterValue,
  };
};

export const useProductFormParameters = (): ProductFormParameterContextType =>
  useRequiredProductFormParameterContext();

'use client';

// ProductStudioContext: manages state related to Image Studio integrations and
// studio workflows for a product (selected images, variant mappings, run
// status). Keeps studio state separate from core form state to simplify
// lifecycle and caching semantics.
'use no memo';

import { useRouter } from 'nextjs-toploader/app';
import React, { createContext, useContext, useState, useMemo, useCallback, useEffect, startTransition } from 'react';

import { useStudioProjects } from '@/features/ai/public';
import { useProductSettings } from '@/features/products/hooks/useProductSettings';
import type { ImageStudioSlotDto as ImageStudioSlotRecord } from '@/shared/contracts/image-studio';
import { productStudioAuditResponseSchema, productStudioLinkResponseSchema, productStudioVariantsResponseSchema } from '@/shared/contracts/products/studio';
import { internalError } from '@/shared/errors/app-error';
import {
  useOptionalContextRegistryPageEnvelope,
  useRegisterContextRegistryPageSource,
} from '@/shared/lib/ai-context-registry/page-context';
import { api } from '@/shared/lib/api-client';
import { useToast } from '@/shared/ui/toast';

import { resolveProductImageUrl } from '@/shared/utils/image-routing';

import { useProductFormCore } from './ProductFormCoreContext';
import { useProductFormImages } from './ProductFormImageContext';
import { useProductFormStudio } from './ProductFormStudioContext';
import { useProductStudioDerivedState } from './ProductStudioContext.derived';
import {
  useSendToStudioMutation,
  useAcceptVariantMutation,
  useRotateImageSlotMutation,
} from '../hooks/useProductStudioMutations';

import type {
  ProductImageSlotPreview,
  ProductStudioAuditEntry,
  ProductStudioActionsContextValue,
  ProductStudioContextValue,
  ProductStudioRunStatus,
  ProductStudioStateContextValue,
  ProductStudioVariantsResponse,
} from './ProductStudioContext.types';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

export type {
  ProductImageSlotPreview,
  ProductStudioAuditEntry,
  ProductStudioActionsContextValue,
  ProductStudioContextValue,
  ProductStudioRunStatus,
  ProductStudioStateContextValue,
  ProductStudioVariantsResponse,
} from './ProductStudioContext.types';

const ProductStudioStateContext = createContext<ProductStudioStateContextValue | null>(null);
const ProductStudioActionsContext = createContext<ProductStudioActionsContextValue | null>(null);

const STUDIO_PROJECT_NOT_CONNECTED = '__product_studio_not_connected__';
const PRODUCT_STUDIO_RUN_STATUSES: ProductStudioRunStatus[] = [
  'queued',
  'running',
  'completed',
  'failed',
  'cancelled',
];

const isProductStudioRunStatus = (value: unknown): value is ProductStudioRunStatus =>
  typeof value === 'string' &&
  PRODUCT_STUDIO_RUN_STATUSES.includes(value as ProductStudioRunStatus);

export function ProductStudioProvider({
  children,
}: {
  children: React.ReactNode;
}): React.JSX.Element {
  const router = useRouter();
  const { studioProjectId, setStudioProjectId, studioConfigLoading, studioConfigSaving } =
    useProductFormStudio();

  const core = useProductFormCore();
  const product = core.product;

  const images = useProductFormImages();
  const imageSlots = images.imageSlots;
  const refreshImagesFromProduct = images.refreshImagesFromProduct;

  const studioProjectsQuery = useStudioProjects();
  const studioProjectIds = useMemo(
    () => (studioProjectsQuery.data ?? []).map((p) => p.id.trim()).filter((id) => id.length > 0),
    [studioProjectsQuery.data]
  );

  const studioProjectOptions = useMemo(
    () => [
      { value: STUDIO_PROJECT_NOT_CONNECTED, label: 'Not Connected' },
      ...studioProjectIds.map((id) => ({ value: id, label: id })),
    ],
    [studioProjectIds]
  );

  const { toast } = useToast();
  const { defaultProjectId, getImageExternalBaseUrl } = useProductSettings();
  const contextRegistry = useOptionalContextRegistryPageEnvelope();
  const productImagesExternalBaseUrl = getImageExternalBaseUrl();

  const sendToStudioMutation = useSendToStudioMutation();
  const acceptVariantMutation = useAcceptVariantMutation();
  const rotateImageSlotMutation = useRotateImageSlotMutation();

  const configuredDefaultStudioProjectId = defaultProjectId;

  const [selectedImageIndex, setSelectedImageIndex] = useState<number | null>(null);
  const [variantsData, setVariantsData] = useState<ProductStudioVariantsResponse | null>(null);
  const [variantsLoading, setVariantsLoading] = useState(false);
  const [studioActionError, setStudioActionError] = useState<string | null>(null);
  const [selectedVariantSlotId, setSelectedVariantSlotId] = useState<string | null>(null);
  const [openingInImageStudio, setOpeningInImageStudio] = useState(false);
  const [deletingVariantId, setDeletingVariantId] = useState<string | null>(null);
  const [auditEntries, setAuditEntries] = useState<ProductStudioAuditEntry[]>([]);
  const [auditLoading, setAuditLoading] = useState(false);
  const [auditError, setAuditError] = useState<string | null>(null);
  const [activeRunId, setActiveRunId] = useState<string | null>(null);
  const [runStatus, setRunStatus] = useState<ProductStudioRunStatus | null>(null);
  const [activeRunBaselineVariantIds, setActiveRunBaselineVariantIds] = useState<string[]>([]);
  const [pendingExpectedOutputs, setPendingExpectedOutputs] = useState<number>(0);

  const imageSlotPreviews = useMemo((): ProductImageSlotPreview[] => {
    return (imageSlots || [])
      .map((slot, index): ProductImageSlotPreview | null => {
        if (!slot) return null;
        const src =
          slot.type === 'file'
            ? slot.previewUrl
            : (resolveProductImageUrl(slot.data.filepath, productImagesExternalBaseUrl) ??
              slot.previewUrl);
        if (!src) return null;
        return { index, label: `Slot ${index + 1}`, src };
      })
      .filter((entry): entry is ProductImageSlotPreview => Boolean(entry));
  }, [imageSlots, productImagesExternalBaseUrl]);

  // Initial selection
  useEffect(() => {
    if (imageSlotPreviews.length === 0) {
      setSelectedImageIndex(null);
      return;
    }
    if (
      selectedImageIndex !== null &&
      imageSlotPreviews.some((p) => p.index === selectedImageIndex)
    ) {
      return;
    }
    setSelectedImageIndex(imageSlotPreviews[0]?.index ?? null);
  }, [imageSlotPreviews, selectedImageIndex]);

  // Handle defaults and hydration
  useEffect(() => {
    if (studioProjectsQuery.isLoading || studioConfigLoading || studioConfigSaving) return;
    const current = studioProjectId?.trim() ?? '';
    if (current.length > 0 && studioProjectIds.includes(current)) return;
    const fallback =
      configuredDefaultStudioProjectId.length > 0 &&
      studioProjectIds.includes(configuredDefaultStudioProjectId)
        ? configuredDefaultStudioProjectId
        : null;
    if (fallback === current) return;
    setStudioProjectId(fallback);
  }, [
    configuredDefaultStudioProjectId,
    studioConfigLoading,
    studioConfigSaving,
    studioProjectId,
    studioProjectIds,
    studioProjectsQuery.isLoading,
    setStudioProjectId,
  ]);

  const refreshVariants = useCallback(async (): Promise<ProductStudioVariantsResponse | null> => {
    if (!product?.id || !studioProjectId || selectedImageIndex === null) {
      setVariantsData(null);
      setSelectedVariantSlotId(null);
      return null;
    }
    setVariantsLoading(true);
    setStudioActionError(null);
    try {
      const response = productStudioVariantsResponseSchema.parse(
        await api.get<unknown>(
          `/api/v2/products/${encodeURIComponent(product.id)}/studio/variants`,
          {
            params: { imageSlotIndex: selectedImageIndex, projectId: studioProjectId },
            cache: 'no-store',
          }
        )
      );
      setVariantsData(response);
      setSelectedVariantSlotId((current) => {
        if (current && response.variants.some((s) => s.id === current)) return current;
        return response.variants[0]?.id ?? null;
      });
      return response;
    } catch (error) {
      logClientError(error);
      setStudioActionError(
        error instanceof Error ? error.message : 'Failed to load Studio variants.'
      );
      return null;
    } finally {
      setVariantsLoading(false);
    }
  }, [product?.id, selectedImageIndex, studioProjectId]);

  useEffect(() => {
    void refreshVariants();
  }, [refreshVariants]);

  const refreshAudit = useCallback(async (): Promise<void> => {
    if (!product?.id || !studioProjectId || selectedImageIndex === null) {
      setAuditEntries([]);
      setAuditError(null);
      return;
    }
    setAuditLoading(true);
    setAuditError(null);
    try {
      const response = productStudioAuditResponseSchema.parse(
        await api.get<unknown>(`/api/v2/products/${encodeURIComponent(product.id)}/studio/audit`, {
          params: { imageSlotIndex: selectedImageIndex, limit: 40 },
          cache: 'no-store',
          logError: false,
        })
      );
      setAuditEntries(Array.isArray(response.entries) ? response.entries : []);
    } catch (error) {
      logClientError(error);
      setAuditError(error instanceof Error ? error.message : 'Failed to load history.');
    } finally {
      setAuditLoading(false);
    }
  }, [product?.id, selectedImageIndex, studioProjectId]);

  useEffect(() => {
    void refreshAudit();
  }, [refreshAudit]);

  const handleSendToStudio = async () => {
    if (!product?.id || !studioProjectId || selectedImageIndex === null) return;
    setStudioActionError(null);
    const baselineIds = (variantsData?.variants ?? [])
      .map((s) => s.id)
      .filter((id): id is string => Boolean(id));
    try {
      const result = await sendToStudioMutation.mutateAsync({
        productId: product.id,
        imageSlotIndex: selectedImageIndex,
        projectId: studioProjectId,
        ...(contextRegistry ? { contextRegistry } : {}),
      });
      setActiveRunId(result.runId);
      setActiveRunBaselineVariantIds(baselineIds);
      setRunStatus(isProductStudioRunStatus(result.runStatus) ? result.runStatus : null);
      setPendingExpectedOutputs(Math.max(0, Math.floor(result.expectedOutputs ?? 0)));
      toast('Image sent to Studio.', { variant: 'success' });
      await refreshVariants();
      await refreshAudit();
    } catch (error) {
      logClientError(error);
      setStudioActionError(error instanceof Error ? error.message : 'Failed to send.');
    }
  };

  const handleOpenInImageStudio = async () => {
    if (!product?.id || !studioProjectId || selectedImageIndex === null) return;
    setOpeningInImageStudio(true);
    try {
      const response = productStudioLinkResponseSchema.parse(
        await api.post<unknown>(`/api/v2/products/${encodeURIComponent(product.id)}/studio/link`, {
          imageSlotIndex: selectedImageIndex,
          projectId: studioProjectId,
        })
      );
      const sourceSlotId = response.sourceSlot?.id;
      if (!sourceSlotId) throw internalError('Source slot not found.');
      startTransition(() => { router.push(`/admin/image-studio?projectId=${response.projectId}&slotId=${sourceSlotId}`); });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to open.', { variant: 'error' });
    } finally {
      setOpeningInImageStudio(false);
    }
  };

  const handleAcceptVariant = async () => {
    if (!product?.id || !studioProjectId || !selectedVariantSlotId) return;
    try {
      const response = await acceptVariantMutation.mutateAsync({
        productId: product.id,
        imageSlotIndex: selectedImageIndex!,
        generationSlotId: selectedVariantSlotId,
        projectId: studioProjectId,
      });
      refreshImagesFromProduct(response.product);
      toast('Variant accepted.', { variant: 'success' });
      await refreshVariants();
      await refreshAudit();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to accept.', { variant: 'error' });
    }
  };

  const handleDeleteVariant = async (slot: ImageStudioSlotRecord) => {
    if (!studioProjectId || !slot.id) return;
    setDeletingVariantId(slot.id);
    try {
      await api.post(
        `/api/image-studio/projects/${encodeURIComponent(studioProjectId)}/variants/delete`,
        {
          slotId: slot.id,
          sourceSlotId: variantsData?.sourceSlotId,
        }
      );
      toast('Variant deleted.', { variant: 'success' });
      await refreshVariants();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to delete.', { variant: 'error' });
    } finally {
      setDeletingVariantId(null);
    }
  };

  const handleRotateImageSlot = async (direction: 'left' | 'right') => {
    if (!product?.id || selectedImageIndex === null) return;
    try {
      const response = await rotateImageSlotMutation.mutateAsync({
        productId: product.id,
        imageSlotIndex: selectedImageIndex,
        direction,
      });
      refreshImagesFromProduct(response.product);
      await refreshVariants();
      toast('Image rotated.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to rotate.', { variant: 'error' });
    }
  };

  const {
    variants,
    selectedVariant,
    selectedSourcePreview,
    sourceImageSrc,
    variantImageSrc,
    canCompareWithSource,
    sequenceReadinessMessage,
    blockSendForSequenceReadiness,
    pendingVariantPlaceholderCount,
    registrySource,
  } = useProductStudioDerivedState({
    product,
    studioProjectId,
    selectedImageIndex,
    imageSlotPreviews,
    productImagesExternalBaseUrl,
    selectedVariantSlotId,
    variantsData,
    activeRunId,
    runStatus,
    activeRunBaselineVariantIds,
    pendingExpectedOutputs,
    auditEntries,
  });

  useRegisterContextRegistryPageSource('product-studio-workspace-state', registrySource);

  const stateValue = useMemo(
    (): ProductStudioStateContextValue => ({
      studioProjectId,
      studioProjectOptions,
      isStudioLoading: studioProjectsQuery.isLoading || studioConfigLoading,
      imageSlotPreviews,
      selectedImageIndex,
      selectedSourcePreview,
      variants,
      variantsLoading,
      selectedVariantSlotId,
      selectedVariant,
      pendingVariantPlaceholderCount,
      sourceImageSrc,
      variantImageSrc,
      canCompareWithSource,
      variantsData,
      sequenceReadinessMessage,
      blockSendForSequenceReadiness,
      auditEntries,
      auditLoading,
      auditError,
      activeRunId,
      runStatus,
      sending: sendToStudioMutation.isPending,
      accepting: acceptVariantMutation.isPending,
      openingInImageStudio,
      rotatingDirection: rotateImageSlotMutation.isPending
        ? (rotateImageSlotMutation.variables?.direction ?? null)
        : null,
      deletingVariantId,
      studioActionError,
    }),
    [
      acceptVariantMutation.isPending,
      activeRunId,
      auditEntries,
      auditError,
      auditLoading,
      blockSendForSequenceReadiness,
      canCompareWithSource,
      deletingVariantId,
      imageSlotPreviews,
      openingInImageStudio,
      pendingVariantPlaceholderCount,
      rotateImageSlotMutation.isPending,
      rotateImageSlotMutation.variables?.direction,
      runStatus,
      selectedImageIndex,
      selectedSourcePreview,
      selectedVariant,
      selectedVariantSlotId,
      sendToStudioMutation.isPending,
      sequenceReadinessMessage,
      sourceImageSrc,
      studioActionError,
      studioConfigLoading,
      studioProjectId,
      studioProjectOptions,
      studioProjectsQuery.isLoading,
      variantImageSrc,
      variants,
      variantsData,
      variantsLoading,
    ]
  );
  const actionsValue = useMemo(
    (): ProductStudioActionsContextValue => ({
      setStudioProjectId,
      setSelectedImageIndex,
      setSelectedVariantSlotId,
      refreshAudit,
      handleSendToStudio,
      handleOpenInImageStudio,
      handleAcceptVariant,
      handleDeleteVariant,
      handleRotateImageSlot,
      refreshVariants,
    }),
    [
      handleAcceptVariant,
      handleDeleteVariant,
      handleOpenInImageStudio,
      handleRotateImageSlot,
      handleSendToStudio,
      refreshAudit,
      refreshVariants,
      setStudioProjectId,
    ]
  );

  return (
    <ProductStudioActionsContext.Provider value={actionsValue}>
      <ProductStudioStateContext.Provider value={stateValue}>
        {children}
      </ProductStudioStateContext.Provider>
    </ProductStudioActionsContext.Provider>
  );
}

export function useProductStudioState(): ProductStudioStateContextValue {
  const context = useContext(ProductStudioStateContext);
  if (!context) {
    throw internalError('useProductStudioState must be used within ProductStudioProvider');
  }
  return context;
}

export function useProductStudioActions(): ProductStudioActionsContextValue {
  const context = useContext(ProductStudioActionsContext);
  if (!context) {
    throw internalError('useProductStudioActions must be used within ProductStudioProvider');
  }
  return context;
}

export function useProductStudioContext(): ProductStudioContextValue {
  const state = useProductStudioState();
  const actions = useProductStudioActions();
  return useMemo(() => ({ ...state, ...actions }), [state, actions]);
}

'use client';
'use no memo';

import { useQueryClient } from '@tanstack/react-query';
import { useCallback, useEffect, useRef, useState, useSyncExternalStore } from 'react';

// useProductEditHydration: Manages opening the live product editor and
// hydrating product detail with a non-blocking prefetch-first strategy.
// Key responsibilities:
// - Debounced prefetch of product detail + ProductForm JS chunk to keep the
//   editor responsive while data downloads in the background.
// - Freshness heuristics (PRODUCT_DETAIL_CACHE_FRESH_MS, PREFETCH_STALE_MS)
//   decide between instant cached rendering and background refetching.
// - Carefully decides when to adopt incoming server updates vs preserving
//   a user's in-progress edits using timestamp and generated-text checks.
// - Gracefully handles missing products (cleans URL, notifies user, refreshes
//   list) and exposes a prefetch helper used by hover/prefetch UIs.
//
// Keep the 'use no memo' directive: it serves as a runtime development hint
// to avoid unstable dev-hook layouts in some compilers during Fast Refresh.

import { preloadProductFormChunk } from '@/features/products/components/product-form-preload';
import {
  isEditingProductHydrated,
  markEditingProductHydrated,
} from '@/features/products/hooks/editingProductHydration';
import {
  EDIT_PRODUCT_DETAIL_STALE_TIME_MS,
  hasIncomingProductDetailGeneratedTextChanges,
  isIncomingProductDetailNewer,
  isIncomingProductDetailSameRevision,
} from '@/features/products/hooks/product-list-state-utils';
import {
  getProductDetailEditQueryKey,
  getProductDetailQueryKey,
} from '@/features/products/hooks/productCache';
import type { ProductWithImages } from '@/shared/contracts/products/product';
import { ApiError, api } from '@/shared/lib/api-client';
import {
  createSingleQueryV2,
  prefetchQueryV2,
  fetchQueryV2,
} from '@/shared/lib/query-factories-v2';
import { normalizeQueryKey } from '@/shared/lib/query-key-utils';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { useToast } from '@/shared/ui/toast';

const subscribeToSearchParams = (callback: () => void): (() => void) => {
  window.addEventListener('popstate', callback);
  return () => window.removeEventListener('popstate', callback);
};
const getSearchSnapshot = (): string =>
  typeof window !== 'undefined' ? (new URLSearchParams(window.location.search).get('openProductId')?.trim() ?? '') : '';
const getSearchServerSnapshot = (): string => '';

const PRODUCT_DETAIL_TIMEOUT_MS = 60_000;
const PRODUCT_DETAIL_PREFETCH_DEBOUNCE_MS = 120;
const PRODUCT_DETAIL_PREFETCH_STALE_MS = 20_000;
// If cached data is younger than this, use it instantly and background-refetch instead of blocking.
const PRODUCT_DETAIL_CACHE_FRESH_MS = 10_000;

type ProductListCacheEntry =
  | ProductWithImages[]
  | { items?: ProductWithImages[] | null; products?: ProductWithImages[] | null }
  | null
  | undefined;

const normalizeSku = (value: unknown): string =>
  typeof value === 'string' ? value.trim().toUpperCase() : '';

export const resolveExactProductIdBySku = (
  products: ProductWithImages[],
  sku: string | null | undefined
): string | null => {
  const normalizedSku = normalizeSku(sku);
  if (!normalizedSku) return null;

  const matches = products.filter(
    (product: ProductWithImages): boolean => normalizeSku(product.sku) === normalizedSku
  );

  return matches.length === 1 ? matches[0]?.id ?? null : null;
};

export const findCachedProductSnapshotById = (
  cacheEntries: ProductListCacheEntry[],
  productId: string | null | undefined
): ProductWithImages | null => {
  const normalizedProductId = typeof productId === 'string' ? productId.trim() : '';
  if (!normalizedProductId) return null;

  for (const entry of cacheEntries) {
    const candidates = Array.isArray(entry)
      ? entry
      : Array.isArray(entry?.items)
        ? entry.items
        : Array.isArray(entry?.products)
          ? entry.products
          : [];
    const match =
      candidates.find((product: ProductWithImages) => product.id === normalizedProductId) ?? null;
    if (match) return match;
  }

  return null;
};

export const shouldEnableLiveEditProductDetailQuery = ({
  editingProduct,
  isEditHydrating,
}: {
  editingProduct: ProductWithImages | null;
  isEditHydrating: boolean;
}): boolean => Boolean(editingProduct?.id && !isEditHydrating && isEditingProductHydrated(editingProduct));

export const shouldAdoptIncomingEditProductDetail = (input: {
  currentProduct: ProductWithImages;
  incomingProduct: ProductWithImages;
  isEditHydrating: boolean;
}): boolean => {
  const { currentProduct, incomingProduct, isEditHydrating } = input;
  if (incomingProduct.id !== currentProduct.id) return false;
  const hydrated = isEditingProductHydrated(currentProduct);
  if (!hydrated && !isEditHydrating) return false;
  if (
    hydrated &&
    !isIncomingProductDetailNewer(incomingProduct, currentProduct) &&
    !(
      isIncomingProductDetailSameRevision(incomingProduct, currentProduct) &&
      hasIncomingProductDetailGeneratedTextChanges(incomingProduct, currentProduct)
    )
  ) {
    return false;
  }
  return true;
};

export function useProductEditHydration({
  editingProduct,
  setEditingProduct,
  setActionError,
  setRefreshTrigger,
  clearProductEditorQueryParams,
}: {
  editingProduct: ProductWithImages | null;
  setEditingProduct: (product: ProductWithImages | null) => void;
  setActionError: (error: string | null) => void;
  setRefreshTrigger: React.Dispatch<React.SetStateAction<number>>;
  clearProductEditorQueryParams: () => void;
}) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const openProductIdFromQuery = useSyncExternalStore(subscribeToSearchParams, getSearchSnapshot, getSearchServerSnapshot);

  const [isEditHydrating, setIsEditHydrating] = useState(false);
  const editOpenRequestTokenRef = useRef(0);
  const openingProductFromQueryRef = useRef<string | null>(null);
  const prefetchTimerRef = useRef<number | null>(null);
  const pendingPrefetchProductIdRef = useRef<string | null>(null);

  const editingProductDetailQuery = createSingleQueryV2<ProductWithImages>({
    id: editingProduct?.id,
    queryKey: (id) =>
      id !== 'none'
        ? QUERY_KEYS.products.detailEdit(id)
        : [...QUERY_KEYS.products.details(), 'edit', 'inactive'],
    queryFn: () =>
      api.get<ProductWithImages>(`/api/v2/products/${editingProduct?.id}`, {
        timeout: PRODUCT_DETAIL_TIMEOUT_MS,
      }),
    staleTime: EDIT_PRODUCT_DETAIL_STALE_TIME_MS,
    refetchOnMount: false,
    refetchInterval: false,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    meta: {
      source: 'products.hooks.useProductEditHydration.editingProductDetail',
      operation: 'detail',
      resource: 'products.detailEdit',
      domain: 'products',
      tags: ['products', 'detail', 'edit', 'editing'],
      description: 'Loads products detail for the live editor.'},
  });

  const handleMissingEditProduct = useCallback(
    (message: string) => {
      openingProductFromQueryRef.current = null;
      setEditingProduct(null);
      setIsEditHydrating(false);
      clearProductEditorQueryParams();
      toast(message, { variant: 'warning' });
      setRefreshTrigger((prev: number) => prev + 1);
    },
    [clearProductEditorQueryParams, setEditingProduct, setRefreshTrigger, toast]
  );

  const prefetchProductDetail = useCallback(
    (productId: string) => {
      const normalizedProductId = productId.trim();
      if (!normalizedProductId) return;

      // Start downloading the ProductForm JS chunk in parallel with data.
      preloadProductFormChunk();

      pendingPrefetchProductIdRef.current = normalizedProductId;

      if (prefetchTimerRef.current !== null) {
        window.clearTimeout(prefetchTimerRef.current);
      }

      prefetchTimerRef.current = window.setTimeout(() => {
        prefetchTimerRef.current = null;
        const queuedProductId = pendingPrefetchProductIdRef.current;
        if (!queuedProductId) return;

        const queryKey = normalizeQueryKey(getProductDetailEditQueryKey(queuedProductId));
        const existingState = queryClient.getQueryState<ProductWithImages>(queryKey);
        if (
          typeof existingState?.dataUpdatedAt === 'number' &&
          Date.now() - existingState.dataUpdatedAt < PRODUCT_DETAIL_PREFETCH_STALE_MS
        ) {
          return;
        }

        void prefetchQueryV2(queryClient, {
          queryKey,
          queryFn: ({ signal }) =>
            api.get<ProductWithImages>(`/api/v2/products/${encodeURIComponent(queuedProductId)}`, {
              signal,
              cache: 'no-store',
              logError: false,
              timeout: PRODUCT_DETAIL_TIMEOUT_MS,
            }),
          staleTime: PRODUCT_DETAIL_PREFETCH_STALE_MS,
          logError: false,
          meta: {
            source: 'products.hooks.useProductEditHydration.prefetchProductDetail',
            operation: 'detail',
            resource: 'products.detailEdit',
            domain: 'products',
            queryKey,
            tags: ['products', 'detail', 'edit', 'prefetch'],
            description: 'Prefetches products detail for the live editor.'},
        })();
      }, PRODUCT_DETAIL_PREFETCH_DEBOUNCE_MS);
    },
    [queryClient]
  );

  useEffect(() => {
    return () => {
      if (prefetchTimerRef.current !== null) {
        window.clearTimeout(prefetchTimerRef.current);
      }
    };
  }, []);

  const handleOpenEditModal = useCallback(
    (product: ProductWithImages) => {
      setActionError(null);
      editOpenRequestTokenRef.current += 1;
      const requestToken = editOpenRequestTokenRef.current;

      const detailQueryKey = normalizeQueryKey(getProductDetailQueryKey(product.id));
      const detailEditQueryKey = normalizeQueryKey(getProductDetailEditQueryKey(product.id));

      // Prefer the editor cache, but still reuse a recent canonical detail prefetch
      // while seeding detailEdit so the live editor sticks to one query key.
      const detailEditCachedState = queryClient.getQueryState<ProductWithImages>(detailEditQueryKey);
      const detailEditCacheAge =
        typeof detailEditCachedState?.dataUpdatedAt === 'number'
          ? Date.now() - detailEditCachedState.dataUpdatedAt
          : Infinity;
      const detailEditCachedData =
        detailEditCacheAge < PRODUCT_DETAIL_CACHE_FRESH_MS
          ? queryClient.getQueryData<ProductWithImages>(detailEditQueryKey)
          : undefined;
      const detailCachedState = queryClient.getQueryState<ProductWithImages>(detailQueryKey);
      const detailCacheAge =
        typeof detailCachedState?.dataUpdatedAt === 'number'
          ? Date.now() - detailCachedState.dataUpdatedAt
          : Infinity;
      const detailCachedData =
        detailCacheAge < PRODUCT_DETAIL_CACHE_FRESH_MS
          ? queryClient.getQueryData<ProductWithImages>(detailQueryKey)
          : undefined;
      const cachedData = detailEditCachedData ?? detailCachedData;

      if (cachedData) {
        queryClient.setQueryData(detailEditQueryKey, cachedData);

        // Open immediately with cached data, then background-refetch for freshness.
        setEditingProduct(markEditingProductHydrated(cachedData));
        setIsEditHydrating(false);
        void fetchQueryV2(queryClient, {
          queryKey: detailEditQueryKey,
          queryFn: ({ signal }) =>
            api.get<ProductWithImages>(`/api/v2/products/${encodeURIComponent(product.id)}?fresh=1`, {
              signal,
              cache: 'no-store',
              logError: false,
              timeout: PRODUCT_DETAIL_TIMEOUT_MS,
            }),
          staleTime: 0,
          logError: false,
          meta: {
            source: 'products.hooks.useProductEditHydration.handleOpenEditModal.cachedRefresh',
            operation: 'detail',
            resource: 'products.detailEdit',
            domain: 'products',
            queryKey: detailEditQueryKey,
            tags: ['products', 'detail', 'edit', 'fetch', 'cached-refresh'],
            description: 'Refreshes cached products edit detail after opening the editor.',
          },
        })()
          .then((freshProduct: ProductWithImages) => {
            queryClient.setQueryData(detailQueryKey, freshProduct);
          })
          .catch((error: unknown) => {
            if (editOpenRequestTokenRef.current !== requestToken) return;
            if (error instanceof ApiError && error.status === 404) {
              handleMissingEditProduct('This product no longer exists. Refreshing the list.');
              return;
            }
            toast(error instanceof Error ? error.message : 'Failed to open product editor.', {
              variant: 'error',
            });
          });
        return;
      }

      setEditingProduct(product);
      setIsEditHydrating(true);

      void fetchQueryV2(queryClient, {
        queryKey: detailEditQueryKey,
        queryFn: ({ signal }) =>
          api.get<ProductWithImages>(`/api/v2/products/${encodeURIComponent(product.id)}?fresh=1`, {
            signal,
            cache: 'no-store',
            logError: false,
            timeout: PRODUCT_DETAIL_TIMEOUT_MS,
          }),
        staleTime: 0,
        logError: false,
        meta: {
          source: 'products.hooks.useProductEditHydration.handleOpenEditModal',
          operation: 'detail',
          resource: 'products.detailEdit',
          domain: 'products',
          queryKey: detailEditQueryKey,
          tags: ['products', 'detail', 'edit', 'fetch'],
          description: 'Loads products edit detail.'},
      })()
        .then((freshProduct: ProductWithImages) => {
          queryClient.setQueryData(detailQueryKey, freshProduct);
          if (editOpenRequestTokenRef.current !== requestToken) return;
          setEditingProduct(markEditingProductHydrated(freshProduct));
          setIsEditHydrating(false);
        })
        .catch((error: unknown) => {
          if (editOpenRequestTokenRef.current !== requestToken) return;
          if (error instanceof ApiError && error.status === 404) {
            handleMissingEditProduct('This product no longer exists. Refreshing the list.');
            return;
          }
          setIsEditHydrating(false);
          toast(error instanceof Error ? error.message : 'Failed to open product editor.', {
            variant: 'error',
          });
        });
    },
    [handleMissingEditProduct, queryClient, setActionError, setEditingProduct, toast]
  );

  const handleCloseEdit = useCallback(() => {
    editOpenRequestTokenRef.current += 1;
    openingProductFromQueryRef.current = null;
    setEditingProduct(null);
    setIsEditHydrating(false);
    clearProductEditorQueryParams();
  }, [clearProductEditorQueryParams, setEditingProduct]);

  useEffect(() => {
    if (!editingProduct?.id) return;
    const fresh = editingProductDetailQuery.data;
    if (!fresh) return;
    if (
      !shouldAdoptIncomingEditProductDetail({
        currentProduct: editingProduct,
        incomingProduct: fresh,
        isEditHydrating,
      })
    ) {
      return;
    }
    setEditingProduct(markEditingProductHydrated(fresh));
  }, [editingProduct, editingProductDetailQuery.data, isEditHydrating, setEditingProduct]);

  useEffect(() => {
    if (editingProduct?.id) return;
    editOpenRequestTokenRef.current += 1;
    setIsEditHydrating(false);
  }, [editingProduct?.id]);

  useEffect(() => {
    if (!openProductIdFromQuery) {
      if (openingProductFromQueryRef.current !== null) {
        openingProductFromQueryRef.current = null;
        editOpenRequestTokenRef.current += 1;
        setIsEditHydrating(false);
      }
      return;
    }
    if (editingProduct?.id === openProductIdFromQuery) return;
    if (openingProductFromQueryRef.current === openProductIdFromQuery) return;
    openingProductFromQueryRef.current = openProductIdFromQuery;
    editOpenRequestTokenRef.current += 1;
    const requestToken = editOpenRequestTokenRef.current;

    setActionError(null);
    setEditingProduct(null);
    setIsEditHydrating(true);

    const detailQueryKey = normalizeQueryKey(getProductDetailQueryKey(openProductIdFromQuery));
    const detailEditQueryKey = normalizeQueryKey(getProductDetailEditQueryKey(openProductIdFromQuery));
    void fetchQueryV2(queryClient, {
      queryKey: detailEditQueryKey,
      queryFn: ({ signal }) =>
        api.get<ProductWithImages>(
          `/api/v2/products/${encodeURIComponent(openProductIdFromQuery)}?fresh=1`,
          {
            signal,
            cache: 'no-store',
            logError: false,
            timeout: PRODUCT_DETAIL_TIMEOUT_MS,
          }
        ),
      staleTime: 0,
      logError: false,
      meta: {
        source: 'products.hooks.useProductEditHydration.openingProductFromQuery',
        operation: 'detail',
        resource: 'products.detailEdit',
        domain: 'products',
        queryKey: detailEditQueryKey,
        tags: ['products', 'detail', 'edit', 'fetch'],
        description: 'Loads products edit detail.'},
    })()
      .then((freshProduct: ProductWithImages) => {
        queryClient.setQueryData(detailQueryKey, freshProduct);
        if (editOpenRequestTokenRef.current !== requestToken) return;
        setEditingProduct(markEditingProductHydrated(freshProduct));
        setIsEditHydrating(false);
      })
      .catch((error: unknown) => {
        if (editOpenRequestTokenRef.current !== requestToken) return;
        if (error instanceof ApiError && error.status === 404) {
          handleMissingEditProduct('This product no longer exists. Refreshing the list.');
          return;
        }
        setIsEditHydrating(false);
        toast(error instanceof Error ? error.message : 'Failed to open product editor.', {
          variant: 'error',
        });
      });
  }, [
    editingProduct?.id,
    handleMissingEditProduct,
    openProductIdFromQuery,
    queryClient,
    setActionError,
    setEditingProduct,
    toast,
  ]);

  useEffect(() => {
    if (!editingProduct?.id) return;
    if (!editingProductDetailQuery.error) return;
    const error = editingProductDetailQuery.error;
    if (!(error instanceof ApiError) || error.status !== 404) return;

    handleMissingEditProduct('This product was deleted or is unavailable.');
  }, [
    editingProduct?.id,
    editingProductDetailQuery.error,
    handleMissingEditProduct,
  ]);

  return {
    isEditHydrating,
    handleOpenEditModal,
    handleCloseEdit,
    prefetchProductDetail,
    editingProductDetailQuery,
  };
}

'use client';
'use no memo';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import type { Catalog } from '@/shared/contracts/products/catalogs';
import type { PriceGroupWithDetails } from '@/shared/contracts/products/product';
import { api } from '@/shared/lib/api-client';
import { createMultiQueryV2 } from '@/shared/lib/query-factories-v2';
import { normalizeQueryKey } from '@/shared/lib/query-key-utils';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import type { UseProductsOptions } from './useProductsQuery';

// This hook composes deferred runtime state with multi-query metadata loading.
// Opt out of React Compiler memoization to keep the admin products page on a
// stable dev hook path.

type LanguageOption = {
  value: 'name_en' | 'name_pl' | 'name_de';
  label: string;
};

const supportedLanguageMap: Record<string, LanguageOption> = {
  EN: { value: 'name_en', label: 'English' },
  PL: { value: 'name_pl', label: 'Polish' },
  DE: { value: 'name_de', label: 'German' },
};

const PRICE_GROUPS_ENDPOINT = '/api/v2/products/metadata/price-groups';
const CATALOGS_ENDPOINT = '/api/v2/products/entities/catalogs';

// API fetch functions
async function fetchCatalogs(signal?: AbortSignal): Promise<Catalog[]> {
  return api.get<Catalog[]>(CATALOGS_ENDPOINT, { signal });
}

async function fetchPriceGroups(signal?: AbortSignal): Promise<PriceGroupWithDetails[]> {
  return api.get<PriceGroupWithDetails[]>(PRICE_GROUPS_ENDPOINT, { signal });
}

export interface UseCatalogSyncResult {
  catalogs: Catalog[];
  catalogsLoading: boolean;
  catalogsError: string | null;
  currencyCode: string;
  setCurrencyCode: (action: string | ((prev: string) => string)) => void;
  currencyOptions: string[];
  priceGroups: PriceGroupWithDetails[];
  catalogFilterInitialized: React.MutableRefObject<boolean>;
  languageOptions: LanguageOption[];
  fallbackNameLocale: 'name_en' | 'name_pl' | 'name_de' | undefined;
}

export type UseCatalogSyncOptions = UseProductsOptions;

const DEFAULT_LANGUAGE_OPTIONS: LanguageOption[] = [
  supportedLanguageMap['EN']!,
  supportedLanguageMap['PL']!,
  supportedLanguageMap['DE']!,
];

const resolveSupportedLanguageOption = (value: string | null | undefined): LanguageOption | undefined => {
  const normalizedValue = String(value ?? '').trim().toUpperCase();
  if (!normalizedValue) return undefined;
  if (normalizedValue in supportedLanguageMap) {
    return supportedLanguageMap[normalizedValue]!;
  }

  const suffix = normalizedValue.split(/[-_]/).pop();
  if (!suffix) return undefined;
  return supportedLanguageMap[suffix];
};

export function useCatalogSync(
  catalogFilter: string,
  { enabled = true }: UseCatalogSyncOptions = {}
): UseCatalogSyncResult {
  const catalogFilterInitialized = useRef(false);
  const [runtimeReady, setRuntimeReady] = useState(process.env['NODE_ENV'] === 'production');

  useEffect(() => {
    if (runtimeReady) return;
    // In React Strict Mode (dev), the first mount is intentionally discarded.
    // Deferring query enablement avoids start->abort noise for metadata calls.
    const timer = setTimeout(() => {
      setRuntimeReady(true);
    }, 0);
    return () => clearTimeout(timer);
  }, [runtimeReady]);

  const queriesEnabled = enabled && runtimeReady;

  // Parallel queries for all data sources
  const results = createMultiQueryV2({
    queries: [
      {
        queryKey: normalizeQueryKey(QUERY_KEYS.products.metadata.catalogs()),
        queryFn: ({ signal }: { signal?: AbortSignal }): Promise<Catalog[]> =>
          fetchCatalogs(signal),
        enabled: queriesEnabled,
        staleTime: 1000 * 60 * 5, // 5 minutes
        refetchOnMount: false,
        refetchOnWindowFocus: false,
        refetchOnReconnect: false,
        meta: {
          source: 'products.hooks.useCatalogSync.fetchCatalogs',
          operation: 'list',
          resource: 'products.metadata.catalogs',
          description: 'Loads products metadata catalogs.',
          domain: 'products',
          tags: ['products', 'metadata', 'catalogs', 'sync'],
        },
      },
      {
        queryKey: normalizeQueryKey(QUERY_KEYS.products.metadata.priceGroups()),
        queryFn: ({ signal }: { signal?: AbortSignal }): Promise<PriceGroupWithDetails[]> =>
          fetchPriceGroups(signal),
        enabled: queriesEnabled,
        staleTime: 1000 * 60 * 5,
        refetchOnMount: false,
        refetchOnWindowFocus: false,
        refetchOnReconnect: false,
        meta: {
          source: 'products.hooks.useCatalogSync.fetchPriceGroups',
          operation: 'list',
          resource: 'products.metadata.price-groups',
          description: 'Loads products metadata price groups.',
          domain: 'products',
          tags: ['products', 'metadata', 'price-groups', 'sync'],
        },
      },
    ] as const,
  });

  const catalogsQuery = results[0];
  const priceGroupsQuery = results[1];

  // Log errors
  useEffect(() => {
    if (catalogsQuery.error) {
      logClientError(catalogsQuery.error as Error, {
        context: { source: 'useCatalogSync', action: 'fetchCatalogs' },
      });
    }
    if (priceGroupsQuery.error) {
      logClientError(priceGroupsQuery.error as Error, {
        context: { source: 'useCatalogSync', action: 'fetchPriceGroups' },
      });
    }
  }, [catalogsQuery.error, priceGroupsQuery.error]);

  // Extract data with defaults
  const rawCatalogs = useMemo(() => {
    return Array.isArray(catalogsQuery.data) ? (catalogsQuery.data as Catalog[]) : [];
  }, [catalogsQuery.data]);
  const priceGroups = useMemo(
    () =>
      Array.isArray(priceGroupsQuery.data)
        ? (priceGroupsQuery.data as PriceGroupWithDetails[])
        : [],
    [priceGroupsQuery.data]
  );

  // Memoize catalog transformation to prevent new references
  const catalogs = useMemo(
    () =>
      rawCatalogs.map((catalog) => ({
        ...catalog,
        priceGroupIds: catalog.priceGroupIds ?? [],
        defaultPriceGroupId: catalog.defaultPriceGroupId ?? null,
      })),
    [rawCatalogs]
  );

  // Memoize currency options to prevent unnecessary re-renders
  const { codes, fallbackCode } = useMemo((): { codes: string[]; fallbackCode: string } => {
    if (priceGroups.length === 0) return { codes: [] as string[], fallbackCode: '' };

    const isCatalogScoped = catalogFilter !== 'all' && catalogFilter !== 'unassigned';
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const catalogPriceGroupIds = catalog?.priceGroupIds ?? [];
    const allowedGroupIds = catalogPriceGroupIds.length > 0 ? new Set(catalogPriceGroupIds) : null;

    const candidateGroups = allowedGroupIds
      ? priceGroups.filter((group) => allowedGroupIds.has(group.id))
      : priceGroups;

    let codes = Array.from(
      new Set(
        candidateGroups
          .map((group) => group.currency?.code)
          .filter((code): code is NonNullable<typeof code> => Boolean(code))
      )
    ).map((code) => code.trim().toUpperCase());

    codes = codes.filter((code) => /^[A-Z]{3,5}$/.test(code));

    const defaultGroupId = catalog?.defaultPriceGroupId ?? null;
    const defaultGroup = defaultGroupId
      ? candidateGroups.find((group) => group.id === defaultGroupId)
      : candidateGroups.find((group) => group.isDefault);

    const fallbackCode = defaultGroup?.currency?.code || codes[0] || '';

    return { codes, fallbackCode };
  }, [catalogFilter, catalogs, priceGroups]);

  // Sync Currency Options based on Catalog
  const currencyOptions = codes;

  const [userCurrencyCode, setUserCurrencyCode] = useState<string | null>(null);

  const currencyCode =
    userCurrencyCode && codes.includes(userCurrencyCode) ? userCurrencyCode : fallbackCode;

  const handleSetCurrencyCode = useCallback(
    (action: string | ((prev: string) => string)): void => {
      setUserCurrencyCode((current) => {
        const baseValue = current ?? fallbackCode;
        return typeof action === 'function' ? action(baseValue) : action;
      });
    },
    [fallbackCode]
  );

  const { languageOptions, fallbackNameLocale } = useMemo((): {
    languageOptions: LanguageOption[];
    fallbackNameLocale: 'name_en' | 'name_pl' | 'name_de' | undefined;
  } => {
    const options: LanguageOption[] = [];
    const isCatalogScoped = catalogFilter !== 'all' && catalogFilter !== 'unassigned';
    const catalog = isCatalogScoped
      ? catalogs.find((entry) => entry.id === catalogFilter)
      : undefined;
    const allowedIds = catalog?.languageIds ?? [];

    const seen = new Set<string>();
    (allowedIds.length > 0 ? allowedIds : Object.keys(supportedLanguageMap)).forEach((languageId) => {
      const option = resolveSupportedLanguageOption(languageId);
      if (!option || seen.has(option.value)) return;
      seen.add(option.value);
      options.push(option);
    });

    if (options.length === 0) {
      options.push(...DEFAULT_LANGUAGE_OPTIONS);
    }

    const defaultLanguageId = catalog?.defaultLanguageId ?? null;
    const defaultOption = resolveSupportedLanguageOption(defaultLanguageId);
    const fallbackNameLocale = defaultOption?.value ?? options[0]?.value;

    return { languageOptions: options, fallbackNameLocale };
  }, [catalogFilter, catalogs]);

  return {
    catalogs,
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: catalogsQuery.error ? (catalogsQuery.error as Error).message : null,
    currencyCode,
    setCurrencyCode: handleSetCurrencyCode,
    currencyOptions,
    priceGroups,
    catalogFilterInitialized,
    languageOptions,
    fallbackNameLocale,
  };
}

'use client';
'use no memo';

import { useQueryClient } from '@tanstack/react-query';
import { useEffect, useRef, useState } from 'react';

import { invalidateProductsAndDetail } from '@/features/products/hooks/productCache';
import { logProductListDebug } from '@/features/products/lib/product-list-observability';
import {
  buildProductAiRunFeedbackFromSnapshot,
  compareProductAiRunFeedback,
  type ProductAiRunFeedback,
} from '@/features/products/lib/product-ai-run-feedback';
import {
  buildQueuedProductAiRunSource,
  getQueuedProductSources,
  markQueuedProductSource,
  removeQueuedProductSource,
} from '@/features/products/state/queued-product-ops';
import {
  AI_PATH_RUN_QUEUE_CHANNEL,
  AI_PATH_RUN_ENQUEUED_EVENT_NAME,
  parseAiPathRunEnqueuedEventPayload,
} from '@/shared/contracts/ai-paths';
import {
  type TrackedAiPathRunSnapshot,
  isTrackedAiPathRunTerminal,
  subscribeToTrackedAiPathRun,
} from '@/shared/lib/ai-paths/client-run-tracker';
import { getRecentAiPathRunEnqueue } from '@/shared/lib/query-invalidation';
import {
  listTriggerButtonRunFeedback,
  markPersistedRunTerminal,
} from '@/shared/lib/ai-paths/trigger-button-run-feedback';
import { safeSetInterval, safeClearInterval, type SafeTimerId } from '@/shared/lib/timers';
import { logClientCatch, logClientError } from '@/shared/utils/observability/client-error-logger';

// useProductAiPathsRunSync: subscribes to AI Path run events and maintains
// per-product run state used for UI badges/feedback. Responsibilities:
// - Listen for enqueue events and subscribe to tracked run snapshots
// - Maintain a map of latest non-terminal run snapshots per product
// - Emit transient badge state with TTLs to avoid flicker on rapid updates
// - Persist terminal run feedback and invalidate product caches when needed
// Note: runs on the client runtime with refs and safe timers to avoid hook
// layout instability during Fast Refresh in the admin products route.

// Keep the badge visible longer than the last scheduled product refresh (9 s).
const AI_PATH_RUN_BADGE_TTL_MS = 30_000;
const AI_PATH_RUN_BADGE_REFRESH_INTERVAL_MS = 10_000;
const TERMINAL_PRODUCT_AI_RUN_BADGE_TTL_MS = 15_000;
const EMPTY_PRODUCT_AI_RUN_STATUS_BY_PRODUCT_ID = new Map<string, ProductAiRunFeedback>();

type TrackedProductRun = {
  productId: string;
  latestSnapshot: TrackedAiPathRunSnapshot | null;
  unsubscribe: () => void;
};

const resolveTrackedProductRun = (detail: unknown): { runId: string; productId: string } | null => {
  const payload = parseAiPathRunEnqueuedEventPayload(detail);
  if (!payload) return null;
  if (payload.entityType !== 'product') return null;
  if (!payload.entityId || !payload.runId) {
    return null;
  }
  return {
    runId: payload.runId,
    productId: payload.entityId,
  };
};

const hasTrackedProductRuns = (
  trackedRuns: Map<string, TrackedProductRun>,
  productId: string
): boolean => {
  for (const trackedRun of trackedRuns.values()) {
    if (trackedRun.productId === productId) {
      return true;
    }
  }
  return false;
};

const areFeedbackMapsEqual = (
  prev: ReadonlyMap<string, ProductAiRunFeedback>,
  next: ReadonlyMap<string, ProductAiRunFeedback>
): boolean => {
  if (prev.size !== next.size) return false;
  for (const [key, nextFeedback] of next) {
    const prevFeedback = prev.get(key);
    if (!prevFeedback) return false;
    // Only compare identity and status — updatedAt changes on every server
    // response even when nothing meaningful changed, causing needless re-renders.
    if (
      prevFeedback.runId !== nextFeedback.runId ||
      prevFeedback.status !== nextFeedback.status
    ) {
      return false;
    }
  }
  return true;
};

const buildProductAiRunStatusByProductId = (
  trackedRuns: ReadonlyMap<string, TrackedProductRun>
): ReadonlyMap<string, ProductAiRunFeedback> => {
  const next = new Map<string, ProductAiRunFeedback>();

  trackedRuns.forEach((trackedRun: TrackedProductRun) => {
    const snapshot = trackedRun.latestSnapshot;
    if (!snapshot || snapshot.trackingState === 'stopped' || isTrackedAiPathRunTerminal(snapshot)) {
      return;
    }

    const feedback = buildProductAiRunFeedbackFromSnapshot(snapshot);
    if (!feedback) return;

    const current = next.get(trackedRun.productId);
    if (!current || compareProductAiRunFeedback(feedback, current) > 0) {
      next.set(trackedRun.productId, feedback);
    }
  });

  return next;
};

const mergeProductAiRunFeedbackMaps = (args: {
  activeByProductId: ReadonlyMap<string, ProductAiRunFeedback>;
  terminalByProductId: ReadonlyMap<string, ProductAiRunFeedback>;
}): ReadonlyMap<string, ProductAiRunFeedback> => {
  const next = new Map<string, ProductAiRunFeedback>(args.terminalByProductId);
  args.activeByProductId.forEach((feedback: ProductAiRunFeedback, productId: string) => {
    const current = next.get(productId);
    if (!current || compareProductAiRunFeedback(feedback, current) >= 0) {
      next.set(productId, feedback);
    }
  });
  return next;
};

/**
 * Listens for AI-Paths runs triggered on individual products and reflects their
 * in-progress state in the product list's run badge + completion highlight.
 *
 * The event is dispatched by useAiPathTriggerEvent (shared lib) via a CustomEvent
 * so the shared layer never imports from the products feature.
 */
export function useProductAiPathsRunSync({
  enabled = true,
}: {
  enabled?: boolean;
} = {}): ReadonlyMap<string, ProductAiRunFeedback> {
  const queryClient = useQueryClient();
  const trackedRunsRef = useRef<Map<string, TrackedProductRun>>(new Map());
  const terminalProductAiRunStatusByProductIdRef = useRef<Map<string, ProductAiRunFeedback>>(
    new Map()
  );
  const terminalBadgeTimersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());
  const badgeRefreshIntervalRef = useRef<SafeTimerId | null>(null);
  const disposedRef = useRef(false);
  const [productAiRunStatusByProductId, setProductAiRunStatusByProductId] = useState<
    ReadonlyMap<string, ProductAiRunFeedback>
  >(() => EMPTY_PRODUCT_AI_RUN_STATUS_BY_PRODUCT_ID);

  useEffect(() => {
    if (!enabled) {
      disposedRef.current = true;
      setProductAiRunStatusByProductId((prev) =>
        prev.size === 0 ? prev : EMPTY_PRODUCT_AI_RUN_STATUS_BY_PRODUCT_ID
      );
      return;
    }

    disposedRef.current = false;

    const clearTerminalBadgeTimer = (productId: string): void => {
      const existingTimer = terminalBadgeTimersRef.current.get(productId);
      if (!existingTimer) return;
      clearTimeout(existingTimer);
      terminalBadgeTimersRef.current.delete(productId);
    };

    const clearTerminalFeedback = (productId: string): boolean => {
      clearTerminalBadgeTimer(productId);
      return terminalProductAiRunStatusByProductIdRef.current.delete(productId);
    };

    const setTerminalFeedback = (
      productId: string,
      feedback: ProductAiRunFeedback
    ): void => {
      terminalProductAiRunStatusByProductIdRef.current.set(productId, feedback);
      clearTerminalBadgeTimer(productId);
      const timer = setTimeout(() => {
        terminalBadgeTimersRef.current.delete(productId);
        if (clearTerminalFeedback(productId)) {
          syncProductAiRunStatuses();
        }
      }, TERMINAL_PRODUCT_AI_RUN_BADGE_TTL_MS);
      terminalBadgeTimersRef.current.set(productId, timer);
    };

    const syncProductAiRunStatuses = (): void => {
      setProductAiRunStatusByProductId((prev) => {
        const next = mergeProductAiRunFeedbackMaps({
          activeByProductId: buildProductAiRunStatusByProductId(trackedRunsRef.current),
          terminalByProductId: terminalProductAiRunStatusByProductIdRef.current,
        });
        if (next.size === 0 && prev.size === 0) return prev;
        if (areFeedbackMapsEqual(prev, next)) return prev;
        logProductListDebug(
          'product-ai-run-status-map-change',
          {
            previousCount: prev.size,
            nextCount: next.size,
            trackedRunsCount: trackedRunsRef.current.size,
            statuses: Array.from(next.entries()).map(([productId, feedback]) => ({
              productId,
              runId: feedback.runId,
              status: feedback.status,
            })),
          },
          {
            dedupeKey: 'product-ai-run-status-map-change',
            throttleMs: 500,
          }
        );
        return next;
      });
    };

    const stopBadgeRefresh = (): void => {
      if (badgeRefreshIntervalRef.current === null) return;
      safeClearInterval(badgeRefreshIntervalRef.current);
      badgeRefreshIntervalRef.current = null;
    };

    const refreshQueuedBadge = (runId: string, productId: string): void => {
      const source = buildQueuedProductAiRunSource(runId);
      if (!source) return;
      markQueuedProductSource(productId, source, AI_PATH_RUN_BADGE_TTL_MS);
    };

    const syncQueuedSourcesForProduct = (productId: string): void => {
      const activeQueuedSources = new Set<string>();
      trackedRunsRef.current.forEach((candidate: TrackedProductRun, trackedRunId: string) => {
        if (candidate.productId !== productId) return;
        const source = buildQueuedProductAiRunSource(trackedRunId);
        if (source) {
          activeQueuedSources.add(source);
        }
      });

      getQueuedProductSources(productId).forEach((source: string) => {
        if (!source.startsWith('ai-run:')) return;
        if (activeQueuedSources.has(source)) return;
        removeQueuedProductSource(productId, source);
      });
    };

    const finalizeRun = (runId: string, productId: string): void => {
      const trackedRun = trackedRunsRef.current.get(runId);
      // Mark as terminal in persisted storage so it won't be re-tracked on next mount.
      const latestSnapshot = trackedRun?.latestSnapshot ?? null;
      const terminalStatus = latestSnapshot?.status;
      if (latestSnapshot && terminalStatus && isTrackedAiPathRunTerminal(latestSnapshot)) {
        markPersistedRunTerminal(runId, terminalStatus);
        const terminalFeedback = buildProductAiRunFeedbackFromSnapshot(latestSnapshot, {
          allowStopped: true,
        });
        if (terminalFeedback) {
          setTerminalFeedback(productId, terminalFeedback);
        }
      }
      trackedRun?.unsubscribe();
      trackedRunsRef.current.delete(runId);
      invalidateProductsAndDetail(queryClient, productId).then(() => {
        if (disposedRef.current) return;
        if (clearTerminalFeedback(productId)) {
          syncProductAiRunStatuses();
        }
      }).catch((err: unknown) => {
        logClientCatch(err, {
          source: 'useProductAiPathsRunSync',
          action: 'finalizeRun',
          level: 'warn',
        });
      });
      const source = buildQueuedProductAiRunSource(runId);
      if (source) {
        removeQueuedProductSource(productId, source);
      }
      syncQueuedSourcesForProduct(productId);
      if (hasTrackedProductRuns(trackedRunsRef.current, productId)) {
        trackedRunsRef.current.forEach((candidate: TrackedProductRun, trackedRunId: string) => {
          if (candidate.productId !== productId) return;
          refreshQueuedBadge(trackedRunId, productId);
        });
      }
      if (trackedRunsRef.current.size === 0) {
        stopBadgeRefresh();
      }
      logProductListDebug(
        'product-ai-run-finalized',
        {
          runId,
          productId,
          terminalStatus: terminalStatus ?? null,
          trackedRunsRemaining: trackedRunsRef.current.size,
        },
        {
          dedupeKey: 'product-ai-run-finalized',
          throttleMs: 250,
        }
      );
      syncProductAiRunStatuses();
    };

    const refreshTrackedRunBadges = (): void => {
      logProductListDebug(
        'product-ai-run-badge-refresh-tick',
        {
          trackedRunsCount: trackedRunsRef.current.size,
        },
        {
          dedupeKey: 'product-ai-run-badge-refresh-tick',
          throttleMs: AI_PATH_RUN_BADGE_REFRESH_INTERVAL_MS,
        }
      );
      trackedRunsRef.current.forEach((trackedRun: TrackedProductRun, runId: string) => {
        if (trackedRun.latestSnapshot?.trackingState === 'stopped') return;
        if (trackedRun.latestSnapshot && isTrackedAiPathRunTerminal(trackedRun.latestSnapshot)) {
          return;
        }
        refreshQueuedBadge(runId, trackedRun.productId);
      });
    };

    const ensureBadgeRefresh = (): void => {
      if (trackedRunsRef.current.size === 0 || badgeRefreshIntervalRef.current !== null) {
        return;
      }
      badgeRefreshIntervalRef.current = safeSetInterval(
        refreshTrackedRunBadges,
        AI_PATH_RUN_BADGE_REFRESH_INTERVAL_MS
      );
    };

    const trackRun = (
      runId: string,
      productId: string,
      initialSnapshot?: Partial<TrackedAiPathRunSnapshot> | undefined
    ): void => {
      clearTerminalFeedback(productId);
      const existingTrackedRun = trackedRunsRef.current.get(runId);
      if (existingTrackedRun) {
        existingTrackedRun.productId = productId;
        logProductListDebug(
          'product-ai-run-retracked',
          {
            runId,
            productId,
          },
          {
            dedupeKey: 'product-ai-run-retracked',
            throttleMs: 250,
          }
        );
        refreshQueuedBadge(runId, productId);
        syncQueuedSourcesForProduct(productId);
        ensureBadgeRefresh();
        syncProductAiRunStatuses();
        return;
      }

      const trackedRun: TrackedProductRun = {
        productId,
        latestSnapshot: null,
        unsubscribe: () => {},
      };
      trackedRunsRef.current.set(runId, trackedRun);
      logProductListDebug(
        'product-ai-run-tracked',
        {
          runId,
          productId,
          trackedRunsCount: trackedRunsRef.current.size,
        },
        {
          dedupeKey: 'product-ai-run-tracked',
          throttleMs: 250,
        }
      );

      const unsubscribe = subscribeToTrackedAiPathRun(
        runId,
        (snapshot: TrackedAiPathRunSnapshot): void => {
          if (disposedRef.current) return;

          const activeTrackedRun = trackedRunsRef.current.get(runId);
          if (!activeTrackedRun) return;

          activeTrackedRun.latestSnapshot = snapshot;
          logProductListDebug(
            'product-ai-run-snapshot',
            {
              runId,
              productId: activeTrackedRun.productId,
              status: snapshot.status,
              trackingState: snapshot.trackingState,
            },
            {
              dedupeKey: `product-ai-run-snapshot:${runId}`,
              throttleMs: 250,
            }
          );

          if (snapshot.trackingState === 'stopped' || isTrackedAiPathRunTerminal(snapshot)) {
            finalizeRun(runId, activeTrackedRun.productId);
            return;
          }

          refreshQueuedBadge(runId, activeTrackedRun.productId);
          syncQueuedSourcesForProduct(activeTrackedRun.productId);
          syncProductAiRunStatuses();
        },
        {
          initialSnapshot: {
            runId,
            status: initialSnapshot?.status ?? 'queued',
            updatedAt: initialSnapshot?.updatedAt,
            finishedAt: initialSnapshot?.finishedAt,
            errorMessage: initialSnapshot?.errorMessage ?? null,
            entityId: productId,
            entityType: 'product',
          },
        }
      );

      const activeTrackedRun = trackedRunsRef.current.get(runId);
      if (activeTrackedRun === trackedRun) {
        activeTrackedRun.unsubscribe = unsubscribe;
        ensureBadgeRefresh();
        return;
      }

      unsubscribe();
    };

    const handlePayload = (payload: unknown): void => {
      try {
        const trackedRun = resolveTrackedProductRun(payload);
        if (!trackedRun) return;
        logProductListDebug(
          'product-ai-run-payload',
          {
            runId: trackedRun.runId,
            productId: trackedRun.productId,
          },
          {
            dedupeKey: 'product-ai-run-payload',
            throttleMs: 250,
          }
        );
        trackRun(trackedRun.runId, trackedRun.productId);
      } catch (error) {
        logClientCatch(error, {
          source: 'useProductAiPathsRunSync',
          action: 'handlePayload',
          level: 'warn',
        });
      }
    };

    const handler = (event: Event): void => {
      handlePayload((event as CustomEvent<unknown>).detail);
    };

    // Only rehydrate persisted runs that are recent enough to still be active.
    // Stale runs (>10 min) are likely from a previous session and would just
    // create unnecessary polling traffic.
    const MAX_PERSISTED_RUN_AGE_MS = 10 * 60 * 1_000;
    listTriggerButtonRunFeedback({
      entityType: 'product',
      activeOnly: true,
    }).forEach((persistedRun) => {
      if (!persistedRun.entityId) return;
      const runAge = persistedRun.updatedAt
        ? Date.now() - new Date(persistedRun.updatedAt).getTime()
        : Infinity;
      if (runAge > MAX_PERSISTED_RUN_AGE_MS) return;
      const initialStatus = persistedRun.status === 'waiting' ? 'queued' : persistedRun.status;
      logProductListDebug(
        'product-ai-run-rehydrated',
        {
          runId: persistedRun.runId,
          productId: persistedRun.entityId,
          initialStatus,
        },
        {
          dedupeKey: 'product-ai-run-rehydrated',
          throttleMs: 250,
        }
      );
      trackRun(persistedRun.runId, persistedRun.entityId, {
        runId: persistedRun.runId,
        status: initialStatus,
        updatedAt: persistedRun.updatedAt,
        finishedAt: persistedRun.finishedAt,
        errorMessage: persistedRun.errorMessage,
        entityId: persistedRun.entityId,
        entityType: 'product',
      });
    });

    handlePayload(getRecentAiPathRunEnqueue());

    window.addEventListener(AI_PATH_RUN_ENQUEUED_EVENT_NAME, handler);

    let channel: BroadcastChannel | null = null;
    const BroadcastChannelCtor = window.BroadcastChannel;
    if (typeof BroadcastChannelCtor === 'function') {
      try {
        channel = new BroadcastChannelCtor(AI_PATH_RUN_QUEUE_CHANNEL);
        channel.onmessage = (event: MessageEvent<unknown>): void => {
          handlePayload(event.data);
        };
      } catch (error) {
        logClientError(error);
        channel = null;
      }
    }

    return () => {
      disposedRef.current = true;
      stopBadgeRefresh();
      terminalBadgeTimersRef.current.forEach((timer: ReturnType<typeof setTimeout>) =>
        clearTimeout(timer)
      );
      terminalBadgeTimersRef.current.clear();
      terminalProductAiRunStatusByProductIdRef.current.clear();
      trackedRunsRef.current.forEach((trackedRun: TrackedProductRun) => trackedRun.unsubscribe());
      trackedRunsRef.current.clear();
      window.removeEventListener(AI_PATH_RUN_ENQUEUED_EVENT_NAME, handler);
      channel?.close();
    };
  }, [enabled, queryClient]);

  return productAiRunStatusByProductId;
}

'use client';
'use no memo';
// useProductData: high-level composition hook that binds local UI state
// (pagination, filters, debounced search) to TanStack Query factories. It
// centralizes initialization from user preferences, enforces filter
// normalization/validation, keeps pagination stable across filter changes, and
// exposes a single, testable interface consumed by the product list UI.
//
// Keep this on the client runtime (no heavy server-only work) and avoid
// embedding side-effects—use the returned refresh() to trigger explicit
// invalidation or refetch flows.

import { useQueryClient } from '@tanstack/react-query';
import { useState, useMemo, useEffect, useCallback, useRef } from 'react';

import {
  type UseProductsFilters,
  type UseProductsOptions,
  useProducts as useProductsQuery,
  useProductsCount as useProductsCountQuery,
  useProductsWithCount,
} from '@/features/products/hooks/useProductsQuery';
import { productAdvancedFilterGroupSchema } from '@/shared/contracts/products/filters';
import { type ProductWithImages } from '@/shared/contracts/products';
import { normalizeProductPageSize } from '@/shared/lib/products/constants';

import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { refetchProductsAndCounts } from './productCache';

// This hook layers a large local-state surface over TanStack Query. Keep it on
// the plain hook runtime to avoid React Compiler dev mismatches on
// /admin/products while we stabilize the products page stack.

const isValidAdvancedFilterPayload = (payload: string): boolean => {
  try {
    const parsed: unknown = JSON.parse(payload);
    return productAdvancedFilterGroupSchema.safeParse(parsed).success;
  } catch (error) {
    logClientError(error);
    return false;
  }
};

const PARSED_MATCH_PRODUCT_IDS_MAX = 500;

const normalizeProductIdList = (ids: string[]): string[] =>
  Array.from(
    new Set(
      ids
        .map((id: string): string => id.trim())
        .filter((id: string): boolean => id.length > 0)
    )
  ).slice(0, PARSED_MATCH_PRODUCT_IDS_MAX);

// --- Queries ---

export type { UseProductsFilters };

export function useProducts(filters: UseProductsFilters, options: UseProductsOptions = {}) {
  return useProductsQuery(filters, options);
}

export function useProductsCount(filters: UseProductsFilters, options: UseProductsOptions = {}) {
  return useProductsCountQuery(filters, options);
}

// --- Composite Hook ---

export interface UseProductDataProps {
  refreshTrigger?: number;
  initialCatalogFilter?: string | null;
  initialPageSize?: number | null;
  initialAppliedAdvancedFilter?: string | null;
  initialAppliedAdvancedFilterPresetId?: string | null;
  preferencesLoaded: boolean;
  currencyCode?: string | null;
  priceGroups?: unknown[];
  searchLanguage?: string | null;
}

export interface ProductDataHookResult {
  data: ProductWithImages[];
  totalPages: number;
  page: number;
  setPage: (p: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  search: string;
  setSearch: (s: string) => void;
  productId: string;
  setProductId: (s: string) => void;
  idMatchMode: 'exact' | 'partial';
  setIdMatchMode: (mode: 'exact' | 'partial') => void;
  sku: string;
  setSku: (s: string) => void;
  description: string;
  setDescription: (s: string) => void;
  categoryId: string;
  setCategoryId: (id: string) => void;
  minPrice: number | undefined;
  setMinPrice: (p: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (p: number | undefined) => void;
  stockValue: number | undefined;
  setStockValue: (value: number | undefined) => void;
  stockOperator: '' | 'gt' | 'gte' | 'lt' | 'lte' | 'eq';
  setStockOperator: (value: '' | 'gt' | 'gte' | 'lt' | 'lte' | 'eq') => void;
  startDate: string | undefined;
  setStartDate: (s: string | undefined) => void;
  endDate: string | undefined;
  setEndDate: (s: string | undefined) => void;
  advancedFilter: string;
  setAdvancedFilter: (value: string) => void;
  activeAdvancedFilterPresetId: string | null;
  setAdvancedFilterState: (value: string, presetId: string | null) => void;
  catalogFilter: string;
  setCatalogFilter: (f: string) => void;
  baseExported: '' | 'true' | 'false';
  setBaseExported: (value: '' | 'true' | 'false') => void;
  includeArchived: boolean;
  setIncludeArchived: (value: boolean) => void;
  parsedMatchProductIds: string[];
  setParsedMatchProductIds: (ids: string[]) => void;
  clearParsedMatchProductIds: () => void;
  loadError: Error | null;
  isLoading: boolean;
  isFetching: boolean;
  refresh: () => void;
}

export function useProductData({
  refreshTrigger,
  initialCatalogFilter,
  initialPageSize,
  initialAppliedAdvancedFilter,
  initialAppliedAdvancedFilterPresetId,
  preferencesLoaded,
  searchLanguage,
}: UseProductDataProps): ProductDataHookResult {
  const queryClient = useQueryClient();

  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(() => normalizeProductPageSize(initialPageSize, 20));
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState('');
  const [productId, setProductId] = useState('');
  const [idMatchMode, setIdMatchMode] = useState<'exact' | 'partial'>('exact');
  const [sku, setSku] = useState('');
  const [description, setDescription] = useState('');
  const [categoryId, setCategoryId] = useState('');
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [stockValue, setStockValue] = useState<number | undefined>(undefined);
  const [stockOperator, setStockOperator] = useState<'' | 'gt' | 'gte' | 'lt' | 'lte' | 'eq'>('');
  const [startDate, setStartDate] = useState<string | undefined>(undefined);
  const [endDate, setEndDate] = useState<string | undefined>(undefined);
  const [advancedFilter, setAdvancedFilter] = useState('');
  const [activeAdvancedFilterPresetId, setActiveAdvancedFilterPresetId] = useState<string | null>(
    null
  );
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter || 'all');
  const [baseExported, setBaseExported] = useState<'' | 'true' | 'false'>('');
  const [includeArchived, setIncludeArchived] = useState(false);
  const [parsedMatchProductIds, setParsedMatchProductIdsState] = useState<string[]>([]);
  const hasInitialized = useRef(false);
  const [filtersInitialized, setFiltersInitialized] = useState(true);

  useEffect(() => {
    if (hasInitialized.current) return;
    if (!preferencesLoaded) return;

    if (initialCatalogFilter) setCatalogFilter(initialCatalogFilter);
    if (initialPageSize) setPageSize(normalizeProductPageSize(initialPageSize, 20));
    const normalizedAdvancedFilter = initialAppliedAdvancedFilter?.trim() ?? '';
    if (
      normalizedAdvancedFilter.length > 0 &&
      isValidAdvancedFilterPayload(normalizedAdvancedFilter)
    ) {
      setAdvancedFilter(normalizedAdvancedFilter);
      setActiveAdvancedFilterPresetId(initialAppliedAdvancedFilterPresetId ?? null);
    } else {
      setAdvancedFilter('');
      setActiveAdvancedFilterPresetId(null);
    }
    hasInitialized.current = true;
    setFiltersInitialized(true);
  }, [
    preferencesLoaded,
    initialCatalogFilter,
    initialPageSize,
    initialAppliedAdvancedFilter,
    initialAppliedAdvancedFilterPresetId,
  ]);

  // Debounce the free-text search input so that we don't fire a new
  // products query on every single keystroke while the user is typing.
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300);
    return () => clearTimeout(timer);
  }, [search]);

  const queriesEnabled = filtersInitialized;
  const parsedMatchProductIdsKey = parsedMatchProductIds.join('\0');
  const effectivePageSize = useMemo(
    (): number =>
      parsedMatchProductIds.length > 0
        ? Math.min(PARSED_MATCH_PRODUCT_IDS_MAX, Math.max(pageSize, parsedMatchProductIds.length))
        : pageSize,
    [pageSize, parsedMatchProductIds.length]
  );

  const filters: UseProductsFilters = useMemo(
    () => {
      const normalizedSearchLanguage = (searchLanguage || undefined) as
        | 'name_en'
        | 'name_pl'
        | 'name_de'
        | undefined;

      if (parsedMatchProductIds.length > 0) {
        return {
          ids: parsedMatchProductIds,
          page,
          pageSize: effectivePageSize,
          searchLanguage: normalizedSearchLanguage,
        };
      }

      return {
        search: debouncedSearch || undefined,
        id: productId || undefined,
        idMatchMode: productId ? idMatchMode : undefined,
        sku: sku || undefined,
        description: description || undefined,
        categoryId: categoryId || undefined,
        minPrice,
        maxPrice,
        stockValue,
        stockOperator: stockValue !== undefined ? stockOperator || 'eq' : undefined,
        startDate: startDate || undefined,
        endDate: endDate || undefined,
        advancedFilter: advancedFilter || undefined,
        page,
        pageSize,
        catalogId: catalogFilter === 'all' ? undefined : catalogFilter,
        searchLanguage: normalizedSearchLanguage,
        baseExported: baseExported === 'true' ? true : baseExported === 'false' ? false : undefined,
        archived: includeArchived ? undefined : false,
      };
    },
    [
      debouncedSearch,
      productId,
      idMatchMode,
      sku,
      description,
      categoryId,
      minPrice,
      maxPrice,
      stockValue,
      stockOperator,
      startDate,
      endDate,
      advancedFilter,
      page,
      pageSize,
      effectivePageSize,
      catalogFilter,
      searchLanguage,
      baseExported,
      includeArchived,
      parsedMatchProductIds,
    ]
  );

  const productsWithCountQuery = useProductsWithCount(filters, {
    enabled: queriesEnabled,
    prefetchNextPage: page > 1,
  });
  const loadError = useMemo((): Error | null => {
    const error = productsWithCountQuery.error;
    if (!error) return null;
    if (error instanceof Error) return error;
    return new Error(String(error));
  }, [productsWithCountQuery.error]);

  const totalPages = useMemo(() => {
    return Math.ceil(productsWithCountQuery.total / effectivePageSize);
  }, [effectivePageSize, productsWithCountQuery.total]);

  // Keep pagination valid when filters change.
  useEffect(() => {
    setPage(1);
  }, [
    debouncedSearch,
    productId,
    idMatchMode,
    sku,
    description,
    categoryId,
    minPrice,
    maxPrice,
    stockValue,
    stockOperator,
    startDate,
    endDate,
    advancedFilter,
    catalogFilter,
    baseExported,
    includeArchived,
    parsedMatchProductIdsKey,
    pageSize,
  ]);

  // Clamp page when current page no longer exists after count change.
  useEffect(() => {
    if (page > 1 && totalPages > 0 && page > totalPages) {
      setPage(totalPages);
    }
  }, [page, totalPages]);

  const refresh = useCallback(() => {
    void refetchProductsAndCounts(queryClient);
  }, [queryClient]);

  // Invalidate when refreshTrigger changes
  useEffect(() => {
    if (refreshTrigger) {
      refresh();
    }
  }, [refreshTrigger, refresh]);

  const handleSetPage = useCallback((p: number) => setPage(p), []);
  const handleSetPageSize = useCallback(
    (size: number) => setPageSize(normalizeProductPageSize(size, 20)),
    []
  );
  const handleSetSearch = useCallback((s: string) => setSearch(s), []);
  const handleSetProductId = useCallback((s: string) => setProductId(s), []);
  const handleSetIdMatchMode = useCallback((mode: 'exact' | 'partial') => setIdMatchMode(mode), []);
  const handleSetSku = useCallback((s: string) => setSku(s), []);
  const handleSetDescription = useCallback((s: string) => setDescription(s), []);
  const handleSetCategoryId = useCallback((id: string) => setCategoryId(id), []);
  const handleSetMinPrice = useCallback((p: number | undefined) => setMinPrice(p), []);
  const handleSetMaxPrice = useCallback((p: number | undefined) => setMaxPrice(p), []);
  const handleSetStockValue = useCallback((value: number | undefined) => setStockValue(value), []);
  const handleSetStockOperator = useCallback(
    (value: '' | 'gt' | 'gte' | 'lt' | 'lte' | 'eq') => setStockOperator(value),
    []
  );
  const handleSetStartDate = useCallback((s: string | undefined) => setStartDate(s), []);
  const handleSetEndDate = useCallback((s: string | undefined) => setEndDate(s), []);
  const handleSetAdvancedFilterState = useCallback((value: string, presetId: string | null) => {
    const normalizedValue = value.trim();
    setAdvancedFilter(normalizedValue);
    setActiveAdvancedFilterPresetId(normalizedValue.length > 0 ? presetId : null);
  }, []);
  const handleSetAdvancedFilter = useCallback(
    (value: string) => {
      handleSetAdvancedFilterState(value, null);
    },
    [handleSetAdvancedFilterState]
  );
  const handleSetCatalogFilter = useCallback((f: string) => setCatalogFilter(f), []);
  const handleSetBaseExported = useCallback(
    (value: '' | 'true' | 'false') => setBaseExported(value),
    []
  );
  const handleSetIncludeArchived = useCallback((value: boolean) => setIncludeArchived(value), []);
  const handleSetParsedMatchProductIds = useCallback((ids: string[]) => {
    const normalizedIds = normalizeProductIdList(ids);
    setPage(1);
    setParsedMatchProductIdsState(normalizedIds);
    if (normalizedIds.length > 0) {
      void refetchProductsAndCounts(queryClient);
    }
  }, [queryClient]);
  const handleClearParsedMatchProductIds = useCallback(() => {
    setParsedMatchProductIdsState([]);
  }, []);

  return {
    data: productsWithCountQuery.products,
    totalPages,
    page,
    setPage: handleSetPage,
    pageSize,
    setPageSize: handleSetPageSize,
    search,
    setSearch: handleSetSearch,
    productId,
    setProductId: handleSetProductId,
    idMatchMode,
    setIdMatchMode: handleSetIdMatchMode,
    sku,
    setSku: handleSetSku,
    description,
    setDescription: handleSetDescription,
    categoryId,
    setCategoryId: handleSetCategoryId,
    minPrice,
    setMinPrice: handleSetMinPrice,
    maxPrice,
    setMaxPrice: handleSetMaxPrice,
    stockValue,
    setStockValue: handleSetStockValue,
    stockOperator,
    setStockOperator: handleSetStockOperator,
    startDate,
    setStartDate: handleSetStartDate,
    endDate,
    setEndDate: handleSetEndDate,
    advancedFilter,
    setAdvancedFilter: handleSetAdvancedFilter,
    activeAdvancedFilterPresetId,
    setAdvancedFilterState: handleSetAdvancedFilterState,
    catalogFilter,
    setCatalogFilter: handleSetCatalogFilter,
    baseExported,
    setBaseExported: handleSetBaseExported,
    includeArchived,
    setIncludeArchived: handleSetIncludeArchived,
    parsedMatchProductIds,
    setParsedMatchProductIds: handleSetParsedMatchProductIds,
    clearParsedMatchProductIds: handleClearParsedMatchProductIds,
    loadError,
    isLoading: productsWithCountQuery.isLoading,
    isFetching: productsWithCountQuery.isFetching,
    refresh,
  };
}

'use client';

// useProductDataMutations: collection of server-facing mutations for product
// data (create, update, delete, bulk operations). Each mutation uses the
// project's query-factory helpers to enable optimistic updates and cache
// invalidation strategies.

import { type QueryClient, type UseMutationResult } from '@tanstack/react-query';

import { createProduct, updateProduct, deleteProduct } from '@/features/products/api';
import {
  addQueuedProductSource,
  buildQueuedProductOfflineMutationSource,
  removeQueuedProductSource,
} from '@/features/products/state/queued-product-ops';
import type { ProductWithImages } from '@/shared/contracts/products/product';
import type { IdDataDto } from '@/shared/contracts/base';
import { badRequestError, notFoundError, operationFailedError } from '@/shared/errors/app-error';
import { useOfflineMutation } from '@/shared/hooks/offline/useOfflineMutation';
import { api } from '@/shared/lib/api-client';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { withCsrfHeaders } from '@/shared/lib/security/csrf-client';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import {
  productsAllQueryKey,
  productsCountsQueryKey,
  getProductDetailQueryKey,
  invalidateProductsAndCounts,
  invalidateProductTitleTerms,
} from './productCache';

const PRODUCT_UPDATE_FORM_TIMEOUT_MS = 60_000;
const PRODUCT_UPDATE_QUEUE_SOURCE = buildQueuedProductOfflineMutationSource('update');
const PRODUCT_DELETE_QUEUE_SOURCE = buildQueuedProductOfflineMutationSource('delete');

type ProductListCacheValue =
  | ProductWithImages[]
  | { items: ProductWithImages[]; total?: number }
  | { products: ProductWithImages[] }
  | null
  | undefined;

const isPaginatedItemsCacheValue = (
  cacheValue: ProductListCacheValue
): cacheValue is { items: ProductWithImages[]; total?: number } =>
  Boolean(cacheValue) &&
  !Array.isArray(cacheValue) &&
  'items' in (cacheValue as any) &&
  Array.isArray((cacheValue as any).items);

const isProductsArrayCacheValue = (
  cacheValue: ProductListCacheValue
): cacheValue is { products: ProductWithImages[] } =>
  Boolean(cacheValue) &&
  !Array.isArray(cacheValue) &&
  'products' in (cacheValue as any) &&
  Array.isArray((cacheValue as any).products);

const patchProductListCacheValue = (
  cacheValue: ProductListCacheValue,
  savedProduct: ProductWithImages
): ProductListCacheValue => {
  if (!cacheValue) return cacheValue;
  if (Array.isArray(cacheValue)) {
    return cacheValue.map((product: ProductWithImages) =>
      product.id === savedProduct.id ? { ...product, ...savedProduct } : product
    );
  }
  if (isPaginatedItemsCacheValue(cacheValue)) {
    return {
      ...cacheValue,
      items: cacheValue.items.map((product: ProductWithImages) =>
        product.id === savedProduct.id ? { ...product, ...savedProduct } : product
      ),
    };
  }
  if (isProductsArrayCacheValue(cacheValue)) {
    return {
      ...cacheValue,
      products: cacheValue.products.map((product: ProductWithImages) =>
        product.id === savedProduct.id ? { ...product, ...savedProduct } : product
      ),
    };
  }
  return cacheValue;
};

const syncUpdatedProductAcrossCaches = (
  queryClient: QueryClient,
  savedProduct: ProductWithImages
): void => {
  queryClient.setQueryData(
    getProductDetailQueryKey(savedProduct.id),
    (old: ProductWithImages | undefined) => (old ? { ...old, ...savedProduct } : savedProduct)
  );
  queryClient.setQueryData(QUERY_KEYS.products.detailEdit(savedProduct.id), savedProduct);
  queryClient.setQueriesData(
    { queryKey: QUERY_KEYS.products.lists() },
    (old: ProductListCacheValue) => patchProductListCacheValue(old, savedProduct)
  );
};

const refreshUpdatedProductCaches = (
  queryClient: QueryClient,
  savedProduct: ProductWithImages
): void => {
  syncUpdatedProductAcrossCaches(queryClient, savedProduct);
  void Promise.all([
    queryClient.invalidateQueries({
      queryKey: QUERY_KEYS.products.lists(),
      refetchType: 'none',
    }),
    queryClient.invalidateQueries({
      queryKey: QUERY_KEYS.products.counts(),
      refetchType: 'none',
    }),
    queryClient.invalidateQueries({
      queryKey: QUERY_KEYS.products.detail(savedProduct.id),
      refetchType: 'none',
    }),
    queryClient.invalidateQueries({
      queryKey: QUERY_KEYS.products.detailEdit(savedProduct.id),
      refetchType: 'none',
    }),
    queryClient.invalidateQueries({
      queryKey: QUERY_KEYS.products.validatorLatestProductSource(),
      refetchType: 'none',
    }),
  ])
    .catch((error) => {
      logClientError(error, {
        context: {
          source: 'products.hooks.useUpdateProductMutation',
          action: 'refreshUpdatedProductCaches',
          productId: savedProduct.id,
        },
      });
    })
    .finally(() => {
      syncUpdatedProductAcrossCaches(queryClient, savedProduct);
    });
};

export function useCreateProductMutation(): UseMutationResult<unknown, Error, FormData, unknown> {
  return useOfflineMutation((formData: FormData) => createProduct(formData), {
    queryKey: productsAllQueryKey,
    meta: {
      source: 'products.hooks.useCreateProductMutation',
      operation: 'create',
      resource: 'products',
      domain: 'products',
      tags: ['products', 'create'],
    },
    extraInvalidateKeys: [productsCountsQueryKey],
    invalidate: async (queryClient) => {
      await Promise.all([
        invalidateProductsAndCounts(queryClient),
        invalidateProductTitleTerms(queryClient),
      ]);
    },
    queuedMessage: 'Product creation queued in runtime queue.',
    processedMessage: 'Queued product creation completed.',
  });
}

export function useUpdateProductMutation(): UseMutationResult<
  ProductWithImages | null,
  Error,
  IdDataDto<Partial<ProductWithImages> | FormData> & {
    originalSku?: string | null;
    originalNameEn?: string | null;
  },
  unknown
> {
  const normalizeIdentityText = (value?: string | null): string =>
    typeof value === 'string' ? value.trim() : '';

  const collectFieldErrorMessages = (details: unknown): string[] => {
    if (!details || typeof details !== 'object' || Array.isArray(details)) {
      return [];
    }

    const fields = (details as { fields?: unknown }).fields;
    if (!fields || typeof fields !== 'object' || Array.isArray(fields)) {
      return [];
    }

    return Object.entries(fields as Record<string, unknown>)
      .flatMap(([field, value]): string[] => {
        if (!Array.isArray(value)) {
          return [];
        }

        return value
          .map((entry: unknown): string => {
            const message = typeof entry === 'string' ? entry.trim() : '';
            return message ? `${field}: ${message}` : '';
          })
          .filter((entry: string): boolean => entry.length > 0);
      })
      .slice(0, 3);
  };

  const parseUpdateError = async (response: Response): Promise<string> => {
    const errorData = (await response.json().catch(() => ({}))) as {
      error?: string;
      details?: unknown;
    };
    let message = errorData.error || 'Failed to update product';
    const detailMessages = Array.isArray(errorData.details)
      ? errorData.details
        .slice(0, 3)
        .map((d: { field?: unknown; message?: unknown }) => {
          const field = typeof d.field === 'string' && d.field ? d.field : 'field';
          const msg = typeof d.message === 'string' && d.message ? d.message : 'invalid';
          return `${field}: ${msg}`;
        })
      : collectFieldErrorMessages(errorData.details);
    if (detailMessages.length > 0) {
      message = `${message} (${detailMessages.join(', ')})`;
    }
    return message;
  };

  const resolveProductIdByIdentity = async (
    originalSku?: string | null,
    originalNameEn?: string | null
  ): Promise<
    | { kind: 'resolved'; id: string }
    | { kind: 'ambiguous'; matchCount: number }
    | { kind: 'missing' }
  > => {
    const normalizedSku = normalizeIdentityText(originalSku).toUpperCase();
    if (!normalizedSku) return { kind: 'missing' };
    const normalizedNameEn = normalizeIdentityText(originalNameEn);

    const products = await api
      .get<ProductWithImages[]>(`/api/v2/products?sku=${encodeURIComponent(normalizedSku)}`, {
        cache: 'no-store',
        logError: false,
      })
      .catch(() => null);

    if (!products) return { kind: 'missing' };

    const exactMatches = products.filter(
      (product: ProductWithImages): boolean =>
        typeof product.sku === 'string' && product.sku.trim().toUpperCase() === normalizedSku
    );

    if (exactMatches.length === 1) {
      return { kind: 'resolved', id: exactMatches[0]!.id };
    }

    if (exactMatches.length > 1 && normalizedNameEn) {
      const exactNameMatches = exactMatches.filter(
        (product: ProductWithImages): boolean =>
          typeof product.name_en === 'string' && product.name_en.trim() === normalizedNameEn
      );
      if (exactNameMatches.length === 1) {
        return { kind: 'resolved', id: exactNameMatches[0]!.id };
      }
    }

    if (exactMatches.length > 1) {
      return { kind: 'ambiguous', matchCount: exactMatches.length };
    }

    return { kind: 'missing' };
  };

  return useOfflineMutation(
    async ({
      id,
      data,
      originalSku,
      originalNameEn,
    }: IdDataDto<Partial<ProductWithImages> | FormData> & {
      originalSku?: string | null;
      originalNameEn?: string | null;
    }): Promise<ProductWithImages> => {
      if (data instanceof FormData) {
        const putProductFormData = async (
          targetId: string,
          formData: FormData
        ): Promise<Response> => {
          const controller = new AbortController();
          const timeoutId = setTimeout(() => controller.abort(), PRODUCT_UPDATE_FORM_TIMEOUT_MS);
          try {
            return await fetch(`/api/v2/products/${targetId}`, {
              method: 'PUT',
              body: formData,
              headers: withCsrfHeaders(),
              credentials: 'same-origin',
              signal: controller.signal,
            });
          } catch (error) {
            logClientError(error);
            if (controller.signal.aborted) {
              throw new Error(`Request timeout after ${PRODUCT_UPDATE_FORM_TIMEOUT_MS}ms`, {
                cause: error,
              });
            }
            throw error;
          } finally {
            clearTimeout(timeoutId);
          }
        };

        let targetId = id;
        let response = await putProductFormData(targetId, data);

        if (response.status === 404) {
          const resolution = await resolveProductIdByIdentity(originalSku, originalNameEn);
          if (resolution.kind === 'resolved' && resolution.id !== targetId) {
            targetId = resolution.id;
            response = await putProductFormData(targetId, data);
          } else if (resolution.kind === 'ambiguous') {
            throw notFoundError(
              `Product not found. The opened product id is stale, and SKU ${normalizeIdentityText(originalSku) || 'this product'} matches ${resolution.matchCount} products. Refresh the products list and reopen the correct product.`
            );
          }
        }

        if (!response.ok) {
          if (response.status === 404) {
            throw notFoundError(
              'Product not found. It may have been moved or deleted. Refresh the product list and try again.'
            );
          }
          throw badRequestError(await parseUpdateError(response));
        }
        return response.json() as Promise<ProductWithImages>;
      }
      return updateProduct(id, data);
    },
    {
      queryKey: QUERY_KEYS.products.lists(),
      skipBaseInvalidation: true,
      extraInvalidateKeys: (variables) => [
        QUERY_KEYS.products.counts(),
        QUERY_KEYS.products.detail(variables.id),
      ],
      meta: {
        source: 'products.hooks.useUpdateProductMutation',
        operation: 'update',
        resource: 'products',
        domain: 'products',
        tags: ['products', 'update'],
      },
      invalidate: (queryClient, savedProduct) => {
        void invalidateProductTitleTerms(queryClient);
        if (!savedProduct) return;
        refreshUpdatedProductCaches(queryClient, savedProduct);
      },
      queuedMessage: 'Product update queued in runtime queue.',
      processedMessage: 'Queued product update completed.',
      onQueued: (variables: {
        id: string;
        data: Partial<ProductWithImages> | FormData;
        originalSku?: string | null;
        originalNameEn?: string | null;
      }) => addQueuedProductSource(variables.id, PRODUCT_UPDATE_QUEUE_SOURCE),
      onProcessed: (
        variables: {
          id: string;
          data: Partial<ProductWithImages> | FormData;
          originalSku?: string | null;
          originalNameEn?: string | null;
        },
        { queryClient }
      ) => {
        removeQueuedProductSource(variables.id, PRODUCT_UPDATE_QUEUE_SOURCE);
        void invalidateProductsAndCounts(queryClient);
        void invalidateProductTitleTerms(queryClient);
        void queryClient.invalidateQueries({
          queryKey: getProductDetailQueryKey(variables.id),
        });
        void queryClient.invalidateQueries({
          queryKey: QUERY_KEYS.products.detailEdit(variables.id),
        });
        void queryClient.invalidateQueries({
          queryKey: QUERY_KEYS.products.validatorLatestProductSource(),
        });
      },
      onFailed: (variables: {
        id: string;
        data: Partial<ProductWithImages> | FormData;
        originalSku?: string | null;
        originalNameEn?: string | null;
      }) => removeQueuedProductSource(variables.id, PRODUCT_UPDATE_QUEUE_SOURCE),
    }
  );
}

export function useDuplicateProductMutation(): UseMutationResult<
  ProductWithImages | null,
  Error,
  { id: string; sku: string },
  unknown
> {
  return useOfflineMutation(
    async ({ id, sku }: { id: string; sku: string }): Promise<ProductWithImages> =>
      await api.post<ProductWithImages>(`/api/v2/products/${id}/duplicate`, { sku }),
    {
      queryKey: productsAllQueryKey,
      meta: {
        source: 'products.hooks.useDuplicateProductMutation',
        operation: 'create',
        resource: 'products.duplicate',
        domain: 'products',
        tags: ['products', 'duplicate'],
      },
      extraInvalidateKeys: [productsCountsQueryKey],
      invalidate: async (queryClient) => {
        await Promise.all([
          invalidateProductsAndCounts(queryClient),
          invalidateProductTitleTerms(queryClient),
        ]);
      },
      queuedMessage: 'Product duplication queued in runtime queue.',
      processedMessage: 'Queued product duplication completed.',
    }
  );
}

export function useBulkDeleteProductsMutation(): UseMutationResult<
  { success: boolean } | null,
  Error,
  string[],
  unknown
> {
  return useOfflineMutation(
    async (ids: string[]): Promise<{ success: boolean }> => {
      const responses = await Promise.all(ids.map((id: string) => deleteProduct(id)));
      if (responses.some((r: { success: boolean }) => !r.success)) {
        throw operationFailedError('Failed to delete some products');
      }
      return { success: true };
    },
    {
      queryKey: productsAllQueryKey,
      meta: {
        source: 'products.hooks.useBulkDeleteProductsMutation',
        operation: 'delete',
        resource: 'products.bulk',
        domain: 'products',
        tags: ['products', 'bulk-delete'],
      },
      extraInvalidateKeys: [productsCountsQueryKey],
      queuedMessage: 'Product deletion queued in runtime queue.',
      processedMessage: 'Queued product deletion completed.',
      onQueued: (ids: string[]) => {
        ids.forEach((id: string) => addQueuedProductSource(id, PRODUCT_DELETE_QUEUE_SOURCE));
      },
      onProcessed: (ids: string[], { queryClient }) => {
        ids.forEach((id: string) => removeQueuedProductSource(id, PRODUCT_DELETE_QUEUE_SOURCE));
        void Promise.all([
          invalidateProductsAndCounts(queryClient),
          invalidateProductTitleTerms(queryClient),
        ]);
      },
      onFailed: (ids: string[]) => {
        ids.forEach((id: string) => removeQueuedProductSource(id, PRODUCT_DELETE_QUEUE_SOURCE));
      },
    }
  );
}

'use client';

// useProductFormValidator: integrates product validation engine with the
// product form. Responsibilities:
// - Wire validator settings and decisions, manage accept/deny flow
// - Provide helpers to accept/deny issues and apply auto-accept rules
// - Coordinate server-side validation mutations and optimistic formatting
// Keep client runtime directive; validator hooks rely on react-hook-form context.

import { useCallback, useEffect, useMemo, useRef, useState, type SetStateAction } from 'react';
import { useFormContext } from 'react-hook-form';

import * as productsApi from '@/features/products/api/products';
import { useProductFormCore } from '@/features/products/context/ProductFormCoreContext';
import { useProductFormMetadata } from '@/features/products/context/ProductFormMetadataContext';
import {
  applyValidatorFieldReplacement,
  doesValidatorFieldReplacementMatchCurrentValue,
} from '@/features/products/lib/applyValidatorFieldReplacement';
import { buildProductValidationSourceValues } from '@/features/products/lib/validatorSourceFields';
import { getProductValidationFieldChangedAtDependencies } from '@/features/products/lib/validatorTargetAdapters';
import { useProductValidatorIssues } from '@/features/products/hooks/useProductValidatorIssues';
import { isPatternConfiguredForFormatterAutoApply } from '@/features/products/validation-engine/core';
import type { ProductValidationDenyBehavior, ProductValidationInstanceScope, ProductValidationPattern, ProductValidationAcceptIssueInput, ProductValidationDenyIssueInput } from '@/shared/contracts/products/validation';
import type { ProductFormData } from '@/shared/contracts/products/drafts';
import { api } from '@/shared/lib/api-client';
import { parseDynamicReplacementRecipe } from '@/shared/lib/products/utils/validator-replacement-recipe';
import { createListQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import type { FieldValidatorIssue } from '../validation-engine/core';
import { useProductFormValidatorSettings } from './validator/useProductFormValidatorSettings';
import { useProductValidationDecisions } from './validator/useProductValidationDecisions';
import {
  getOrCreateAutoAcceptedSet,
  clearAutoAcceptedForEntity,
} from './validator/validator-auto-accept-registry';
import { resolveLatestProductValidatorSourceValues } from './validator/validator-utils';

export interface UseProductFormValidatorResult {
  validationInstanceScope: ProductValidationInstanceScope;
  validatorEnabled: boolean;
  formatterEnabled: boolean;
  setValidatorEnabled: (enabled: SetStateAction<boolean>) => void;
  setFormatterEnabled: (enabled: SetStateAction<boolean>) => void;
  validationDenyBehavior: ProductValidationDenyBehavior;
  setValidationDenyBehavior: (behavior: ProductValidationDenyBehavior) => void;
  denyActionLabel: 'Deny' | 'Mute';
  getDenyActionLabel: (patternId: string) => 'Deny' | 'Mute';
  isIssueDenied: (fieldName: string, patternId: string) => boolean;
  denyIssue: (input: ProductValidationDenyIssueInput) => Promise<void>;
  isIssueAccepted: (fieldName: string, patternId: string) => boolean;
  acceptIssue: (input: ProductValidationAcceptIssueInput) => Promise<void>;
  validatorPatterns: ProductValidationPattern[];
  latestProductValues: Record<string, unknown> | null;
  visibleFieldIssues: Record<string, FieldValidatorIssue[]>;
  setValidatorManuallyChanged: (changed: boolean) => void;
}

export function useProductFormValidator(
  scopeOverride?: string,
  validatorSessionKey?: string
): UseProductFormValidatorResult {
  const { product, draft } = useProductFormCore();
  const {
    categories,
    producers,
    selectedCategoryId,
    selectedCatalogIds,
    selectedProducerIds,
    setCategoryId,
    setProducerIds,
  } = useProductFormMetadata();
  const { watch, getValues, setValue } = useFormContext<ProductFormData>();

  const settings = useProductFormValidatorSettings();
  const {
    validatorEnabled,
    formatterEnabled,
    setValidatorEnabled,
    setFormatterEnabled,
    setValidatorEnabledState,
    setFormatterEnabledState,
    setValidatorInitialized,
    setValidatorManuallyChanged,
    validatorManuallyChangedRef,
    configEnabledByDefault,
    defaultValidatorEnabled,
    defaultFormatterEnabled,
    validatorConfigQuery,
  } = settings;

  const entityIdentity = `${product?.id?.trim() ?? ''}::${draft?.id?.trim() ?? ''}::${validatorSessionKey ?? ''}`;
  const lastEntityIdentityRef = useRef<string>(entityIdentity);

  const watchFields = watch([
    'name_en', 'name_pl', 'name_de', 'description_en', 'description_pl', 'description_de',
    'sku', 'price', 'stock', 'weight', 'sizeLength', 'sizeWidth', 'length',
    'supplierName', 'supplierLink', 'priceComment', 'categoryId',
  ]);

  const [draftValidationInstanceId] = useState<string>(() =>
    typeof globalThis.crypto !== 'undefined' && typeof globalThis.crypto.randomUUID === 'function'
      ? globalThis.crypto.randomUUID()
      : `draft-validation-${Date.now().toString(36)}`
  );

  const [productCreateValidationInstanceId] = useState<string>(() =>
    typeof globalThis.crypto !== 'undefined' && typeof globalThis.crypto.randomUUID === 'function'
      ? globalThis.crypto.randomUUID()
      : `product-create-validation-${Date.now().toString(36)}`
  );

  const validationInstanceScope = useMemo((): ProductValidationInstanceScope => {
    if (scopeOverride) return scopeOverride as ProductValidationInstanceScope;
    if (product?.id?.trim()) return 'product_edit';
    if (draft?.id?.trim()) return 'draft_template';
    return 'product_create';
  }, [draft?.id, product?.id, scopeOverride]);

  const validatorPatterns = validatorConfigQuery.data?.patterns ?? [];

  const decisions = useProductValidationDecisions(
    validationInstanceScope,
    validatorConfigQuery.data?.instanceDenyBehavior ?? null,
    validatorPatterns,
    product?.id ?? null,
    draft?.id ?? null
  );

  const {
    deniedIssueKeys,
    setDeniedIssueKeys,
    acceptedIssueKeys,
    setAcceptedIssueKeys,
    validationSessionId,
    effectiveValidationDenyBehavior,
    setValidationDenyBehavior,
    getIssueDenyBehavior,
  } = decisions;

  const validatorPatternById = useMemo(
    () => new Map<string, ProductValidationPattern>(validatorPatterns.map((p) => [p.id, p])),
    [validatorPatterns]
  );

  const validatorValues = useMemo(
    (): Record<string, unknown> =>
      buildProductValidationSourceValues({
        baseValues: {
          name_en: watchFields[0], name_pl: watchFields[1], name_de: watchFields[2],
          description_en: watchFields[3], description_pl: watchFields[4], description_de: watchFields[5],
          sku: watchFields[6], price: watchFields[7], stock: watchFields[8], weight: watchFields[9],
          sizeLength: watchFields[10], sizeWidth: watchFields[11], length: watchFields[12],
          supplierName: watchFields[13], supplierLink: watchFields[14], priceComment: watchFields[15],
          categoryId: (watchFields[16] as string) ?? '',
        },
        categories,
        producers,
        selectedCategoryId,
        selectedCatalogIds,
        selectedProducerIds,
        fallbackCatalogId: product?.catalogId ?? '',
      }),
    [
      watchFields,
      categories,
      producers,
      selectedCategoryId,
      selectedCatalogIds,
      selectedProducerIds,
      product?.catalogId,
    ]
  );

  const needsLatestProductSource = useMemo(
    () =>
      validatorPatterns.some((pattern: ProductValidationPattern) => {
        const recipe = parseDynamicReplacementRecipe(pattern.replacementValue);
        return recipe?.sourceMode === 'latest_product_field' || (pattern.launchEnabled && pattern.launchSourceMode === 'latest_product_field');
      }),
    [validatorPatterns]
  );

  const latestProductsQueryKey = QUERY_KEYS.products.validatorLatestProductSource();
  const latestProductsQuery = createListQueryV2({
    queryKey: latestProductsQueryKey,
    queryFn: () => productsApi.getProducts({ page: 1, pageSize: 2 }, undefined, { fresh: true }),
    enabled: validatorEnabled && needsLatestProductSource,
    staleTime: 0,
    meta: {
      source: 'products.hooks.useProductFormValidator',
      operation: 'list',
      resource: 'products.validator.latest-product-source',
      domain: 'products',
      queryKey: latestProductsQueryKey,
      tags: ['products', 'validator', 'latest-product-source'],
      description: 'Loads products validator latest product source.',
    },
  });

  const latestProductValues = useMemo(
    (): Record<string, unknown> | null =>
      resolveLatestProductValidatorSourceValues({
        products: latestProductsQuery.data,
        currentProductId: product?.id ?? null,
        isFetching: latestProductsQuery.isFetching,
      }),
    [latestProductsQuery.data, latestProductsQuery.isFetching, product?.id]
  );

  useEffect(() => {
    if (lastEntityIdentityRef.current === entityIdentity) return;
    const prevIdentity = lastEntityIdentityRef.current;
    lastEntityIdentityRef.current = entityIdentity;
    if (prevIdentity) clearAutoAcceptedForEntity(prevIdentity);
    // Only reset to config default if the user has NOT manually changed the setting.
    // When the user explicitly toggles validation (e.g. turns it off), that preference
    // is saved globally via the mutation. Resetting here before the query refetches
    // would clobber their choice — most visibly when a draft auto-saves and gets an id,
    // causing entityIdentity to change mid-session.
    if (!validatorManuallyChangedRef.current) {
      setValidatorEnabledState(defaultValidatorEnabled);
      setFormatterEnabledState(defaultFormatterEnabled);
    }
    setValidatorInitialized(typeof configEnabledByDefault === 'boolean');
    setValidatorManuallyChanged(false);
  }, [configEnabledByDefault, defaultFormatterEnabled, defaultValidatorEnabled, entityIdentity, setFormatterEnabledState, setValidatorEnabledState, setValidatorInitialized, setValidatorManuallyChanged, validatorManuallyChangedRef]);

  const validationScopeKey = useMemo((): string => {
    if (validationInstanceScope === 'product_edit' && product?.id?.trim()) return `product:${product.id.trim()}`;
    if (validationInstanceScope === 'draft_template') return `draft-instance:${draft?.id?.trim() ?? 'draft'}:${draftValidationInstanceId}`;
    return `product-create-instance:${productCreateValidationInstanceId}`;
  }, [product?.id, draft?.id, draftValidationInstanceId, productCreateValidationInstanceId, validationInstanceScope]);

  const buildIssueDecisionKey = useCallback(
    (fieldName: string, patternId: string): string => `${validationScopeKey}::${fieldName}::${patternId}`,
    [validationScopeKey]
  );

  useEffect(() => {
    if (validationInstanceScope !== 'product_create' && validationInstanceScope !== 'draft_template') return;
    const scopePrefix = `${validationScopeKey}::`;
    setDeniedIssueKeys((prev) => {
      const next = new Set<string>();
      let changed = false;
      for (const key of prev) { if (key.startsWith(scopePrefix)) { changed = true; continue; } next.add(key); }
      return changed ? next : prev;
    });
    setAcceptedIssueKeys((prev) => {
      const next = new Set<string>();
      let changed = false;
      for (const key of prev) { if (key.startsWith(scopePrefix)) { changed = true; continue; } next.add(key); }
      return changed ? next : prev;
    });
  }, [setAcceptedIssueKeys, setDeniedIssueKeys, validationInstanceScope, validationScopeKey]);

  const getDenyActionLabel = useCallback((patternId: string): 'Deny' | 'Mute' => getIssueDenyBehavior(patternId) === 'mute_session' ? 'Mute' : 'Deny', [getIssueDenyBehavior]);
  const isIssueDenied = useCallback((fieldName: string, patternId: string): boolean => deniedIssueKeys.has(buildIssueDecisionKey(fieldName, patternId)), [buildIssueDecisionKey, deniedIssueKeys]);
  const isIssueAccepted = useCallback((fieldName: string, patternId: string): boolean => acceptedIssueKeys.has(buildIssueDecisionKey(fieldName, patternId)), [acceptedIssueKeys, buildIssueDecisionKey]);

  const { visibleFieldIssues } = useProductValidatorIssues({
    values: validatorValues, runtimeValues: validatorValues, patterns: validatorPatterns, latestProductValues,
    categories, validationScope: validationInstanceScope, validatorEnabled, isIssueDenied, isIssueAccepted,
    resolveChangedAt: (fieldName, timestamps) => getProductValidationFieldChangedAtDependencies(fieldName).reduce((max, dep) => Math.max(max, timestamps[dep] ?? 0), 0),
    source: 'ProductForm',
  });

  const denyIssue = useCallback(async (input: ProductValidationDenyIssueInput): Promise<void> => {
    const patternId = (input.patternId || '').trim();
    const fieldName = (input.fieldName || '').trim();
    if (!patternId || !fieldName) return;
    const issueKey = buildIssueDecisionKey(fieldName, patternId);
    const issueDenyBehavior = getIssueDenyBehavior(patternId);
    if (issueDenyBehavior === 'mute_session') setDeniedIssueKeys((prev) => prev.has(issueKey) ? prev : new Set(prev).add(issueKey));
    void api.post('/api/v2/products/validator-decisions', { action: 'deny', productId: product?.id ?? null, draftId: draft?.id ?? null, patternId, fieldName, denyBehavior: issueDenyBehavior, message: input.message ?? null, replacementValue: input.replacementValue ?? null, sessionId: validationSessionId || null }, { logError: false }).catch(err => logClientError(err));
  }, [buildIssueDecisionKey, draft?.id, getIssueDenyBehavior, product?.id, setDeniedIssueKeys, validationSessionId]);

  const acceptIssue = useCallback(async (input: ProductValidationAcceptIssueInput): Promise<void> => {
    const patternId = (input.patternId || '').trim();
    const fieldName = (input.fieldName || '').trim();
    if (!patternId || !fieldName) return;
    const issueKey = buildIssueDecisionKey(fieldName, patternId);
    const shouldMute = input.postAcceptBehavior === 'stop_after_accept';
    setAcceptedIssueKeys((prev) => shouldMute ? (prev.has(issueKey) ? prev : new Set(prev).add(issueKey)) : (prev.has(issueKey) ? (()=>{const n=new Set(prev); n.delete(issueKey); return n;})() : prev));
    void api.post('/api/v2/products/validator-decisions', { action: 'accept', productId: product?.id ?? null, draftId: draft?.id ?? null, patternId, fieldName, denyBehavior: null, message: input.message ?? null, replacementValue: input.replacementValue ?? null, sessionId: validationSessionId || null }, { logError: false }).catch(err => logClientError(err));
  }, [buildIssueDecisionKey, draft?.id, product?.id, setAcceptedIssueKeys, validationSessionId]);

  const applyAutoReplacementToField = useCallback(
    (fieldName: string, val: string) =>
      applyValidatorFieldReplacement({
        fieldName,
        replacementValue: val,
        categories,
        producers,
        getCurrentFieldValue: (nextFieldName) =>
          nextFieldName === 'producerIds' ? selectedProducerIds : getValues(nextFieldName),
        setFormFieldValue: (nextFieldName, nextValue) =>
          setValue(nextFieldName, nextValue, { shouldDirty: true, shouldTouch: true }),
        setCategoryId,
        setProducerIds,
      }),
    [categories, getValues, producers, selectedProducerIds, setCategoryId, setProducerIds, setValue]
  );
  const doesAutoReplacementMatchField = useCallback(
    (fieldName: string, val: string) =>
      doesValidatorFieldReplacementMatchCurrentValue({
        fieldName,
        replacementValue: val,
        categories,
        producers,
        getCurrentFieldValue: (nextFieldName) =>
          nextFieldName === 'producerIds' ? selectedProducerIds : getValues(nextFieldName),
        setFormFieldValue: () => {},
        setCategoryId: () => {},
        setProducerIds: () => {},
      }),
    [categories, getValues, producers, selectedProducerIds]
  );

  const autoAcceptTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const autoAcceptedIssueKeysRef = useRef<Set<string>>(getOrCreateAutoAcceptedSet(entityIdentity));
  useEffect(() => { autoAcceptedIssueKeysRef.current = getOrCreateAutoAcceptedSet(entityIdentity); }, [entityIdentity]);

  useEffect(() => {
    if (!validatorEnabled || !formatterEnabled) { if (autoAcceptTimerRef.current) { clearTimeout(autoAcceptTimerRef.current); autoAcceptTimerRef.current = null; } if (autoAcceptedIssueKeysRef.current.size > 0) autoAcceptedIssueKeysRef.current.clear(); return; }
    if (autoAcceptTimerRef.current) clearTimeout(autoAcceptTimerRef.current);
    autoAcceptTimerRef.current = setTimeout(() => {
      autoAcceptTimerRef.current = null;
      const nextVisibleIssueKeys = new Set<string>();
      interface PendingAccept {
        fieldName: string;
        patternId: string;
        postAcceptBehavior: string | null | undefined;
        message: string;
        replacementValue: string | null | undefined;
        issueKey: string;
      }
      const pendingAccepts: PendingAccept[] = [];
      for (const [fieldName, issues] of Object.entries(visibleFieldIssues)) {
        for (const issue of issues) {
          const issueKey = buildIssueDecisionKey(fieldName, issue.patternId);
          nextVisibleIssueKeys.add(issueKey);
          const pattern = validatorPatternById.get(issue.patternId);
          const shouldAutoApply = pattern && isPatternConfiguredForFormatterAutoApply({ pattern, fieldName, validationScope: validationInstanceScope }) && typeof issue.replacementValue === 'string' && issue.replacementValue.trim().length > 0;
          if (autoAcceptedIssueKeysRef.current.has(issueKey)) { if (shouldAutoApply && !doesAutoReplacementMatchField(fieldName, issue.replacementValue ?? '')) autoAcceptedIssueKeysRef.current.delete(issueKey); else continue; }
          if (shouldAutoApply) { if (!applyAutoReplacementToField(fieldName, issue.replacementValue ?? '')) continue; }
          pendingAccepts.push({ fieldName, patternId: issue.patternId, postAcceptBehavior: issue.postAcceptBehavior, message: issue.message, replacementValue: issue.replacementValue, issueKey });
          autoAcceptedIssueKeysRef.current.add(issueKey);
        }
      }
      if (pendingAccepts.length > 0) {
        setAcceptedIssueKeys((prev) => { const next = new Set(prev); for (const a of pendingAccepts) if (a.postAcceptBehavior === 'stop_after_accept') next.add(a.issueKey); return next; });
        void api.post('/api/v2/products/validator-decisions/batch', { decisions: pendingAccepts.map((a: PendingAccept) => ({ action: 'accept', productId: product?.id ?? null, draftId: draft?.id ?? null, patternId: a.patternId, fieldName: a.fieldName, denyBehavior: null, message: a.message ?? null, replacementValue: a.replacementValue ?? null, sessionId: validationSessionId || null })) }, { logError: false }).catch(err => logClientError(err));
      }
      const staleKeys: string[] = [];
      for (const k of autoAcceptedIssueKeysRef.current) if (!nextVisibleIssueKeys.has(k)) staleKeys.push(k);
      staleKeys.forEach(k => autoAcceptedIssueKeysRef.current.delete(k));
    }, 200);
    return () => { if (autoAcceptTimerRef.current) clearTimeout(autoAcceptTimerRef.current); };
  }, [applyAutoReplacementToField, buildIssueDecisionKey, doesAutoReplacementMatchField, draft?.id, formatterEnabled, product?.id, setAcceptedIssueKeys, validationSessionId, validationInstanceScope, validatorPatternById, validatorEnabled, visibleFieldIssues]);

  return {
    validationInstanceScope, validatorEnabled, formatterEnabled, setValidatorEnabled, setFormatterEnabled,
    validationDenyBehavior: effectiveValidationDenyBehavior, setValidationDenyBehavior,
    denyActionLabel: effectiveValidationDenyBehavior === 'mute_session' ? 'Mute' : 'Deny',
    getDenyActionLabel, isIssueDenied, denyIssue, isIssueAccepted, acceptIssue,
    validatorPatterns, latestProductValues, visibleFieldIssues, setValidatorManuallyChanged,
  };
}

'use client';
'use no memo';
// useProductListState: composition hook that builds the ProductListProvider
// value. Responsibilities:
// - Orchestrates data hooks (useProductData), user preferences, background
//   sync, integrations, and row-runtime subscriptions.
// - Defers heavy initialization (draft bootstrap and row runtime readiness)
//   to a deferred effect so initial rendering remains snappy.
// - Exposes memoized callbacks and stable values for pagination, filtering,
//   selection and modal operations consumed by the ProductListProvider.
// - Reports debug telemetry when debug mode is enabled and keeps effects
//   localized to minimize cross-cutting re-renders.

// Note: keep 'use no memo' directive present — it is used as a runtime hint
// for development tooling and should not be removed without verifying callers.

