const toTrimmedString = (value: unknown): string => {
  if (typeof value !== 'string') return '';
  return value.trim();
};

const normalizeSelectionIds = (values: ReadonlyArray<unknown>): string[] => {
  const unique = new Set<string>();
  for (const value of values) {
    const normalizedValue = toTrimmedString(value);
    if (!normalizedValue) continue;
    unique.add(normalizedValue);
  }
  return Array.from(unique);
};

const normalizeCatalogIdList = (values: ReadonlyArray<unknown>): string[] => {
  const resolveCatalogId = (value: unknown): string => {
    if (typeof value === 'string') {
      return toTrimmedString(value);
    }
    if (value === null || value === undefined || typeof value !== 'object') return '';
    const record = value as Record<string, unknown>;
    const direct =
      toTrimmedString(record['catalogId']) ||
      toTrimmedString(record['catalog_id']) ||
      toTrimmedString(record['id']) ||
      toTrimmedString(record['value']);
    if (direct !== '') return direct;

    const nestedCatalog = record['catalog'];
    if (nestedCatalog === null || nestedCatalog === undefined || typeof nestedCatalog !== 'object') return '';
    const nestedRecord = nestedCatalog as Record<string, unknown>;
    const nestedId = toTrimmedString(nestedRecord['id']) ||
      toTrimmedString(nestedRecord['catalogId']) ||
      toTrimmedString(nestedRecord['catalog_id']);
    return nestedId;
  };

  const unique = new Set<string>();
  for (const value of values) {
    const trimmed = resolveCatalogId(value);
    if (trimmed === '') continue;
    unique.add(trimmed);
  }
  return Array.from(unique);
};

const CATALOG_ID_KEY_SEPARATOR = '\u001f';

const resolveCategoryIdFromProduct = (product?: ProductWithImages): string | null => {
  if (product === undefined || product === null) return null;
  const direct = toTrimmedString(product.categoryId);
  if (direct !== '') return direct;
  return null;
};

// Composite hook that combines all metadata functionality
export function useProductMetadata({
  product,
  initialCatalogId,
  initialCatalogIds,
  initialCategoryId,
  initialTagIds,
  initialProducerIds,
}: UseProductMetadataProps): ProductMetadataHookResult {
  const catalogsQuery = useCatalogs();
  const languagesQuery = useLanguages();
  const priceGroupsQuery = usePriceGroups();
  const producersQuery = useProducers();
  const initialCatalogIdsKey = normalizeCatalogIdList(initialCatalogIds ?? []).join(
    CATALOG_ID_KEY_SEPARATOR
  );
  // Initialize selections based on product or initial values
  const initialCatalogSelection = React.useMemo((): string[] => {
    if (product !== undefined && product !== null) {
      const productCatalogIds = Array.isArray(product.catalogs)
        ? normalizeCatalogIdList(product.catalogs)
        : [];
      if (productCatalogIds.length > 0) {
        return productCatalogIds;
      }
      const fallbackCatalogId =
        typeof product.catalogId === 'string' ? product.catalogId.trim() : '';
      if (fallbackCatalogId !== '') {
        return [fallbackCatalogId];
      }
    }
    const normalizedInitialCatalogIds =
      initialCatalogIdsKey === ''
        ? []
        : initialCatalogIdsKey.split(CATALOG_ID_KEY_SEPARATOR).filter(Boolean);
    if (normalizedInitialCatalogIds.length > 0) {
      return normalizedInitialCatalogIds;
    }
    const fallbackInitialCatalogId =
      typeof initialCatalogId === 'string' ? initialCatalogId.trim() : '';
    if (fallbackInitialCatalogId !== '') {
      return [fallbackInitialCatalogId];
    }
    return [];
  }, [product, initialCatalogIdsKey, initialCatalogId]);

  const initialCategorySelection = React.useMemo((): string | null => {
    const resolvedProductCategoryId = resolveCategoryIdFromProduct(product);
    if (resolvedProductCategoryId !== null) {
      return resolvedProductCategoryId;
    }
    if (initialCategoryId !== null && initialCategoryId !== undefined && initialCategoryId !== '') {
      return initialCategoryId;
    }
    return null;
  }, [product, initialCategoryId]);

  const initialTagSelection = React.useMemo((): string[] => {
    if (product?.tags !== undefined && product.tags !== null) {
      return product.tags.map((t: { tagId: string }) => t.tagId);
    }
    return initialTagIds ?? [];
  }, [product, initialTagIds]);

  const initialProducerSelection = React.useMemo((): string[] => {
    if (product?.producers !== undefined && product.producers !== null) {
      return normalizeSelectionIds(
        product.producers.map((p: { producerId: string }) => p.producerId)
      );
    }
    if (initialProducerIds !== undefined && initialProducerIds !== null && initialProducerIds.length > 0) {
      return normalizeSelectionIds(initialProducerIds);
    }
    return [];
  }, [product, initialProducerIds]);

  const [selectedCatalogIds, setSelectedCatalogIds] =
    React.useState<string[]>(initialCatalogSelection);
  const [selectedCategoryId, setSelectedCategoryId] = React.useState<string | null>(
    initialCategorySelection
  );
  const [selectedTagIds, setSelectedTagIds] = React.useState<string[]>(initialTagSelection);
  const [selectedProducerIds, setSelectedProducerIds] =
    React.useState<string[]>(initialProducerSelection);

  const arraysEqual = (a: string[], b: string[]): boolean =>
    a.length === b.length && a.every((value: string, index: number) => value === b[index]);

  React.useEffect(() => {
    setSelectedCatalogIds((prev: string[]) =>
      arraysEqual(prev, initialCatalogSelection) ? prev : initialCatalogSelection
    );
  }, [initialCatalogSelection]);

  React.useEffect(() => {
    setSelectedCategoryId((prev: string | null) =>
      prev === initialCategorySelection ? prev : initialCategorySelection
    );
  }, [initialCategorySelection]);

  React.useEffect(() => {
    setSelectedTagIds((prev: string[]) =>
      arraysEqual(prev, initialTagSelection) ? prev : initialTagSelection
    );
  }, [initialTagSelection]);

  React.useEffect(() => {
    setSelectedProducerIds((prev: string[]) =>
      arraysEqual(prev, initialProducerSelection) ? prev : initialProducerSelection
    );
  }, [initialProducerSelection]);

  const primaryCatalogId = selectedCatalogIds[0] ?? '';
  const categoriesQuery = useCategoriesForCatalogs(selectedCatalogIds);
  const shippingGroupsQuery = useShippingGroups(primaryCatalogId);
  const tagsQuery = useTags(primaryCatalogId);
  const parametersQuery = useParameters(primaryCatalogId);
  const categories = categoriesQuery.data ?? [];
  const isSelectedCategoryInPrimaryCatalog = React.useMemo((): boolean => {
    if (selectedCategoryId === null) return true;
    return categories.some((category: ProductCategory) => category.id === selectedCategoryId);
  }, [categories, selectedCategoryId]);
  const attemptedCategoryCatalogResolutionsRef = React.useRef<Set<string>>(new Set());

  React.useEffect(() => {
    attemptedCategoryCatalogResolutionsRef.current.clear();
  }, [initialCategorySelection, product?.id]);

  React.useEffect(() => {
    if ((product?.id ?? null) === null) return;
    if (selectedCategoryId === null) return;
    if (selectedCategoryId !== initialCategorySelection) return;
    if (arraysEqual(selectedCatalogIds, initialCatalogSelection) === false) return;
    if (categoriesQuery.isLoading === true) return;
    if (isSelectedCategoryInPrimaryCatalog === true) return;

    const resolutionKey = `${selectedCategoryId}:${primaryCatalogId !== '' ? primaryCatalogId : 'none'}`;
    if (attemptedCategoryCatalogResolutionsRef.current.has(resolutionKey)) return;
    attemptedCategoryCatalogResolutionsRef.current.add(resolutionKey);

    let cancelled = false;
    void api
      .get<ProductCategory>(
        `/api/v2/products/categories/${encodeURIComponent(selectedCategoryId)}`,
        {
          logError: false,
        }
      )
      .then((category: ProductCategory) => {
        if (cancelled === true) return;
        const categoryCatalogId =
          typeof category?.catalogId === 'string' ? category.catalogId.trim() : '';
        if (categoryCatalogId === '') return;
        setSelectedCatalogIds((prev: string[]) => {
          if (prev[0] === categoryCatalogId) return prev;
          const withoutCurrent = prev.filter((id: string) => id !== categoryCatalogId);
          return [categoryCatalogId, ...withoutCurrent];
        });
      })
      .catch(() => {
        // Best effort fallback only.
      });

    return () => {
      cancelled = true;
    };
  }, [
    categoriesQuery.isLoading,
    initialCatalogSelection,
    initialCategorySelection,
    isSelectedCategoryInPrimaryCatalog,
    primaryCatalogId,
    product?.id,
    selectedCategoryId,
    selectedCatalogIds,
  ]);

  const toggleCatalog = (catalogId: string): void => {
    setSelectedCatalogIds((prev: string[]) =>
      prev.includes(catalogId)
        ? prev.filter((id: string) => id !== catalogId)
        : [...prev, catalogId]
    );
  };

  const setCategoryId = (categoryId: string | null): void => {
    const trimmed = typeof categoryId === 'string' ? categoryId.trim() : '';
    setSelectedCategoryId(trimmed !== '' ? trimmed : null);
    if (trimmed === '') return;

    const categoryCatalogId =
      categories.find((category: ProductCategory) => category.id === trimmed)?.catalogId?.trim() ??
      '';
    if (categoryCatalogId === '') return;

    setSelectedCatalogIds((prev: string[]) => {
      if (prev[0] === categoryCatalogId) return prev;
      const withoutCategoryCatalog = prev.filter((id: string) => id !== categoryCatalogId);
      return [categoryCatalogId, ...withoutCategoryCatalog];
    });
  };

  const toggleTag = (tagId: string): void => {
    setSelectedTagIds((prev: string[]) =>
      prev.includes(tagId) ? prev.filter((id: string) => id !== tagId) : [...prev, tagId]
    );
  };

  const toggleProducer = (producerId: string): void => {
    setSelectedProducerIds((prev: string[]) =>
      prev.includes(producerId)
        ? prev.filter((id: string) => id !== producerId)
        : [...prev, producerId]
    );
  };

  const setProducerIds = (producerIds: string[]): void => {
    setSelectedProducerIds((prev: string[]) => {
      const nextIds = normalizeSelectionIds(producerIds);
      return arraysEqual(prev, nextIds) ? prev : nextIds;
    });
  };

  // Derive filtered languages and price groups based on selected catalogs
  const filteredResult = useMemo(() => {
    const catalogs = catalogsQuery.data ?? [];
    const languages = languagesQuery.data ?? [];
    const priceGroups = priceGroupsQuery.data ?? [];

    if (selectedCatalogIds.length === 0) {
      return {
        filteredLanguages: languages,
        filteredPriceGroups: priceGroups,
      };
    }

    const selectedCatalogs = catalogs.filter((catalog: CatalogRecord) =>
      selectedCatalogIds.includes(catalog.id)
    );
    const languageIdSet = new Set(
      selectedCatalogs.flatMap((catalog: CatalogRecord) => catalog.languageIds ?? [])
    );
    const normalizedLanguageSet = new Set(
      Array.from(languageIdSet).map((value: string) => String(value).trim().toUpperCase())
    );

    const languagesResult = languageIdSet.size > 0
      ? languages.filter((language: Language) => {
        const idKey = String(language.id).trim().toUpperCase();
        const codeKey = String(language.code).trim().toUpperCase();
        return normalizedLanguageSet.has(idKey) || normalizedLanguageSet.has(codeKey);
      })
      : languages;

    const priceGroupIdSet = new Set(
      selectedCatalogs.flatMap((catalog: CatalogRecord) => catalog.priceGroupIds ?? [])
    );
    const priceGroupsResult = priceGroupIdSet.size > 0
      ? priceGroups.filter((group: PriceGroupWithDetails) =>
        Array.from(priceGroupIdSet).some((identifier) =>
          matchesPriceGroupIdentifier(group, identifier)
        )
      )
      : priceGroups;

    return { filteredLanguages: languagesResult, filteredPriceGroups: priceGroupsResult };
  }, [catalogsQuery.data, languagesQuery.data, priceGroupsQuery.data, selectedCatalogIds]);

  const { filteredLanguages, filteredPriceGroups } = filteredResult;

  // Guard: detect "form fields invisible" failure condition.
  // Fires only AFTER both catalog and language queries succeed — never during loading.
  useEffect(() => {
    if ((product?.id ?? null) === null) return;
    if (catalogsQuery.isSuccess === false || languagesQuery.isSuccess === false) return;
    if (selectedCatalogIds.length === 0) return;
    if (filteredLanguages.length > 0) return;
    logClientError(new Error('[ProductForm] filteredLanguages empty after queries resolved'), {
      context: {
        service: 'products',
        category: 'form-guard',
        productId: product!.id,
        isHydrated: isEditingProductHydrated(product),
        selectedCatalogIds,
        catalogsCount: catalogsQuery.data?.length ?? 0,
        languagesCount: languagesQuery.data?.length ?? 0,
      },
    });
  }, [
    product,
    catalogsQuery.isSuccess,
    catalogsQuery.data,
    languagesQuery.isSuccess,
    languagesQuery.data,
    selectedCatalogIds,
    filteredLanguages,
  ]);

  return {
    catalogs: catalogsQuery.data ?? [],
    catalogsLoading: catalogsQuery.isLoading,
    catalogsError: ((catalogsQuery.error ?? null) !== null) ? (catalogsQuery.error as Error).message : null,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading: categoriesQuery.isLoading,
    selectedCategoryId,
    setCategoryId,
    shippingGroups: shippingGroupsQuery.data ?? [],
    shippingGroupsLoading: shippingGroupsQuery.isLoading,
    tags: tagsQuery.data ?? [],
    tagsLoading: tagsQuery.isLoading,
    selectedTagIds,
    toggleTag,
    producers: producersQuery.data ?? [],
    producersLoading: producersQuery.isLoading,
    selectedProducerIds,
    setProducerIds,
    toggleProducer,
    parameters: parametersQuery.data ?? [],
    parametersLoading: parametersQuery.isLoading,
    filteredLanguages,
    filteredPriceGroups,
  };
}

'use client';
'use no memo';
// User preferences for product list: reads persisted preferences (server +
// localStorage), exposes stable setters that persist via offline mutation
// helpers and update localStorage for responsive UI.

import { type UseMutationResult } from '@tanstack/react-query';
import { useCallback, useState } from 'react';

// React Compiler currently miscompiles this hook stack in dev when it wraps
// TanStack Query + offline mutation helpers, producing useMemoCache size
// mismatches during Fast Refresh. Keep this hook on the plain runtime path.

import {
  type UserPreferencesResponse,
  userPreferencesUpdateSchema,
} from '@/shared/contracts/auth';
import type { ProductAdvancedFilterPreset, ProductListPreferences } from '@/shared/contracts/products/filters';
import { productListPreferencesSchema } from '@/shared/contracts/products/filters';
import { useOfflineMutation } from '@/shared/hooks/offline/useOfflineMutation';
import { api, ApiError } from '@/shared/lib/api-client';
import { normalizeProductPageSize } from '@/shared/lib/products/constants';
import { createSingleQueryV2 } from '@/shared/lib/query-factories-v2';
import { invalidateUserPreferences } from '@/shared/lib/query-invalidation';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import {
  normalizeUserPreferencesResponse,
  normalizeUserPreferencesUpdatePayload,
} from '@/shared/validations/user-preferences';

const DEFAULT_PREFERENCES: ProductListPreferences = {
  nameLocale: 'name_en',
  catalogFilter: 'all',
  currencyCode: 'PLN',
  pageSize: 12,
  thumbnailSource: 'file',
  filtersCollapsedByDefault: true,
  showTriggerRunFeedback: true,
  advancedFilterPresets: [],
  appliedAdvancedFilter: '',
  appliedAdvancedFilterPresetId: null,
};

const userPreferencesQueryKey = QUERY_KEYS.userPreferences.all;
const PRODUCT_LIST_NAME_LOCALES = new Set(['name_en', 'name_pl', 'name_de']);
const PRODUCT_LIST_THUMBNAIL_SOURCES = new Set(['file', 'link', 'base64']);

const mapProductListPreferences = (
  data: UserPreferencesResponse | null | undefined
): ProductListPreferences => ({
  nameLocale:
    (data?.productListNameLocale as 'name_en' | 'name_pl' | 'name_de' | null | undefined) ||
    'name_en',
  catalogFilter: data?.productListCatalogFilter || 'all',
  currencyCode: data?.productListCurrencyCode ?? 'PLN',
  pageSize: normalizeProductPageSize(data?.productListPageSize, 12),
  thumbnailSource: data?.productListThumbnailSource || 'file',
  filtersCollapsedByDefault: data?.productListFiltersCollapsedByDefault ?? true,
  showTriggerRunFeedback: data?.productListShowTriggerRunFeedback ?? true,
  advancedFilterPresets: data?.productListAdvancedFilterPresets ?? [],
  appliedAdvancedFilter: data?.productListAppliedAdvancedFilter ?? '',
  appliedAdvancedFilterPresetId: data?.productListAppliedAdvancedFilterPresetId ?? null,
});

async function fetchUserPreferences(signal?: AbortSignal): Promise<UserPreferencesResponse> {
  const data = normalizeUserPreferencesResponse(
    await api.get<UserPreferencesResponse>('/api/user/preferences', { signal })
  );
  return data;
}

async function updateUserPreference(
  key: keyof ProductListPreferences,
  value: unknown
): Promise<void> {
  const apiKey = `productList${key.charAt(0).toUpperCase()}${key.slice(1)}`;
  const validation = userPreferencesUpdateSchema.safeParse({ [apiKey]: value });
  if (!validation.success) {
    throw new ApiError('Invalid user preference update payload.', 400);
  }
  const payload = normalizeUserPreferencesUpdatePayload(validation.data);
  await api.patch('/api/user/preferences', payload);
}

function getProductListPreferenceStorageKey(key: keyof ProductListPreferences): string {
  return `productList${key.charAt(0).toUpperCase()}${key.slice(1)}`;
}

function serializeProductListPreferenceValue(value: unknown): string {
  if (value === null) return 'null';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }
  try {
    return JSON.stringify(value);
  } catch {
    return String(value);
  }
}

function updateLocalStorage(key: keyof ProductListPreferences, value: unknown): void {
  if (typeof window === 'undefined') return;

  window.localStorage.setItem(
    getProductListPreferenceStorageKey(key),
    serializeProductListPreferenceValue(value)
  );
}

function parseStoredBooleanPreference(value: string | null): boolean | undefined {
  if (value == null) return undefined;
  if (value === 'true' || value === '1') return true;
  if (value === 'false' || value === '0') return false;
  return undefined;
}

function parseStoredJsonPreference(value: string | null): unknown {
  if (!value) return undefined;
  try {
    return JSON.parse(value);
  } catch {
    return undefined;
  }
}

function readStoredProductListPreferences(): ProductListPreferences | null {
  if (typeof window === 'undefined') return null;

  const partial: Partial<ProductListPreferences> = {};
  let hasStoredValue = false;

  const nameLocale = window.localStorage.getItem(getProductListPreferenceStorageKey('nameLocale'));
  if (nameLocale != null) {
    hasStoredValue = true;
    if (PRODUCT_LIST_NAME_LOCALES.has(nameLocale)) {
      partial.nameLocale = nameLocale as ProductListPreferences['nameLocale'];
    }
  }

  const catalogFilter = window.localStorage.getItem(
    getProductListPreferenceStorageKey('catalogFilter')
  );
  if (catalogFilter != null) {
    hasStoredValue = true;
    partial.catalogFilter = catalogFilter;
  }

  const currencyCode = window.localStorage.getItem(
    getProductListPreferenceStorageKey('currencyCode')
  );
  if (currencyCode != null) {
    hasStoredValue = true;
    partial.currencyCode = currencyCode === 'null' ? null : currencyCode;
  }

  const pageSize = window.localStorage.getItem(getProductListPreferenceStorageKey('pageSize'));
  if (pageSize != null) {
    hasStoredValue = true;
    partial.pageSize = normalizeProductPageSize(Number.parseInt(pageSize, 10), 12);
  }

  const thumbnailSource = window.localStorage.getItem(
    getProductListPreferenceStorageKey('thumbnailSource')
  );
  if (thumbnailSource != null) {
    hasStoredValue = true;
    if (PRODUCT_LIST_THUMBNAIL_SOURCES.has(thumbnailSource)) {
      partial.thumbnailSource = thumbnailSource as ProductListPreferences['thumbnailSource'];
    }
  }

  const filtersCollapsedByDefault = parseStoredBooleanPreference(
    window.localStorage.getItem(getProductListPreferenceStorageKey('filtersCollapsedByDefault'))
  );
  if (filtersCollapsedByDefault != null) {
    hasStoredValue = true;
    partial.filtersCollapsedByDefault = filtersCollapsedByDefault;
  }

  const showTriggerRunFeedback = parseStoredBooleanPreference(
    window.localStorage.getItem(getProductListPreferenceStorageKey('showTriggerRunFeedback'))
  );
  if (showTriggerRunFeedback != null) {
    hasStoredValue = true;
    partial.showTriggerRunFeedback = showTriggerRunFeedback;
  }

  const advancedFilterPresets = parseStoredJsonPreference(
    window.localStorage.getItem(getProductListPreferenceStorageKey('advancedFilterPresets'))
  );
  if (advancedFilterPresets !== undefined) {
    hasStoredValue = true;
    if (Array.isArray(advancedFilterPresets)) {
      partial.advancedFilterPresets = advancedFilterPresets as ProductAdvancedFilterPreset[];
    }
  }

  const appliedAdvancedFilter = window.localStorage.getItem(
    getProductListPreferenceStorageKey('appliedAdvancedFilter')
  );
  if (appliedAdvancedFilter != null) {
    hasStoredValue = true;
    partial.appliedAdvancedFilter = appliedAdvancedFilter;
  }

  const appliedAdvancedFilterPresetId = window.localStorage.getItem(
    getProductListPreferenceStorageKey('appliedAdvancedFilterPresetId')
  );
  if (appliedAdvancedFilterPresetId != null) {
    hasStoredValue = true;
    partial.appliedAdvancedFilterPresetId =
      appliedAdvancedFilterPresetId === 'null' ? null : appliedAdvancedFilterPresetId;
  }

  if (!hasStoredValue) return null;

  const parsed = productListPreferencesSchema.safeParse({
    ...DEFAULT_PREFERENCES,
    ...partial,
  });

  return parsed.success ? parsed.data : DEFAULT_PREFERENCES;
}

async function updateUserPreferences(data: Partial<ProductListPreferences>): Promise<void> {
  const entries = Object.entries(data);
  for (const [key, value] of entries) {
    await updateUserPreference(key as keyof ProductListPreferences, value);
  }
}
export function useUpdateUserPreferences(): UseMutationResult<
  void,
  Error,
  Partial<ProductListPreferences>
  > {
  return useOfflineMutation<void, Error, Partial<ProductListPreferences>>(updateUserPreferences, {
    queryKey: userPreferencesQueryKey,
    onQueued: () => {
      // Handle queued state
    },
    onProcessed: (_vars, { queryClient }) => {
      void invalidateUserPreferences(queryClient);
    },
    errorMessage: 'Failed to update preferences',
  });
}

export interface UserPreferencesHookResult {
  preferences: ProductListPreferences;
  loading: boolean;
  setNameLocale: (locale: 'name_en' | 'name_pl' | 'name_de') => Promise<void>;
  setCatalogFilter: (filter: string) => Promise<void>;
  setCurrencyCode: (code: string) => Promise<void>;
  setPageSize: (size: number) => Promise<void>;
  setShowTriggerRunFeedback: (show: boolean) => Promise<void>;
  setAdvancedFilterPresets: (presets: ProductAdvancedFilterPreset[]) => Promise<void>;
  setAppliedAdvancedFilterState: (state: {
    advancedFilter: string;
    presetId: string | null;
  }) => Promise<void>;
}

export function useUserPreferences(): UserPreferencesHookResult {
  const [storedPreferences] = useState<ProductListPreferences | null>(() =>
    readStoredProductListPreferences()
  );
  const [localPreferenceOverrides, setLocalPreferenceOverrides] = useState<
    Partial<ProductListPreferences>
  >({});
  const query = createSingleQueryV2<UserPreferencesResponse, ProductListPreferences>({
    id: 'current',
    queryKey: userPreferencesQueryKey,
    queryFn: (context) => fetchUserPreferences(context.signal),
    select: mapProductListPreferences,
    staleTime: 1000 * 60 * 5,
    refetchOnMount: false,
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
    retry: 1,
    meta: {
      source: 'products.hooks.useUserPreferences',
      operation: 'detail',
      resource: 'user-preferences.product-list',
      domain: 'products',
      queryKey: userPreferencesQueryKey,
      tags: ['products', 'user-preferences'],
      description: 'Loads user preferences product list.'},
  });

  const { data, isLoading } = query;
  const preferences = {
    ...(data ?? storedPreferences ?? DEFAULT_PREFERENCES),
    ...localPreferenceOverrides,
  };

  const { mutateAsync: updateBulk } = useUpdateUserPreferences();

  const setPreference = useCallback(
    async (updates: Partial<ProductListPreferences>) => {
      await updateBulk(updates);
      Object.entries(updates).forEach(([key, value]) => {
        updateLocalStorage(key as keyof ProductListPreferences, value);
      });
      setLocalPreferenceOverrides((current) => ({
        ...current,
        ...updates,
      }));
    },
    [updateBulk]
  );

  const setNameLocale = useCallback(
    async (locale: 'name_en' | 'name_pl' | 'name_de') => {
      await setPreference({ nameLocale: locale });
    },
    [setPreference]
  );

  const setCatalogFilter = useCallback(
    async (filter: string) => {
      await setPreference({ catalogFilter: filter });
    },
    [setPreference]
  );

  const setCurrencyCode = useCallback(
    async (code: string) => {
      await setPreference({ currencyCode: code });
    },
    [setPreference]
  );

  const setPageSize = useCallback(
    async (size: number) => {
      await setPreference({ pageSize: normalizeProductPageSize(size, 12) });
    },
    [setPreference]
  );

  const setAdvancedFilterPresets = useCallback(
    async (presets: ProductAdvancedFilterPreset[]) => {
      await setPreference({ advancedFilterPresets: presets });
    },
    [setPreference]
  );

  const setShowTriggerRunFeedback = useCallback(
    async (show: boolean) => {
      await setPreference({ showTriggerRunFeedback: show });
    },
    [setPreference]
  );

  const setAppliedAdvancedFilterState = useCallback(
    async (state: { advancedFilter: string; presetId: string | null }) => {
      await setPreference({
        appliedAdvancedFilter: state.advancedFilter,
        appliedAdvancedFilterPresetId: state.presetId,
      });
    },
    [setPreference]
  );

  return {
    preferences,
    loading: isLoading,
    setNameLocale,
    setCatalogFilter,
    setCurrencyCode,
    setPageSize,
    setShowTriggerRunFeedback,
    setAdvancedFilterPresets,
    setAppliedAdvancedFilterState,
  };
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';
import type { ProductValidationDenyBehavior, ProductValidationInstanceScope, ProductValidationPattern } from '@/shared/contracts/products/validation';
import {
  normalizeProductValidationDenyBehavior,
  normalizeProductValidationInstanceDenyBehaviorMap,
  normalizeProductValidationPatternDenyBehaviorOverride,
} from '@/shared/lib/products/utils/validator-instance-behavior';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import {
  VALIDATION_ACCEPTED_ISSUES_SESSION_KEY,
  VALIDATION_DENIED_ISSUES_SESSION_KEY,
  VALIDATION_DENY_BEHAVIOR_SESSION_KEY,
  VALIDATION_DENY_SESSION_ID_KEY,
} from './validator-utils';

export function useProductValidationDecisions(
  validationInstanceScope: ProductValidationInstanceScope,
  instanceDenyBehavior: unknown,
  patterns: ProductValidationPattern[],
  _productId: string | null,
  _draftId: string | null
) {
  const [validationDenyBehaviorOverrides, setValidationDenyBehaviorOverrides] = useState<
    Partial<Record<ProductValidationInstanceScope, ProductValidationDenyBehavior>>
  >(() => {
    if (typeof window === 'undefined') return {};
    try {
      const raw = window.sessionStorage.getItem(VALIDATION_DENY_BEHAVIOR_SESSION_KEY);
      if (!raw) return {};
      const parsed = JSON.parse(raw) as unknown;
      if (!parsed || typeof parsed !== 'object') return {};
      const source = parsed as Partial<Record<ProductValidationInstanceScope, unknown>>;
      const next: Partial<Record<ProductValidationInstanceScope, ProductValidationDenyBehavior>> = {};
      if (source['draft_template'] !== undefined) {
        next['draft_template'] = normalizeProductValidationDenyBehavior(source['draft_template']);
      }
      if (source['product_create'] !== undefined) {
        next['product_create'] = normalizeProductValidationDenyBehavior(source['product_create']);
      }
      if (source['product_edit'] !== undefined) {
        next['product_edit'] = normalizeProductValidationDenyBehavior(source['product_edit']);
      }
      return next;
    } catch (error) {
      logClientError(error);
      return {};
    }
  });

  const [deniedIssueKeys, setDeniedIssueKeys] = useState<Set<string>>(() => {
    if (typeof window === 'undefined') return new Set<string>();
    try {
      const raw = window.sessionStorage.getItem(VALIDATION_DENIED_ISSUES_SESSION_KEY);
      if (!raw) return new Set<string>();
      const parsed = JSON.parse(raw) as unknown;
      if (!Array.isArray(parsed)) return new Set<string>();
      return new Set(parsed.filter((entry: unknown): entry is string => typeof entry === 'string' && entry.length > 0));
    } catch (error) {
      logClientError(error);
      return new Set<string>();
    }
  });

  const [acceptedIssueKeys, setAcceptedIssueKeys] = useState<Set<string>>(() => {
    if (typeof window === 'undefined') return new Set<string>();
    try {
      const raw = window.sessionStorage.getItem(VALIDATION_ACCEPTED_ISSUES_SESSION_KEY);
      if (!raw) return new Set<string>();
      const parsed = JSON.parse(raw) as unknown;
      if (!Array.isArray(parsed)) return new Set<string>();
      return new Set(parsed.filter((entry: unknown): entry is string => typeof entry === 'string' && entry.length > 0));
    } catch (error) {
      logClientError(error);
      return new Set<string>();
    }
  });

  const [validationSessionId] = useState<string>(() => {
    if (typeof window === 'undefined') return '';
    const existing = window.sessionStorage.getItem(VALIDATION_DENY_SESSION_ID_KEY);
    if (existing) return existing;
    const nextId =
      typeof globalThis.crypto !== 'undefined' && typeof globalThis.crypto.randomUUID === 'function'
        ? globalThis.crypto.randomUUID()
        : `validator-session-${Date.now().toString(36)}`;
    window.sessionStorage.setItem(VALIDATION_DENY_SESSION_ID_KEY, nextId);
    return nextId;
  });

  const denyBehaviorWriteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const deniedIssuesWriteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const acceptedIssuesWriteTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (denyBehaviorWriteTimerRef.current) clearTimeout(denyBehaviorWriteTimerRef.current);
    denyBehaviorWriteTimerRef.current = setTimeout(() => {
      window.sessionStorage.setItem(VALIDATION_DENY_BEHAVIOR_SESSION_KEY, JSON.stringify(validationDenyBehaviorOverrides));
    }, 300);
    return () => { if (denyBehaviorWriteTimerRef.current) clearTimeout(denyBehaviorWriteTimerRef.current); };
  }, [validationDenyBehaviorOverrides]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (deniedIssuesWriteTimerRef.current) clearTimeout(deniedIssuesWriteTimerRef.current);
    deniedIssuesWriteTimerRef.current = setTimeout(() => {
      window.sessionStorage.setItem(VALIDATION_DENIED_ISSUES_SESSION_KEY, JSON.stringify([...deniedIssueKeys]));
    }, 300);
    return () => { if (deniedIssuesWriteTimerRef.current) clearTimeout(deniedIssuesWriteTimerRef.current); };
  }, [deniedIssueKeys]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (acceptedIssuesWriteTimerRef.current) clearTimeout(acceptedIssuesWriteTimerRef.current);
    acceptedIssuesWriteTimerRef.current = setTimeout(() => {
      window.sessionStorage.setItem(VALIDATION_ACCEPTED_ISSUES_SESSION_KEY, JSON.stringify([...acceptedIssueKeys]));
    }, 300);
    return () => { if (acceptedIssuesWriteTimerRef.current) clearTimeout(acceptedIssuesWriteTimerRef.current); };
  }, [acceptedIssueKeys]);

  const configuredInstanceDenyBehavior = normalizeProductValidationInstanceDenyBehaviorMap(instanceDenyBehavior);
  const effectiveValidationDenyBehavior: ProductValidationDenyBehavior =
    validationDenyBehaviorOverrides[validationInstanceScope] ??
    configuredInstanceDenyBehavior[validationInstanceScope];

  const patternDenyBehaviorOverrideById = new Map<string, ProductValidationDenyBehavior | null>(
    (patterns ?? []).map((pattern: ProductValidationPattern) => [
      pattern.id,
      normalizeProductValidationPatternDenyBehaviorOverride(pattern.denyBehaviorOverride),
    ])
  );

  const setValidationDenyBehavior = useCallback(
    (
      next:
        | ProductValidationDenyBehavior
        | ((prev: ProductValidationDenyBehavior) => ProductValidationDenyBehavior)
    ): void => {
      setValidationDenyBehaviorOverrides(
        (prev: Partial<Record<ProductValidationInstanceScope, ProductValidationDenyBehavior>>) => {
          const current =
            prev[validationInstanceScope] ??
            configuredInstanceDenyBehavior[validationInstanceScope];
          const resolved =
            typeof next === 'function'
              ? (next as (prev: ProductValidationDenyBehavior) => ProductValidationDenyBehavior)(
                current
              )
              : next;
          const normalized = normalizeProductValidationDenyBehavior(resolved);
          if (normalized === current && prev[validationInstanceScope] === normalized) {
            return prev;
          }
          return {
            ...prev,
            [validationInstanceScope]: normalized,
          };
        }
      );
    },
    [configuredInstanceDenyBehavior, validationInstanceScope]
  );

  const getIssueDenyBehavior = useCallback(
    (patternId: string): ProductValidationDenyBehavior => {
      const normalizedPatternId = patternId.trim();
      if (!normalizedPatternId) return effectiveValidationDenyBehavior;
      const override = patternDenyBehaviorOverrideById.get(normalizedPatternId);
      return override ?? effectiveValidationDenyBehavior;
    },
    [effectiveValidationDenyBehavior, patternDenyBehaviorOverrideById]
  );

  return {
    validationDenyBehaviorOverrides,
    setValidationDenyBehaviorOverrides,
    deniedIssueKeys,
    setDeniedIssueKeys,
    acceptedIssueKeys,
    setAcceptedIssueKeys,
    validationSessionId,
    effectiveValidationDenyBehavior,
    setValidationDenyBehavior,
    getIssueDenyBehavior,
  };
}

const NORMALIZE_PRODUCT_NAME_PATH_ID = 'path_name_normalize_v1';

export type NormalizeProductNameCategoryLeaf = {
  id: string | null;
  label: string;
  fullPath: string | null;
  parentId: string | null;
  isCurrent: boolean | null;
};

export type NormalizeProductNameCategoryContext = {
  catalogId: string | null;
  currentCategoryId: string | null;
  leafCategories: NormalizeProductNameCategoryLeaf[];
  allowedLeafLabels: string[];
  totalCategories: number | null;
  totalLeafCategories: number | null;
  fetchedAt: string | null;
};

export type NormalizeProductNameAiPathResult = {
  normalizedName: string | null;
  title: string | null;
  size: string | null;
  material: string | null;
  category: string | null;
  theme: string | null;
  isValid: boolean | null;
  validationError: string | null;
  confidence: number | null;
  categoryContext?: NormalizeProductNameCategoryContext | null;
};

type NormalizeDbSchemaCollectionState = {
  name: string;
  documentsCount: number | null;
  error: string | null;
};

type NormalizeDbSchemaContextState = {
  query: string | null;
  collections: NormalizeDbSchemaCollectionState[];
};

const asRecord = (value: unknown): Record<string, unknown> | null => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  return value as Record<string, unknown>;
};

const asTrimmedString = (value: unknown): string | null => {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const asNullableBoolean = (value: unknown): boolean | null =>
  typeof value === 'boolean' ? value : null;

const asNullableNumber = (value: unknown): number | null =>
  typeof value === 'number' && Number.isFinite(value) ? value : null;

const asRecordArray = (value: unknown): Record<string, unknown>[] =>
  Array.isArray(value)
    ? value
        .map((entry: unknown) => asRecord(entry))
        .filter((entry): entry is Record<string, unknown> => entry !== null)
    : [];

const resolveNormalizeCategoryLeaf = (value: unknown): NormalizeProductNameCategoryLeaf | null => {
  const record = asRecord(value);
  if (!record) return null;

  const label = asTrimmedString(record['label']) ?? asTrimmedString(record['name']);
  if (!label) return null;

  return {
    id: asTrimmedString(record['id']),
    label,
    fullPath: asTrimmedString(record['fullPath']),
    parentId: asTrimmedString(record['parentId']),
    isCurrent: asNullableBoolean(record['isCurrent']),
  };
};

const resolveNormalizeCategoryContext = (
  value: unknown
): NormalizeProductNameCategoryContext | null => {
  const record = asRecord(value);
  if (!record) return null;

  const leafCategories = Array.isArray(record['leafCategories'])
    ? record['leafCategories']
        .map((entry: unknown) => resolveNormalizeCategoryLeaf(entry))
        .filter((entry): entry is NormalizeProductNameCategoryLeaf => entry !== null)
    : [];
  const allowedLeafLabels = Array.isArray(record['allowedLeafLabels'])
    ? record['allowedLeafLabels']
        .map((entry: unknown) => asTrimmedString(entry))
        .filter((entry): entry is string => entry !== null)
    : [];
  const totalCategories = asNullableNumber(record['totalCategories']);
  const totalLeafCategories = asNullableNumber(record['totalLeafCategories']);
  const catalogId = asTrimmedString(record['catalogId']);
  const currentCategoryId = asTrimmedString(record['currentCategoryId']);
  const fetchedAt = asTrimmedString(record['fetchedAt']);

  if (
    leafCategories.length === 0 &&
    allowedLeafLabels.length === 0 &&
    totalCategories === null &&
    totalLeafCategories === null &&
    catalogId === null &&
    currentCategoryId === null &&
    fetchedAt === null
  ) {
    return null;
  }

  return {
    catalogId,
    currentCategoryId,
    leafCategories,
    allowedLeafLabels,
    totalCategories,
    totalLeafCategories,
    fetchedAt,
  };
};

const resolveNormalizeCategoryContextFromValue = (
  value: unknown
): NormalizeProductNameCategoryContext | null => {
  const record = asRecord(value);
  if (!record) return null;

  return (
    resolveNormalizeCategoryContext(record['categoryContext']) ??
    resolveNormalizeCategoryContext(asRecord(record['bundle'])?.['categoryContext']) ??
    resolveNormalizeCategoryContext(asRecord(record['value'])?.['categoryContext']) ??
    null
  );
};

const resolveDbSchemaCollectionState = (
  value: unknown
): NormalizeDbSchemaCollectionState | null => {
  const record = asRecord(value);
  if (!record) return null;

  const name = asTrimmedString(record['name']);
  if (!name) return null;

  const documentsCount = Array.isArray(record['documents']) ? record['documents'].length : null;
  const error = asTrimmedString(record['error']);

  return {
    name,
    documentsCount,
    error,
  };
};

const resolveNormalizeDbSchemaContextState = (
  value: unknown
): NormalizeDbSchemaContextState | null => {
  const record = asRecord(value);
  if (!record) return null;

  const liveContext = asRecord(record['liveContext']);
  if (!liveContext) return null;

  const collections = asRecordArray(liveContext['collections'])
    .map((entry: Record<string, unknown>) => resolveDbSchemaCollectionState(entry))
    .filter((entry): entry is NormalizeDbSchemaCollectionState => entry !== null);

  const collectionMap = asRecord(liveContext['collectionMap']);
  if (collectionMap) {
    Object.values(collectionMap).forEach((entry: unknown) => {
      const resolved = resolveDbSchemaCollectionState(entry);
      if (!resolved) return;
      if (collections.some((collection) => collection.name === resolved.name)) return;
      collections.push(resolved);
    });
  }

  if (collections.length === 0 && asTrimmedString(liveContext['query']) === null) {
    return null;
  }

  return {
    query: asTrimmedString(liveContext['query']),
    collections,
  };
};

const resolveNormalizeDbSchemaContextFromNodes = (
  value: unknown
): NormalizeDbSchemaContextState | null => {
  if (!Array.isArray(value)) return null;

  const nodeEntries = value
    .map((entry: unknown) => asRecord(entry))
    .filter((entry): entry is Record<string, unknown> => entry !== null);

  for (const entry of nodeEntries) {
    const outputs = asRecord(entry['outputs']);
    const resolved =
      resolveNormalizeDbSchemaContextState(outputs?.['context']) ??
      resolveNormalizeDbSchemaContextState(outputs);
    if (resolved) return resolved;
  }

  return null;
};

const resolveNormalizeDbSchemaContextFromRuntimeState = (
  value: unknown
): NormalizeDbSchemaContextState | null => {
  const runtimeState = asRecord(value);
  if (!runtimeState) return null;

  const nodeOutputs = asRecord(runtimeState['nodeOutputs']) ?? asRecord(runtimeState['outputs']);
  if (!nodeOutputs) return null;

  for (const entry of Object.values(nodeOutputs)) {
    const resolved = resolveNormalizeDbSchemaContextState(entry);
    if (resolved) return resolved;
  }

  return null;
};

const normalizeCategoryUnavailableValidationError = (args: {
  validationError: string | null;
  categoryContext: NormalizeProductNameCategoryContext | null;
  dbSchemaContext: NormalizeDbSchemaContextState | null;
}): string | null => {
  const normalizedError = args.validationError?.trim().toLowerCase() ?? '';
  if (normalizedError !== 'category context unavailable') {
    return args.validationError;
  }

  const collection = args.dbSchemaContext?.collections.find(
    (entry) => entry.name === 'product_categories'
  );
  if (collection?.error) {
    return `Category context unavailable: ${collection.error}`;
  }

  if (collection?.documentsCount === 0) {
    const catalogId = args.categoryContext?.catalogId;
    if (catalogId) {
      return `Category context unavailable: no product_categories rows matched catalog "${catalogId}".`;
    }
    return 'Category context unavailable: no product_categories rows were returned.';
  }

  return args.validationError;
};

const resolveNameFromUpdateDoc = (value: unknown): string | null => {
  const updateDoc = asRecord(value);
  if (!updateDoc) return null;
  const setDoc = asRecord(updateDoc['$set']);
  if (!setDoc) return null;
  return asTrimmedString(setDoc['name_en']);
};

const resolveNormalizePayload = (value: unknown): NormalizeProductNameAiPathResult | null => {
  const record = asRecord(value);
  if (!record) return null;

  const debugPayload = asRecord(record['debugPayload']);
  const bundle = asRecord(record['bundle']);
  const nestedValue = asRecord(record['value']);
  const candidates = [
    debugPayload ? asRecord(debugPayload['updateDoc']) : null,
    bundle,
    nestedValue,
    record,
  ].filter((candidate): candidate is Record<string, unknown> => candidate !== null);

  for (const candidate of candidates) {
    const normalizedName =
      resolveNameFromUpdateDoc(candidate) ??
      asTrimmedString(candidate['normalizedName']) ??
      asTrimmedString(candidate['result']);
    const title = asTrimmedString(candidate['title']);
    const size = asTrimmedString(candidate['size']);
    const material = asTrimmedString(candidate['material']);
    const category = asTrimmedString(candidate['category']);
    const theme = asTrimmedString(candidate['theme']);
    const validationError = asTrimmedString(candidate['validationError']);
    const isValid = asNullableBoolean(candidate['isValid']);
    const confidence = asNullableNumber(candidate['confidence']);

    if (
      normalizedName ||
      title ||
      size ||
      material ||
      category ||
      theme ||
      validationError ||
      isValid !== null ||
      confidence !== null
    ) {
      return {
        normalizedName,
        title,
        size,
        material,
        category,
        theme,
        isValid,
        validationError,
        confidence,
      };
    }
  }

  return null;
};

const resolveNormalizePayloadFromNodes = (
  value: unknown
): NormalizeProductNameAiPathResult | null => {
  if (!Array.isArray(value)) return null;

  const nodeEntries = value
    .map((entry: unknown) => asRecord(entry))
    .filter((entry): entry is Record<string, unknown> => entry !== null);
  const orderedCandidates = [
    ...nodeEntries.filter((entry) => entry['nodeType'] === 'database'),
    ...nodeEntries.filter((entry) => entry['nodeType'] === 'mapper'),
    ...nodeEntries.filter((entry) => entry['nodeType'] === 'regex'),
    ...nodeEntries,
  ];

  for (const entry of orderedCandidates) {
    const payload = resolveNormalizePayload(asRecord(entry['outputs']));
    if (payload) return payload;
  }

  return null;
};

const resolveNormalizePayloadFromRuntimeState = (
  value: unknown
): NormalizeProductNameAiPathResult | null => {
  const runtimeState = asRecord(value);
  if (!runtimeState) return null;

  const nodeOutputs = asRecord(runtimeState['nodeOutputs']) ?? asRecord(runtimeState['outputs']);
  if (!nodeOutputs) return null;

  for (const entry of Object.values(nodeOutputs)) {
    const payload = resolveNormalizePayload(entry);
    if (payload) return payload;
  }

  return null;
};

const resolveNormalizeCategoryContextFromNodes = (
  value: unknown
): NormalizeProductNameCategoryContext | null => {
  if (!Array.isArray(value)) return null;

  const nodeEntries = value
    .map((entry: unknown) => asRecord(entry))
    .filter((entry): entry is Record<string, unknown> => entry !== null);

  for (const entry of nodeEntries) {
    const categoryContext = resolveNormalizeCategoryContextFromValue(entry['outputs']);
    if (categoryContext) return categoryContext;
  }

  return null;
};

const resolveNormalizeCategoryContextFromRuntimeState = (
  value: unknown
): NormalizeProductNameCategoryContext | null => {
  const runtimeState = asRecord(value);
  if (!runtimeState) return null;

  const nodeOutputs = asRecord(runtimeState['nodeOutputs']) ?? asRecord(runtimeState['outputs']);
  if (!nodeOutputs) return null;

  for (const entry of Object.values(nodeOutputs)) {
    const categoryContext = resolveNormalizeCategoryContextFromValue(entry);
    if (categoryContext) return categoryContext;
  }

  return null;
};

export const isNormalizeProductNamePath = (pathId: unknown): boolean =>
  asTrimmedString(pathId) === NORMALIZE_PRODUCT_NAME_PATH_ID;

export const extractNormalizeProductNameResultFromAiPathRunDetail = (
  detail: unknown
): NormalizeProductNameAiPathResult | null => {
  const record = asRecord(detail);
  if (!record) return null;

  const payload =
    resolveNormalizePayloadFromNodes(record['nodes']) ??
    resolveNormalizePayloadFromRuntimeState(asRecord(record['run'])?.['runtimeState']) ??
    resolveNormalizePayload(asRecord(record['run'])?.['result']) ??
    null;
  if (!payload) return null;

  const categoryContext =
    resolveNormalizeCategoryContextFromNodes(record['nodes']) ??
    resolveNormalizeCategoryContextFromRuntimeState(asRecord(record['run'])?.['runtimeState']) ??
    resolveNormalizeCategoryContextFromValue(asRecord(record['run'])?.['result']) ??
    null;
  const dbSchemaContext =
    resolveNormalizeDbSchemaContextFromNodes(record['nodes']) ??
    resolveNormalizeDbSchemaContextFromRuntimeState(asRecord(record['run'])?.['runtimeState']) ??
    null;
  const validationError = normalizeCategoryUnavailableValidationError({
    validationError: payload.validationError,
    categoryContext,
    dbSchemaContext,
  });
  const enrichedPayload = {
    ...payload,
    validationError,
  };

  return categoryContext ? { ...enrichedPayload, categoryContext } : enrichedPayload;
};

export const extractNormalizeProductNameFromAiPathRunDetail = (
  detail: unknown
): string | null => extractNormalizeProductNameResultFromAiPathRunDetail(detail)?.normalizedName ?? null;

