const isManualVerificationPending = (scan: Pick<ProductScanRecord, 'rawResult'>): boolean => {
  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  return (rawResult as Record<string, unknown>)['manualVerificationPending'] === true;
};

export const isProductScanGoogleStealthRetrying = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult'> | null | undefined
): boolean => {
  if (scan?.status !== 'running' && scan?.status !== 'queued') {
    return false;
  }

  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  const result = rawResult as Record<string, unknown>;
  return (
    result['captchaStealthRetryStarted'] === true &&
    result['manualVerificationPending'] !== true &&
    result['captchaManualRetryStarted'] !== true
  );
};

export const isProductScanGoogleManualFallbackOpen = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult' | 'steps'> | null | undefined
): boolean => {
  if (scan?.status !== 'running' && scan?.status !== 'queued') {
    return false;
  }

  const rawResult = scan.rawResult;
  const rawResultRecord =
    rawResult && typeof rawResult === 'object' && !Array.isArray(rawResult)
      ? (rawResult as Record<string, unknown>)
      : null;
  const hasManualRetryFlag = rawResultRecord?.['captchaManualRetryStarted'] === true;
  const hasManualRetryStep =
    Array.isArray(scan.steps) &&
    scan.steps.some((step) => step.key === 'google_manual_retry');

  return hasManualRetryFlag || hasManualRetryStep;
};

const getManualVerificationMessage = (
  scan: Pick<ProductScanRecord, 'rawResult' | 'asinUpdateMessage'> | null | undefined
): string | null => {
  if (!scan) {
    return null;
  }
  const rawResult = scan.rawResult;
  if (rawResult && typeof rawResult === 'object' && !Array.isArray(rawResult)) {
    const msg = (rawResult as Record<string, unknown>)['manualVerificationMessage'];
    if (typeof msg === 'string' && msg.trim().length > 0) {
      return msg;
    }
  }
  return typeof scan.asinUpdateMessage === 'string' ? scan.asinUpdateMessage : null;
};

export const isProductScanCandidateSelectionRequired = (
  scan: Pick<ProductScanRecord, 'status' | 'rawResult'> | null | undefined
): boolean => {
  if (scan?.status !== 'completed') {
    return false;
  }

  const rawResult = scan.rawResult;
  if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) {
    return false;
  }

  return (rawResult as Record<string, unknown>)['candidateSelectionRequired'] === true;
};

export const resolveProductScanRunFeedbackPresentation = (
  status: ProductScanStatus,
  options?: {
    manualVerificationPending?: boolean | null;
    manualVerificationMessage?: string | null;
    googleStealthRetrying?: boolean | null;
    googleManualFallbackOpen?: boolean | null;
    candidateSelectionRequired?: boolean | null;
    amazonEvaluationStatus?: ProductScanAmazonEvaluationStatus | null;
    amazonEvaluationLanguageAccepted?: boolean | null;
    supplierEvaluationStatus?: ProductScanSupplierEvaluationStatus | null;
  }
): TriggerButtonRunFeedbackPresentation =>
  (status === 'running' || status === 'queued') && options?.googleStealthRetrying
    ? {
        label: PRODUCT_SCAN_GOOGLE_STEALTH_RETRY_LABEL,
        variant: 'warning',
        badgeClassName:
          'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
      }
    : (status === 'running' || status === 'queued') && options?.googleManualFallbackOpen
    ? {
        label: PRODUCT_SCAN_GOOGLE_MANUAL_FALLBACK_LABEL,
        variant: 'warning',
        badgeClassName:
          'border-sky-500/40 bg-sky-500/20 text-sky-200 hover:bg-sky-500/25',
      }
    : status === 'running' && options?.manualVerificationPending
    ? {
        label: /requested login/i.test(options?.manualVerificationMessage ?? '') ? 'Login' : 'Captcha',
        variant: 'warning',
        badgeClassName:
          'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
      }
    : status === 'completed' && options?.candidateSelectionRequired
      ? {
          label: PRODUCT_SCAN_CANDIDATE_SELECTION_LABEL,
          variant: 'warning',
          badgeClassName:
            'border-amber-500/40 bg-amber-500/20 text-amber-200 hover:bg-amber-500/25',
        }
    : status === 'no_match' &&
        options?.amazonEvaluationStatus === 'rejected' &&
        options?.amazonEvaluationLanguageAccepted === false
      ? {
          label: 'AI Rejected: Language',
          variant: 'warning',
          badgeClassName:
            'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
        }
    : status === 'no_match' && options?.amazonEvaluationStatus === 'rejected'
      ? {
          label: 'AI Rejected',
          variant: 'warning',
          badgeClassName:
            'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
        }
      : status === 'no_match' && options?.supplierEvaluationStatus === 'rejected'
        ? {
            label: 'AI Rejected',
            variant: 'warning',
            badgeClassName:
              'border-orange-500/40 bg-orange-500/20 text-orange-200 hover:bg-orange-500/25',
          }
      : status === 'failed' && options?.amazonEvaluationStatus === 'failed'
        ? {
            label: 'AI Failed',
            variant: 'error',
          }
        : status === 'failed' && options?.supplierEvaluationStatus === 'failed'
          ? {
              label: 'AI Failed',
              variant: 'error',
            }
        : PRODUCT_SCAN_RUN_FEEDBACK_PRESENTATIONS[status] ?? {
            label: status,
            variant: 'neutral',
          };

export const buildProductScanRunFeedbackFromRecord = (
  scan: ProductScanRecord
): ProductScanRunFeedback => ({
  scanId: scan.id,
  status: scan.status,
  updatedAt: scan.updatedAt ?? scan.completedAt ?? scan.createdAt ?? null,
  ...resolveProductScanRunFeedbackPresentation(scan.status, {
    manualVerificationPending: isManualVerificationPending(scan),
    manualVerificationMessage: getManualVerificationMessage(scan),
    googleStealthRetrying: isProductScanGoogleStealthRetrying(scan),
    googleManualFallbackOpen: isProductScanGoogleManualFallbackOpen(scan),
    candidateSelectionRequired: isProductScanCandidateSelectionRequired(scan),
    amazonEvaluationStatus: scan.amazonEvaluation?.status ?? null,
    amazonEvaluationLanguageAccepted: scan.amazonEvaluation?.languageAccepted ?? null,
    supplierEvaluationStatus: scan.supplierEvaluation?.status ?? null,
  }),
});

export const resolveProductScanFeedbackAgeMs = (
  scan: ProductScanRecord,
  now = Date.now()
): number => {
  const timestamp = Date.parse(scan.updatedAt ?? scan.completedAt ?? scan.createdAt ?? '');
  if (!Number.isFinite(timestamp)) {
    return Number.POSITIVE_INFINITY;
  }
  return Math.max(0, now - timestamp);
};

export const shouldShowProductScanRunFeedback = (
  scan: ProductScanRecord,
  now = Date.now(),
  terminalTtlMs = 15_000
): boolean => {
  if (isProductScanActiveStatus(scan.status)) {
    return true;
  }
  return resolveProductScanFeedbackAgeMs(scan, now) <= terminalTtlMs;
};

// validateNormalizedProductName: utility to validate and normalize structured
// product names. Uses category leaf hierarchy helpers to disambiguate category
// segments and protects against generic or ambiguous category matches.
import type { ProductCategory } from '@/shared/contracts/products/categories';
import {
  composeStructuredProductName,
  normalizeStructuredProductName,
  parseStructuredProductName,
} from '@/shared/lib/products/title-terms';
import { buildLeafCategoryHierarchyEntries } from './leafCategoryHierarchy';

export type NormalizeProductNameCategoryContextLeaf = {
  label: string;
  fullPath?: string | null;
};

export type NormalizeProductNameCategoryContext = {
  leafCategories: NormalizeProductNameCategoryContextLeaf[];
  allowedLeafLabels?: string[] | null;
  totalLeafCategories?: number | null;
};

export type ValidateNormalizedProductNameResult =
  | {
      isValid: true;
      normalizedName: string;
    }
  | {
      isValid: false;
      error: string;
    };

const GENERIC_SEGMENT_VALUES = new Set(['unknown', 'n/a', 'na', 'tbd']);
const GENERIC_BASE_NAME_VALUES = new Set(['name', 'product', 'title']);

const normalizeComparable = (value: string): string => value.trim().replace(/\s+/g, ' ').toLowerCase();

const normalizeHierarchyComparable = (value: string): string =>
  value
    .split(/\s*(?:>|\/)\s*/)
    .map((segment) => normalizeComparable(segment))
    .filter((segment) => segment.length > 0)
    .join(' > ');

const isGenericSizeSegment = (value: string): boolean => {
  const normalized = normalizeComparable(value);
  return /^x(?:\s*(?:cm|mm|m|in|inch|inches))?$/.test(normalized);
};

const resolveMatchingLeafNamesForNonTerminalSegment = (
  entries: ReturnType<typeof buildLeafCategoryHierarchyEntries>,
  rawCategoryValue: string
): string[] => {
  const normalizedCategoryValue = normalizeComparable(rawCategoryValue);
  if (!normalizedCategoryValue) return [];

  return Array.from(
    new Set(
      entries
        .filter((entry) =>
          entry.pathSegments
            .slice(0, -1)
            .map((segment) => normalizeComparable(segment))
            .includes(normalizedCategoryValue)
        )
        .map((entry) => entry.leafName)
    )
  );
};

const resolveLeafCategoryMatch = (
  categories: ProductCategory[],
  rawCategoryValue: string
):
  | {
      canonicalCategoryName: string;
    }
  | {
      error: 'missing' | 'ambiguous' | 'too_generic';
    } => {
  const entries = buildLeafCategoryHierarchyEntries(categories);
  const entriesByHierarchyPath = new Map<string, string>();
  const entriesByLeafName = new Map<string, string[]>();

  entries.forEach((entry) => {
    const normalizedHierarchyPath = normalizeHierarchyComparable(entry.hierarchyPath);
    if (normalizedHierarchyPath && !entriesByHierarchyPath.has(normalizedHierarchyPath)) {
      entriesByHierarchyPath.set(normalizedHierarchyPath, entry.leafName);
    }

    const normalizedLeafName = normalizeComparable(entry.leafName);
    if (!normalizedLeafName) return;
    const matches = entriesByLeafName.get(normalizedLeafName) ?? [];
    matches.push(entry.leafName);
    entriesByLeafName.set(normalizedLeafName, matches);
  });

  const normalizedHierarchyInput = normalizeHierarchyComparable(rawCategoryValue);
  if (normalizedHierarchyInput) {
    const hierarchyMatch = entriesByHierarchyPath.get(normalizedHierarchyInput);
    if (hierarchyMatch) {
      return {
        canonicalCategoryName: hierarchyMatch,
      };
    }
  }

  if (resolveMatchingLeafNamesForNonTerminalSegment(entries, rawCategoryValue).length > 0) {
    return {
      error: 'too_generic',
    };
  }

  const normalizedLeafInput =
    normalizedHierarchyInput.split(' > ').filter(Boolean).pop() ?? normalizeComparable(rawCategoryValue);
  const leafMatches = entriesByLeafName.get(normalizedLeafInput) ?? [];
  if (leafMatches.length === 1) {
    return {
      canonicalCategoryName: leafMatches[0]!,
    };
  }
  if (leafMatches.length > 1) {
    return {
      error: 'ambiguous',
    };
  }

  return {
    error: 'missing',
  };
};

const resolveLeafCategoryMatchFromContext = (
  categoryContext: NormalizeProductNameCategoryContext,
  rawCategoryValue: string
):
  | {
      canonicalCategoryName: string;
    }
  | {
      error: 'missing' | 'ambiguous' | 'too_generic';
    } => {
  const normalizedLeafEntries = categoryContext.leafCategories
    .map((entry) => {
      const label = normalizeComparable(entry.label);
      const fullPath = normalizeHierarchyComparable(entry.fullPath ?? entry.label);
      if (!label) return null;
      return {
        label: entry.label.trim(),
        normalizedLabel: label,
        normalizedFullPath: fullPath,
      };
    })
    .filter(
      (
        entry
      ): entry is {
        label: string;
        normalizedLabel: string;
        normalizedFullPath: string;
      } => entry !== null
    );

  if (normalizedLeafEntries.length === 0) {
    return {
      error: 'missing',
    };
  }

  const entriesByHierarchyPath = new Map<string, string>();
  const entriesByLeafName = new Map<string, string[]>();

  normalizedLeafEntries.forEach((entry) => {
    if (entry.normalizedFullPath && !entriesByHierarchyPath.has(entry.normalizedFullPath)) {
      entriesByHierarchyPath.set(entry.normalizedFullPath, entry.label);
    }

    const matches = entriesByLeafName.get(entry.normalizedLabel) ?? [];
    matches.push(entry.label);
    entriesByLeafName.set(entry.normalizedLabel, matches);
  });

  const normalizedHierarchyInput = normalizeHierarchyComparable(rawCategoryValue);
  if (normalizedHierarchyInput) {
    const hierarchyMatch = entriesByHierarchyPath.get(normalizedHierarchyInput);
    if (hierarchyMatch) {
      return {
        canonicalCategoryName: hierarchyMatch,
      };
    }
  }

  const normalizedCategoryValue = normalizeComparable(rawCategoryValue);
  if (
    normalizedLeafEntries.some((entry) =>
      entry.normalizedFullPath
        .split(' > ')
        .slice(0, -1)
        .includes(normalizedCategoryValue)
    )
  ) {
    return {
      error: 'too_generic',
    };
  }

  const normalizedLeafInput =
    normalizedHierarchyInput.split(' > ').filter(Boolean).pop() ?? normalizedCategoryValue;
  const leafMatches = entriesByLeafName.get(normalizedLeafInput) ?? [];
  if (leafMatches.length === 1) {
    return {
      canonicalCategoryName: leafMatches[0]!,
    };
  }
  if (leafMatches.length > 1) {
    return {
      error: 'ambiguous',
    };
  }

  return {
    error: 'missing',
  };
};

export const validateNormalizedProductName = (args: {
  normalizedName: string;
  categories: ProductCategory[];
  categoryHint?: string | null;
  categoryContext?: NormalizeProductNameCategoryContext | null;
}): ValidateNormalizedProductNameResult => {
  const structuredValue = normalizeStructuredProductName(args.normalizedName);
  const parsed = parseStructuredProductName(structuredValue);

  if (!parsed) {
    return {
      isValid: false,
      error:
        'Normalize failed: the title must use exactly 5 non-empty segments in the format <title> | <size> | <material> | <category> | <theme>.',
    };
  }

  if (GENERIC_BASE_NAME_VALUES.has(normalizeComparable(parsed.baseName))) {
    return {
      isValid: false,
      error: 'Normalize failed: the title segment is still generic. Provide a specific product title.',
    };
  }

  if (isGenericSizeSegment(parsed.size)) {
    return {
      isValid: false,
      error: 'Normalize failed: the size segment is still a placeholder such as "X cm".',
    };
  }

  const genericMaterial = GENERIC_SEGMENT_VALUES.has(normalizeComparable(parsed.material));
  const genericTheme = GENERIC_SEGMENT_VALUES.has(normalizeComparable(parsed.theme));
  if (genericMaterial || genericTheme) {
    return {
      isValid: false,
      error: 'Normalize failed: material and theme must be inferred instead of using placeholder values.',
    };
  }

  if (
    args.categoryContext &&
    typeof args.categoryContext.totalLeafCategories === 'number' &&
    args.categoryContext.totalLeafCategories <= 0
  ) {
    return {
      isValid: false,
      error: 'Normalize failed: category context unavailable.',
    };
  }

  const categoryCandidates = [
    typeof args.categoryHint === 'string' ? args.categoryHint.trim() : '',
    parsed.category,
  ].filter((value, index, values): value is string => value.length > 0 && values.indexOf(value) === index);

  const shouldUseCategoryContext =
    Boolean(args.categoryContext) && (args.categoryContext?.leafCategories.length ?? 0) > 0;
  const categoryMatches = categoryCandidates.map((value) =>
    shouldUseCategoryContext
      ? resolveLeafCategoryMatchFromContext(args.categoryContext!, value)
      : resolveLeafCategoryMatch(args.categories, value)
  );
  const categoryMatch = categoryMatches.find(
    (value): value is { canonicalCategoryName: string } => 'canonicalCategoryName' in value
  );

  if (!categoryMatch) {
    const categoryError = categoryMatches.some(
      (value): value is { error: 'ambiguous' } => 'error' in value && value.error === 'ambiguous'
    )
      ? 'ambiguous'
      : categoryMatches.some(
            (value): value is { error: 'too_generic' } =>
              'error' in value && value.error === 'too_generic'
          )
        ? 'too_generic'
        : 'missing';

    return {
      isValid: false,
      error:
        categoryError === 'ambiguous'
          ? 'Normalize failed: category leaf is ambiguous. Return the full category hierarchy so the final leaf can be resolved uniquely.'
          : categoryError === 'too_generic'
            ? 'Normalize failed: category is too generic. Return the most specific terminal leaf category or the full hierarchy so the final leaf can be resolved.'
          : 'Normalize failed: category must match one of the available leaf categories.',
    };
  }

  return {
    isValid: true,
    normalizedName: composeStructuredProductName({
      baseName: parsed.baseName,
      size: parsed.size,
      material: parsed.material,
      category: categoryMatch.canonicalCategoryName,
      theme: parsed.theme,
    }),
  };
};

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { useEffect, useState, useMemo, startTransition } from 'react';

import { useCatalogs } from '@/features/products/hooks/useProductSettingsQueries';
import {
  useUserPreferences,
  useUpdateUserPreferences,
} from '@/features/products/hooks/useUserPreferences';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { Catalog } from '@/shared/contracts/products/catalogs';
import type { ProductListPreferences } from '@/shared/contracts/products/filters';
import { AdminProductsPageLayout } from '@/shared/ui/admin-products-page-layout';
import { Button } from '@/shared/ui/button';
import { FormSection, FormField } from '@/shared/ui/form-section';
import { FormActions } from '@/shared/ui/FormActions';
import { Input } from '@/shared/ui/input';
import { LoadingState } from '@/shared/ui/LoadingState';
import { SelectSimple } from '@/shared/ui/select-simple';
import { useToast } from '@/shared/ui/toast';

import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

const DEFAULT_PREFERENCES: ProductListPreferences = {
  nameLocale: 'name_en',
  catalogFilter: 'all',
  currencyCode: 'PLN',
  pageSize: 50,
  thumbnailSource: 'file',
  filtersCollapsedByDefault: true,
  showTriggerRunFeedback: true,
  advancedFilterPresets: [],
  appliedAdvancedFilter: '',
  appliedAdvancedFilterPresetId: null,
};

const NAME_LOCALE_OPTIONS = [
  { value: 'name_en', label: 'English' },
  { value: 'name_pl', label: 'Polish' },
  { value: 'name_de', label: 'German' },
] as const satisfies ReadonlyArray<LabeledOptionDto<'name_en' | 'name_pl' | 'name_de'>>;

const ALL_CATALOGS_OPTION: LabeledOptionDto<string> = {
  value: 'all',
  label: 'All Catalogs',
};

const THUMBNAIL_SOURCE_OPTIONS = [
  { value: 'file', label: 'File Uploads' },
  { value: 'link', label: 'URL Links' },
  { value: 'base64', label: 'Base64' },
] as const satisfies ReadonlyArray<LabeledOptionDto<'file' | 'link' | 'base64'>>;

const PAGE_SIZE_OPTIONS = ['10', '25', '50', '100', '200'].map((size: string) => ({
  value: size,
  label: size,
})) as ReadonlyArray<LabeledOptionDto<string>>;

const FILTER_VISIBILITY_OPTIONS = [
  { value: 'shown', label: 'Show Filters' },
  { value: 'hidden', label: 'Hide Filters' },
] as const satisfies ReadonlyArray<LabeledOptionDto<'shown' | 'hidden'>>;

const TRIGGER_RUN_FEEDBACK_OPTIONS = [
  { value: 'shown', label: 'Show Pills' },
  { value: 'hidden', label: 'Hide Pills' },
] as const satisfies ReadonlyArray<LabeledOptionDto<'shown' | 'hidden'>>;

export function ProductPreferencesPage(): React.JSX.Element {
  const { toast } = useToast();
  const router = useRouter();
  const { preferences: savedPreferences, loading: prefsLoading } = useUserPreferences();
  const catalogsQuery = useCatalogs();
  const catalogs = useMemo(() => catalogsQuery.data || [], [catalogsQuery.data]);
  const catalogOptions = useMemo(
    (): Array<LabeledOptionDto<string>> => [
      ALL_CATALOGS_OPTION,
      ...catalogs.map((catalog: Catalog) => ({
        value: catalog.id,
        label: catalog.name,
      })),
    ],
    [catalogs]
  );

  const [preferences, setPreferences] = useState<ProductListPreferences>(DEFAULT_PREFERENCES);
  const updateMutation = useUpdateUserPreferences();

  useEffect(() => {
    let timer: NodeJS.Timeout | null = null;
    if (savedPreferences) {
      timer = setTimeout(() => {
        setPreferences((prev: ProductListPreferences) => {
          // Only update if actually different to minimize cascading renders
          if (JSON.stringify(prev) === JSON.stringify(savedPreferences)) return prev;
          return savedPreferences;
        });
      }, 0);
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [savedPreferences]);

  const handleSave = async (): Promise<void> => {
    try {
      await updateMutation.mutateAsync(preferences);
      toast('Preferences saved successfully', { variant: 'success' });
      startTransition(() => { router.push('/admin/products'); });
    } catch (error) {
      logClientCatch(error, { source: 'ProductPreferencesPage', action: 'handleSave' });
      toast('Failed to save preferences', { variant: 'error' });
    }
  };

  const handleResetToDefault = async (): Promise<void> => {
    try {
      await updateMutation.mutateAsync(DEFAULT_PREFERENCES);
      setPreferences(DEFAULT_PREFERENCES);
      toast('Preferences reset to default', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'ProductPreferencesPage',
        action: 'handleResetToDefault',
      });
      toast('Failed to reset preferences', { variant: 'error' });
    }
  };

  if (prefsLoading || catalogsQuery.isLoading) {
    return (
      <div className='flex min-h-[400px] items-center justify-center'>
        <LoadingState message='Loading preferences...' />
      </div>
    );
  }

  return (
    <AdminProductsPageLayout
      title='Product Preferences'
      current='Preferences'
      description='Manage your product list display and navigation preferences'
    >
      <div className='space-y-6'>
        <FormSection title='Product List Settings' className='p-6'>
          <div className='space-y-4'>
            {/* Name Locale */}
            <FormField
              label='Product Name Language'
              description='Default language for product names in the list'
            >
              <SelectSimple
                size='sm'
                value={preferences.nameLocale || 'name_en'}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    nameLocale: value as 'name_en' | 'name_pl' | 'name_de',
                  }))
                }
                options={NAME_LOCALE_OPTIONS}
               ariaLabel='Product Name Language' title='Product Name Language'/>
            </FormField>

            {/* Default Catalog Filter */}
            <FormField
              label='Default Catalog Filter'
              description='Default catalog filter when opening the product list'
            >
              <SelectSimple
                size='sm'
                value={preferences.catalogFilter || 'all'}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    catalogFilter: value,
                  }))
                }
                options={catalogOptions}
               ariaLabel='Default Catalog Filter' title='Default Catalog Filter'/>
            </FormField>

            {/* Currency Code */}
            <FormField
              label='Preferred Currency'
              description='Preferred currency code for price display (leave empty for catalog default)'
            >
              <Input
                id='currencyCode'
                value={preferences.currencyCode || ''}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    currencyCode: e.target.value || 'PLN',
                  }))
                }
                placeholder='EUR, USD, PLN, etc.'
               aria-label='EUR, USD, PLN, etc.' title='EUR, USD, PLN, etc.'/>
            </FormField>

            {/* Thumbnail Source */}
            <FormField
              label='Thumbnail Source'
              description='Choose which image source is used for product list thumbnails'
            >
              <SelectSimple
                size='sm'
                value={preferences.thumbnailSource || 'file'}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    thumbnailSource: value as 'file' | 'link' | 'base64',
                  }))
                }
                options={THUMBNAIL_SOURCE_OPTIONS}
               ariaLabel='Thumbnail Source' title='Thumbnail Source'/>
            </FormField>

            {/* Page Size */}
            <FormField
              label='Products Per Page'
              description='Number of products to display per page'
            >
              <SelectSimple
                size='sm'
                value={String(preferences.pageSize || 50)}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    pageSize: parseInt(value, 10),
                  }))
                }
                options={PAGE_SIZE_OPTIONS}
               ariaLabel='Products Per Page' title='Products Per Page'/>
            </FormField>

            {/* Filter Toggle Default */}
            <FormField
              label='Filters Button Default'
              description='Choose whether the Product List starts with filters shown or hidden'
            >
              <SelectSimple
                size='sm'
                value={preferences.filtersCollapsedByDefault ? 'hidden' : 'shown'}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    filtersCollapsedByDefault: value === 'hidden',
                  }))
                }
                options={FILTER_VISIBILITY_OPTIONS}
               ariaLabel='Filters Button Default' title='Filters Button Default'/>
            </FormField>

            <FormField
              label='Trigger Run Feedback Pills'
              description='Show or hide AI trigger run feedback pills across the product list'
            >
              <SelectSimple
                size='sm'
                value={preferences.showTriggerRunFeedback ? 'shown' : 'hidden'}
                onValueChange={(value: string) =>
                  setPreferences((prev: ProductListPreferences) => ({
                    ...prev,
                    showTriggerRunFeedback: value === 'shown',
                  }))
                }
                options={TRIGGER_RUN_FEEDBACK_OPTIONS}
               ariaLabel='Trigger Run Feedback Pills' title='Trigger Run Feedback Pills'/>
            </FormField>
          </div>
        </FormSection>

        {/* Action Buttons */}
        <FormActions
          onSave={() => void handleSave()}
          onCancel={() => startTransition(() => { router.push('/admin/products'); })}
          saveText='Save Preferences'
          isSaving={updateMutation.isPending}
          className='flex-row-reverse justify-between'
        >
          <Button
            type='button'
            variant='outline'
            onClick={() => void handleResetToDefault()}
            disabled={updateMutation.isPending}
            className='border-yellow-600 text-yellow-600 hover:bg-yellow-600/10'
          >
            Reset to Default
          </Button>
        </FormActions>
      </div>
    </AdminProductsPageLayout>
  );
}

