import { ValidatorSettings } from '@/features/products/components/settings/ValidatorSettings';
import {
  useCatalogs,
  useCategories,
  useCustomFields,
  useDeleteCatalogMutation,
  useDeletePriceGroupMutation,
  useParameters,
  usePriceGroups,
  useShippingGroups,
  useTags,
  useUpdatePriceGroupMutation,
} from '@/features/products/hooks/useProductSettingsQueries';
import type { Catalog, PriceGroup } from '@/shared/contracts/products/catalogs';
import { AdminProductsPageLayout } from '@/shared/ui/admin-products-page-layout';
import { Button } from '@/shared/ui/button';
import { Card } from '@/shared/ui/card';
import { UI_GRID_ROOMY_CLASSNAME } from '@/shared/ui/layout';
import { ConfirmModal } from '@/shared/ui/templates/modals/ConfirmModal';
import { useToast } from '@/shared/ui/toast';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

import { settingSections } from './ProductSettingsConstants';
import { ProductDefaultsForm } from './product-settings/ProductDefaultsForm';
import { ProductLabelingSettings } from './product-settings/ProductLabelingSettings';
import { TaxationSettingsPanel } from './product-settings/TaxationSettingsPanel';
import { useProductSettingsController } from './product-settings/useProductSettingsController';

export type ProductSettingsPageProps = {
  internationalizationSettingsSlot?: ReactNode;
  internationalizationProvider?: ComponentType<{ children: ReactNode }>;
  internationalizationModalsSlot?: ReactNode;
  productSyncSettingsSlot?: ReactNode;
};

const PassthroughProvider = ({ children }: { children: ReactNode }): JSX.Element => <>{children}</>;

const toSettingSectionSlug = (section: (typeof settingSections)[number]): string =>
  section
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

const resolveSettingSectionFromParam = (
  value: string | null | undefined
): (typeof settingSections)[number] | null => {
  const normalized = (value ?? '').trim().toLowerCase();
  if (!normalized) return null;
  return settingSections.find((section) => toSettingSectionSlug(section) === normalized) ?? null;
};

const ProductDefaultsSettingsSection = (): JSX.Element => {
  const ctrl = useProductSettingsController();

  return (
    <div className='space-y-6'>
      <ProductDefaultsForm
        settings={ctrl.settings}
        onUpdate={ctrl.handleUpdate}
        onSave={ctrl.saveSettings}
        isSaving={ctrl.isSaving}
      />
      <ProductLabelingSettings settings={ctrl.settings} onUpdate={ctrl.handleUpdate} />
      <TaxationSettingsPanel settings={ctrl.settings} onUpdate={ctrl.handleUpdate} />
    </div>
  );
};

export function ProductSettingsPage({
  internationalizationSettingsSlot,
  internationalizationProvider: InternationalizationProvider = PassthroughProvider,
  internationalizationModalsSlot,
  productSyncSettingsSlot,
}: ProductSettingsPageProps = {}): JSX.Element {
  const searchParams = useSearchParams();
  const requestedSection = resolveSettingSectionFromParam(searchParams?.get('section'));
  const [activeSection, setActiveSection] =
    useState<(typeof settingSections)[number]>(requestedSection ?? 'Categories');

  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [editingCatalog, setEditingCatalog] = useState<Catalog | null>(null);
  const [showPriceGroupModal, setShowPriceGroupModal] = useState(false);
  const [editingPriceGroup, setEditingPriceGroup] = useState<PriceGroup | null>(null);
  const [confirmation, setConfirmation] = useState<{
    title: string;
    message: string;
    onConfirm: () => void | Promise<void>;
    confirmText?: string;
    isDangerous?: boolean;
  } | null>(null);

  const { toast } = useToast();
  const isCategoriesSectionActive = activeSection === 'Categories';
  const isShippingGroupsSectionActive = activeSection === 'Shipping Groups';
  const isTagsSectionActive = activeSection === 'Tags';
  const isCustomFieldsSectionActive = activeSection === 'Custom Fields';
  const isParametersSectionActive = activeSection === 'Parameters';
  const isPriceGroupsSectionActive = activeSection === 'Price Groups';
  const isCatalogsSectionActive = activeSection === 'Catalogs';
  const shouldLoadCatalogs =
    isCategoriesSectionActive ||
    isShippingGroupsSectionActive ||
    isTagsSectionActive ||
    isParametersSectionActive ||
    isCatalogsSectionActive;
  const shouldLoadPriceGroups =
    isPriceGroupsSectionActive || showCatalogModal || showPriceGroupModal;

  const { data: priceGroups = [], isLoading: loadingGroups } = usePriceGroups({
    enabled: shouldLoadPriceGroups,
  });
  const { data: catalogs = [], isLoading: loadingCatalogs } = useCatalogs({
    enabled: shouldLoadCatalogs,
  });

  const [selectedCategoryCatalogId, setSelectedCategoryCatalogId] = useState<string | null>(null);
  const [selectedShippingGroupCatalogId, setSelectedShippingGroupCatalogId] = useState<
    string | null
  >(null);
  const [selectedTagCatalogId, setSelectedTagCatalogId] = useState<string | null>(null);
  const [selectedParameterCatalogId, setSelectedParameterCatalogId] = useState<string | null>(null);

  const {
    data: productCategories = [],
    isLoading: loadingCategories,
    refetch: refetchCategories,
  } = useCategories(selectedCategoryCatalogId, { enabled: isCategoriesSectionActive });
  const {
    data: shippingGroups = [],
    isLoading: loadingShippingGroups,
    refetch: refetchShippingGroups,
  } = useShippingGroups(selectedShippingGroupCatalogId, {
    enabled: isShippingGroupsSectionActive,
  });
  const {
    data: productTags = [],
    isLoading: loadingTags,
    refetch: refetchTags,
  } = useTags(selectedTagCatalogId, { enabled: isTagsSectionActive });
  const {
    data: productCustomFields = [],
    isLoading: loadingCustomFields,
    refetch: refetchCustomFields,
  } = useCustomFields({ enabled: isCustomFieldsSectionActive });
  const {
    data: productParameters = [],
    isLoading: loadingParameters,
    refetch: refetchParameters,
  } = useParameters(selectedParameterCatalogId, { enabled: isParametersSectionActive });

  const updatePriceGroupMutation = useUpdatePriceGroupMutation();
  const deletePriceGroupMutation = useDeletePriceGroupMutation();
  const deleteCatalogMutation = useDeleteCatalogMutation();

  const defaultGroupId = priceGroups.find((group: PriceGroup) => group.isDefault)?.id ?? '';

  useEffect(() => {
    if (!requestedSection || requestedSection === activeSection) return;
    setActiveSection(requestedSection);
  }, [activeSection, requestedSection]);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout> | null = null;
    if (catalogs.length > 0 && shouldLoadCatalogs) {
      timer = setTimeout(() => {
        const defaultCatalog = catalogs.find((catalog: Catalog) => catalog.isDefault) ?? catalogs[0];
        if (!defaultCatalog) return;

        if (isCategoriesSectionActive && !selectedCategoryCatalogId) {
          setSelectedCategoryCatalogId(defaultCatalog.id);
        }
        if (isShippingGroupsSectionActive && !selectedShippingGroupCatalogId) {
          setSelectedShippingGroupCatalogId(defaultCatalog.id);
        }
        if (isTagsSectionActive && !selectedTagCatalogId) {
          setSelectedTagCatalogId(defaultCatalog.id);
        }
        if (isParametersSectionActive && !selectedParameterCatalogId) {
          setSelectedParameterCatalogId(defaultCatalog.id);
        }
      }, 0);
    }
    return (): void => {
      if (timer) clearTimeout(timer);
    };
  }, [
    catalogs,
    isCategoriesSectionActive,
    isParametersSectionActive,
    isShippingGroupsSectionActive,
    isTagsSectionActive,
    selectedCategoryCatalogId,
    selectedParameterCatalogId,
    selectedShippingGroupCatalogId,
    selectedTagCatalogId,
    shouldLoadCatalogs,
  ]);

  const handleSetDefaultGroup = async (groupId: string): Promise<void> => {
    const group = priceGroups.find((candidate: PriceGroup) => candidate.id === groupId);
    if (!group) return;
    try {
      await updatePriceGroupMutation.mutateAsync({ ...group, isDefault: true });
      toast('Default price group updated.', { variant: 'success' });
    } catch (error) {
      logClientCatch(error, {
        source: 'ProductSettingsPage',
        action: 'handleSetDefaultGroup',
        groupId,
      });
    }
  };

  const handleDeleteCatalog = async (catalog: Catalog): Promise<void> => {
    setConfirmation({
      title: 'Delete Catalog?',
      message: `Delete catalog "${catalog.name}"? This action cannot be undone and will affect all products in this catalog.`,
      confirmText: 'Delete Catalog',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deleteCatalogMutation.mutateAsync(catalog.id);
          toast('Catalog deleted.', { variant: 'success' });
        } catch (err) {
          logClientCatch(err, {
            source: 'ProductSettingsPage',
            action: 'handleDeleteCatalog',
            catalogId: catalog.id,
          });
          toast('Failed to delete catalog.', { variant: 'error' });
        }
      },
    });
  };

  const handleDeleteGroup = async (group: PriceGroup): Promise<void> => {
    if (priceGroups.length <= 1) {
      toast('At least one price group is required.', { variant: 'error' });
      return;
    }
    setConfirmation({
      title: 'Delete Price Group?',
      message: `Delete price group "${group.name}"? This will remove all associated price records.`,
      confirmText: 'Delete Group',
      isDangerous: true,
      onConfirm: async () => {
        try {
          await deletePriceGroupMutation.mutateAsync(group.id);
          toast('Price group deleted.', { variant: 'success' });
        } catch (err) {
          logClientCatch(err, {
            source: 'ProductSettingsPage',
            action: 'handleDeleteGroup',
            groupId: group.id,
          });
          toast('Failed to delete price group.', { variant: 'error' });
        }
      },
    });
  };

  const sharedSettingsContextValue: ComponentProps<typeof ProductSettingsProvider>['value'] = {
    loadingCatalogs,
    catalogs,
    onOpenCatalogModal: (): void => {
      setEditingCatalog(null);
      setShowCatalogModal(true);
    },
    onEditCatalog: (catalog: Catalog): void => {
      setEditingCatalog(catalog);
      setShowCatalogModal(true);
    },
    onDeleteCatalog: (catalog: Catalog): void => {
      void handleDeleteCatalog(catalog);
    },
    loadingGroups,
    priceGroups,
    defaultGroupId,
    onDefaultGroupChange: (id: string): void => {
      void handleSetDefaultGroup(id);
    },
    defaultGroupSaving: updatePriceGroupMutation.isPending,
    onOpenPriceGroupCreate: (): void => {
      setEditingPriceGroup(null);
      setShowPriceGroupModal(true);
    },
    onEditPriceGroup: (group: PriceGroup): void => {
      setEditingPriceGroup(group);
      setShowPriceGroupModal(true);
    },
    onDeletePriceGroup: (group: PriceGroup): void => {
      void handleDeleteGroup(group);
    },
    loadingCategories,
    categories: productCategories,
    selectedCategoryCatalogId,
    onCategoryCatalogChange: (id: string | null): void => {
      setSelectedCategoryCatalogId(id);
    },
    onRefreshCategories: (): void => {
      void refetchCategories();
    },
    loadingShippingGroups,
    shippingGroups,
    selectedShippingGroupCatalogId,
    onShippingGroupCatalogChange: (id: string | null): void => {
      setSelectedShippingGroupCatalogId(id);
    },
    onRefreshShippingGroups: (): void => {
      void refetchShippingGroups();
    },
    loadingTags,
    tags: productTags,
    selectedTagCatalogId,
    onTagCatalogChange: (id: string | null): void => {
      setSelectedTagCatalogId(id);
    },
    onRefreshTags: (): void => {
      void refetchTags();
    },
    loadingParameters,
    parameters: productParameters,
    selectedParameterCatalogId,
    onParameterCatalogChange: (id: string | null): void => {
      setSelectedParameterCatalogId(id);
    },
    onRefreshParameters: (): void => {
      void refetchParameters();
    },
  };

  return (
    <InternationalizationProvider>
      <AdminProductsPageLayout title='Product Settings' current='Settings'>
        <Card variant='subtle-compact' padding='sm' className='mb-4 border-border/60 bg-card/30'>
          <div className='flex flex-wrap items-center justify-between gap-3'>
            <div>
              <p className='text-sm font-medium text-gray-100'>Image Studio Integration</p>
              <p className='text-xs text-gray-400'>
                Configure default Studio project binding and start Product to Image Studio
                connection.
              </p>
            </div>
            <Button
              size='xs'
              type='button'
              variant='outline'
              onClick={(): void => setActiveSection('Images & Studio')}
            >
              Open Integration Settings
            </Button>
          </div>
        </Card>
        <Card variant='subtle-compact' padding='sm' className='mb-4 border-border/60 bg-card/30'>
          <div className='flex flex-wrap items-center justify-between gap-3'>
            <div>
              <p className='text-sm font-medium text-gray-100'>Structured Product Name Terms</p>
              <p className='text-xs text-gray-400'>
                Manage catalog-specific size, material, and theme lists used by the English product
                name composer.
              </p>
            </div>
            <Button size='xs' type='button' variant='outline' asChild>
              <Link href='/admin/products/title-terms'>Open Title Terms</Link>
            </Button>
          </div>
        </Card>

        <div className={`${UI_GRID_ROOMY_CLASSNAME} md:grid-cols-[240px_1fr]`}>
          <Card variant='subtle' padding='md' className='border-border/60 bg-card/40'>
            <div className='flex flex-col gap-2'>
              {settingSections.map((section: (typeof settingSections)[number]) => (
                <Button
                  size='xs'
                  key={section}
                  variant={activeSection === section ? 'secondary' : 'ghost'}
                  onClick={(): void => setActiveSection(section)}
                  className='justify-start px-3 py-2 text-left text-sm'
                >
                  {section}
                </Button>
              ))}
            </div>
          </Card>

          <ProductSettingsProvider value={sharedSettingsContextValue}>
            <Card variant='subtle' padding='lg' className='border-border/60 bg-card/40'>
              {activeSection === 'Categories' && <CategoriesSettings />}
              {activeSection === 'Shipping Groups' && <ShippingGroupsSettings />}
              {activeSection === 'Tags' && <TagsSettings />}
              {activeSection === 'Custom Fields' && (
                <CustomFieldsSettings
                  loading={loadingCustomFields}
                  customFields={productCustomFields}
                  onRefresh={(): void => {
                    void refetchCustomFields();
                  }}
                />
              )}
              {activeSection === 'Parameters' && (
                <ParametersSettings
                  loading={loadingParameters}
                  parameters={productParameters}
                  catalogs={catalogs}
                  selectedCatalogId={selectedParameterCatalogId}
                  onCatalogChange={(catalogId: string): void =>
                    setSelectedParameterCatalogId(catalogId)
                  }
                  onRefresh={(): void => {
                    void refetchParameters();
                  }}
                />
              )}
              {activeSection === 'Price Groups' && <PriceGroupsSettings />}
              {activeSection === 'Catalogs' && <CatalogsSettings />}
              {activeSection === 'Defaults' && <ProductDefaultsSettingsSection />}
              {activeSection === 'Sync Settings' &&
                (productSyncSettingsSlot ?? <div>Product Sync Settings is not available.</div>)}
              {activeSection === 'Images & Studio' && <ProductImageRoutingSettings />}
              {activeSection === 'Validator' && (
                <ValidatorDocsTooltipsProvider>
                  <div className='space-y-5'>
                    <ValidatorDefaultPanel />
                    <ValidatorSettings />
                  </div>
                </ValidatorDocsTooltipsProvider>
              )}
              {activeSection === 'Internationalization' &&
                (internationalizationSettingsSlot ?? (
                  <div>Internationalization Settings is not available.</div>
                ))}
            </Card>
          </ProductSettingsProvider>
        </div>

        {showCatalogModal && (
          <CatalogModal
            isOpen={showCatalogModal}
            onClose={(): void => setShowCatalogModal(false)}
            onSuccess={(): void => {
              setShowCatalogModal(false);
            }}
            item={editingCatalog}
            items={priceGroups}
            loading={loadingGroups}
            defaultId={defaultGroupId}
          />
        )}

        {showPriceGroupModal && (
          <PriceGroupModal
            isOpen={showPriceGroupModal}
            onClose={(): void => setShowPriceGroupModal(false)}
            onSuccess={(): void => {
              setShowPriceGroupModal(false);
            }}
            item={editingPriceGroup}
            items={priceGroups}
          />
        )}

        {internationalizationModalsSlot}

        <ConfirmModal
          isOpen={Boolean(confirmation)}
          onClose={(): void => setConfirmation(null)}
          title={confirmation?.title ?? ''}
          message={confirmation?.message ?? ''}
          confirmText={confirmation?.confirmText ?? 'Confirm'}
          isDangerous={confirmation?.isDangerous ?? false}
          onConfirm={async (): Promise<void> => {
            if (confirmation?.onConfirm) {
              await confirmation.onConfirm();
            }
            setConfirmation(null);
          }}
        />
      </AdminProductsPageLayout>
    </InternationalizationProvider>
  );
}

export default ProductSettingsPage;

import crypto from 'crypto';

import { type NextRequest } from 'next/server';

import { badRequestError } from '@/shared/errors/app-error';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

const CONTROL_CHARACTERS_PATTERN = /\p{Cc}/gu;

type FileValidationResult = {
  isValid: boolean;
  errors: string[];
  sanitizedName?: string;
  fileHash?: string;
};

type UploadConfig = {
  maxFileSize: number;
  allowedMimeTypes: string[];
  allowedExtensions: string[];
  maxFiles: number;
  requireImageDimensions?: boolean;
  maxWidth?: number;
  maxHeight?: number;
};

export class SecureFileUpload {
  private static readonly DANGEROUS_EXTENSIONS: string[] = [
    '.exe',
    '.bat',
    '.cmd',
    '.com',
    '.pif',
    '.scr',
    '.vbs',
    '.js',
    '.jar',
    '.php',
    '.asp',
    '.aspx',
    '.jsp',
    '.py',
    '.rb',
    '.pl',
    '.sh',
    '.ps1',
  ];

  private static readonly IMAGE_MIME_TYPES: string[] = [
    'image/jpeg',
    'image/jpg',
    'image/png',
    'image/webp',
    'image/gif',
    'image/svg+xml',
  ];

  private static readonly DEFAULT_CONFIG: UploadConfig = {
    maxFileSize: 10 * 1024 * 1024, // 10MB
    allowedMimeTypes: this.IMAGE_MIME_TYPES,
    allowedExtensions: ['.jpg', '.jpeg', '.png', '.webp', '.gif'],
    maxFiles: 5,
    requireImageDimensions: true,
    maxWidth: 4000,
    maxHeight: 4000,
  };

  static async validateFile(
    file: File,
    config: Partial<UploadConfig> = {}
  ): Promise<FileValidationResult> {
    const cfg = { ...this.DEFAULT_CONFIG, ...config };
    const errors: string[] = [];

    // Check file size
    if (file.size > cfg.maxFileSize) {
      errors.push(`File size exceeds ${cfg.maxFileSize / (1024 * 1024)}MB limit`);
    }

    // Check MIME type
    if (!cfg.allowedMimeTypes.includes(file.type)) {
      errors.push(`File type ${file.type} not allowed`);
    }

    // Check file extension
    const extension = this.getFileExtension(file.name).toLowerCase();
    if (!cfg.allowedExtensions.includes(extension)) {
      errors.push(`File extension ${extension} not allowed`);
    }

    // Check for dangerous extensions
    if (this.DANGEROUS_EXTENSIONS.includes(extension)) {
      errors.push('Potentially dangerous file type detected');
    }

    // Validate file name
    const sanitizedName = this.sanitizeFileName(file.name);
    if (!sanitizedName) {
      errors.push('Invalid file name');
    }

    // Check file content (magic bytes)
    const buffer = await file.arrayBuffer();
    const isValidImage = this.validateImageMagicBytes(new Uint8Array(buffer), file.type);
    if (!isValidImage) {
      errors.push('File content does not match declared type');
    }

    // Generate file hash for deduplication
    const fileHash = await this.generateFileHash(buffer);

    // Check image dimensions if required
    if (cfg.requireImageDimensions && this.IMAGE_MIME_TYPES.includes(file.type)) {
      try {
        const dimensions = this.getImageDimensions(buffer);
        if (cfg.maxWidth && dimensions.width > cfg.maxWidth) {
          errors.push(`Image width ${dimensions.width}px exceeds ${cfg.maxWidth}px limit`);
        }
        if (cfg.maxHeight && dimensions.height > cfg.maxHeight) {
          errors.push(`Image height ${dimensions.height}px exceeds ${cfg.maxHeight}px limit`);
        }
      } catch (error) {
        logClientError(error);
        errors.push('Unable to read image dimensions');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
      sanitizedName,
      fileHash,
    };
  }

  static async validateMultipleFiles(
    files: File[],
    config: Partial<UploadConfig> = {}
  ): Promise<{
    isValid: boolean;
    results: Array<FileValidationResult & { fileName: string }>;
    globalErrors: string[];
  }> {
    const cfg = { ...this.DEFAULT_CONFIG, ...config };
    const globalErrors: string[] = [];

    // Check file count
    if (files.length > cfg.maxFiles) {
      globalErrors.push(`Too many files. Maximum ${cfg.maxFiles} allowed`);
    }

    // Check total size
    const totalSize = files.reduce((sum: number, file: File) => sum + file.size, 0);
    const maxTotalSize = cfg.maxFileSize * cfg.maxFiles;
    if (totalSize > maxTotalSize) {
      globalErrors.push(`Total file size exceeds ${maxTotalSize / (1024 * 1024)}MB limit`);
    }

    // Validate each file
    const results = await Promise.all(
      files.map(async (file: File) => ({
        fileName: file.name,
        ...(await this.validateFile(file, config)),
      }))
    );

    // Check for duplicate files
    const hashes = results.map((r: FileValidationResult) => r.fileHash).filter(Boolean);
    const duplicates = hashes.filter(
      (hash: string | undefined, index: number) => hashes.indexOf(hash) !== index
    );
    if (duplicates.length > 0) {
      globalErrors.push('Duplicate files detected');
    }

    return {
      isValid: globalErrors.length === 0 && results.every((r: FileValidationResult) => r.isValid),
      results,
      globalErrors,
    };
  }

  private static getFileExtension(fileName: string): string {
    const lastDot = fileName.lastIndexOf('.');
    return lastDot === -1 ? '' : fileName.substring(lastDot);
  }

  private static sanitizeFileName(fileName: string): string {
    // Remove path traversal attempts
    let sanitized = fileName.replace(/[/\\:*?"<>|]/g, '');

    // Remove null bytes and control characters
    sanitized = sanitized.replace(CONTROL_CHARACTERS_PATTERN, '');

    // Limit length
    if (sanitized.length > 255) {
      const ext = this.getFileExtension(sanitized);
      const nameWithoutExt = sanitized.substring(0, sanitized.lastIndexOf('.'));
      sanitized = nameWithoutExt.substring(0, 255 - ext.length) + ext;
    }

    // Ensure it's not empty or just dots
    if (!sanitized || /^\.+$/.test(sanitized)) {
      return '';
    }

    return sanitized;
  }

  private static validateImageMagicBytes(bytes: Uint8Array, mimeType: string): boolean {
    const signatures: Record<string, number[][]> = {
      'image/jpeg': [[0xff, 0xd8, 0xff]],
      'image/png': [[0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]],
      'image/gif': [
        [0x47, 0x49, 0x46, 0x38, 0x37, 0x61],
        [0x47, 0x49, 0x46, 0x38, 0x39, 0x61],
      ],
      'image/webp': [
        [0x52, 0x49, 0x46, 0x46],
        [0x57, 0x45, 0x42, 0x50],
      ],
      'image/svg+xml': [
        [0x3c, 0x3f, 0x78, 0x6d, 0x6c],
        [0x3c, 0x73, 0x76, 0x67],
      ],
    };

    const sigs = signatures[mimeType];
    if (!sigs) return false;

    return sigs.some((sig: number[]) =>
      sig.every((byte: number, index: number) => bytes[index] === byte)
    );
  }

  private static async generateFileHash(buffer: ArrayBuffer): Promise<string> {
    const hashBuffer = await crypto.subtle.digest('SHA-256', buffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map((b: number) => b.toString(16).padStart(2, '0')).join('');
  }

  private static getImageDimensions(buffer: ArrayBuffer): { width: number; height: number } {
    const bytes = new Uint8Array(buffer);

    // PNG: magic bytes 89 50 4E 47, IHDR chunk at offset 8 contains width/height
    if (bytes[0] === 0x89 && bytes[1] === 0x50) {
      if (bytes.length < 24) throw badRequestError('Invalid PNG buffer');
      const width = (bytes[16]! << 24) | (bytes[17]! << 16) | (bytes[18]! << 8) | bytes[19]!;
      const height = (bytes[20]! << 24) | (bytes[21]! << 16) | (bytes[22]! << 8) | bytes[23]!;
      return { width, height };
    }

    // JPEG: scan for SOF (Start Of Frame) marker to read real dimensions
    if (bytes[0] === 0xff && bytes[1] === 0xd8) {
      let i = 2;
      while (i + 1 < bytes.length) {
        if (bytes[i] !== 0xff) break;
        const marker = bytes[i + 1]!;
        // SOF markers C0–CF encode image dimensions, except:
        //   C4 = DHT (Huffman table), C8 = JPEG extension, CC = DAC
        if (
          marker >= 0xc0 &&
          marker <= 0xcf &&
          marker !== 0xc4 &&
          marker !== 0xc8 &&
          marker !== 0xcc
        ) {
          // SOF layout: FF Cx <length 2B> <precision 1B> <height 2B> <width 2B>
          if (i + 8 >= bytes.length) break;
          const height = (bytes[i + 5]! << 8) | bytes[i + 6]!;
          const width = (bytes[i + 7]! << 8) | bytes[i + 8]!;
          if (width > 0 && height > 0) return { width, height };
        }
        // EOI — end of image
        if (marker === 0xd9) break;
        // Markers without a length field: RST0–RST7 (D0–D7), SOI (D8), EOI (D9), TEM (01)
        if (marker === 0x01 || (marker >= 0xd0 && marker <= 0xd9)) {
          i += 2;
          continue;
        }
        // All other markers carry a 2-byte length field (the length includes itself)
        if (i + 3 >= bytes.length) break;
        const segLength = (bytes[i + 2]! << 8) | bytes[i + 3]!;
        if (segLength < 2) break;
        i += 2 + segLength;
      }
      throw badRequestError('Could not parse JPEG dimensions');
    }

    throw badRequestError('Unsupported image format for dimension reading');
  }
}

// Middleware for secure file upload
export async function withSecureFileUpload(
  req: NextRequest,
  config?: Partial<UploadConfig>
): Promise<{
  isValid: boolean;
  files?: File[];
  errors: string[];
  sanitizedFiles?: Array<{ file: File; sanitizedName: string; hash: string }>;
}> {
  try {
    const formData = await req.formData();
    const files: File[] = [];

    // Extract files from form data
    for (const [_key, value] of formData.entries()) {
      if (value instanceof File) {
        files.push(value);
      }
    }

    if (files.length === 0) {
      return { isValid: false, errors: ['No files provided'] };
    }

    const validation = await SecureFileUpload.validateMultipleFiles(files, config);

    if (!validation.isValid) {
      const allErrors = [
        ...validation.globalErrors,
        ...validation.results.flatMap((r: FileValidationResult) => r.errors),
      ];
      return { isValid: false, errors: allErrors };
    }

    const sanitizedFiles = validation.results.map(
      (result: FileValidationResult, index: number) => ({
        file: files[index]!,
        sanitizedName: result.sanitizedName!,
        hash: result.fileHash!,
      })
    );

    return {
      isValid: true,
      files,
      errors: [],
      sanitizedFiles,
    };
  } catch (error) {
    logClientError(error);
    return {
      isValid: false,
      errors: ['Failed to process file upload'],
    };
  }
}

import 'server-only';

import path from 'node:path';

import { z } from 'zod';

import {
  readPlaywrightEngineArtifact,
  type PlaywrightEngineRunRecord,
} from '@/features/playwright/server';
import type {
  ProductScanRecord,
  ProductScanSupplierEvaluation,
  NonNullableProductScanSupplierEvaluation,
} from '@/shared/contracts/product-scans';
import type { ProductWithImages } from '@/shared/contracts/products/product';
import { runBrainChatCompletion } from '@/shared/lib/ai-brain/server-runtime-client';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

import {
  buildProductScanImagePart,
  loadProductScanImageSourceAsDataUrl,
  PRODUCT_SCAN_SUPPORTED_IMAGE_RUNTIME_VENDORS,
  productScanBufferToDataUrl,
} from './product-scan-ai-evaluator.shared';
import type { ProductScanner1688CandidateEvaluatorResolvedConfig } from './product-scanner-settings';
import type { SupplierScanRuntimeResult } from './product-scans-service.helpers';

const SUPPLIER_EVALUATOR_MAX_REASON_COUNT = 10;

const supplierEvaluatorResponseSchema = z.object({
  sameProduct: z.boolean(),
  imageMatch: z.boolean().nullable().optional().default(null),
  titleMatch: z.boolean().nullable().optional().default(null),
  confidence: z.preprocess(
    (value) => {
      const parsed =
        typeof value === 'number'
          ? value
          : typeof value === 'string' && value.trim().length > 0
            ? Number(value)
            : Number.NaN;
      if (!Number.isFinite(parsed)) {
        return Number.NaN;
      }
      if (parsed > 1 && parsed <= 100) {
        return parsed / 100;
      }
      return parsed;
    },
    z.number().min(0).max(1)
  ),
  proceed: z.boolean(),
  reasons: z.array(z.string().trim().min(1).max(500)).max(SUPPLIER_EVALUATOR_MAX_REASON_COUNT).default([]),
  mismatches: z
    .array(z.string().trim().min(1).max(500))
    .max(SUPPLIER_EVALUATOR_MAX_REASON_COUNT)
    .default([]),
});

const readOptionalString = (value: unknown): string | null =>
  typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;

const normalizeTextList = (values: Array<string | null | undefined>): string[] => {
  const seen = new Set<string>();
  const normalized: string[] = [];
  for (const value of values) {
    const next = readOptionalString(value);
    if (!next || seen.has(next)) {
      continue;
    }
    seen.add(next);
    normalized.push(next);
  }
  return normalized;
};

const resolveArtifactFileNameByKey = (
  run: Pick<PlaywrightEngineRunRecord, 'artifacts'>,
  artifactKey: string | null,
  mimePrefix: string
): string | null => {
  const normalizedKey = readOptionalString(artifactKey);
  if (!normalizedKey) {
    return null;
  }
  const artifact = (Array.isArray(run.artifacts) ? run.artifacts : []).find((entry) => {
    const artifactPath = entry.path || '';
    const baseName = readOptionalString(path.basename(artifactPath, path.extname(artifactPath)));
    return (
      entry.mimeType?.startsWith(mimePrefix) === true &&
      (entry.name === normalizedKey || baseName === normalizedKey)
    );
  });
  if (!artifact?.path) {
    return null;
  }
  const fileName = path.basename(artifact.path);
  return fileName.trim().length > 0 ? fileName : null;
};

const resolveProductImageSources = (
  scan: Pick<ProductScanRecord, 'imageCandidates'>,
  product: ProductWithImages
): string[] => {
  const fromScan = scan.imageCandidates.flatMap((candidate) => [
    readOptionalString(candidate.url),
    readOptionalString(candidate.filepath),
  ]);
  const fromProductImages = (Array.isArray(product.images) ? product.images : []).flatMap((image) => [
    readOptionalString(image.imageFile?.publicUrl),
    readOptionalString(image.imageFile?.url),
    readOptionalString(image.imageFile?.filepath),
  ]);
  const fromImageLinks = Array.isArray(product.imageLinks) ? product.imageLinks : [];

  return normalizeTextList([...fromScan, ...fromProductImages, ...fromImageLinks]).slice(0, 4);
};

const resolveSourceProductName = (
  product: ProductWithImages,
  scan: Pick<ProductScanRecord, 'productName'>
): string | null =>
  readOptionalString(product.name_en) ??
  readOptionalString(product.name_pl) ??
  readOptionalString(product.name_de) ??
  readOptionalString(scan.productName);

const resolveSourceProductDescription = (product: ProductWithImages): string | null =>
  readOptionalString(product.description_en) ??
  readOptionalString(product.description_pl) ??
  readOptionalString(product.description_de);

const createSupplierEvaluation = (
  input: Omit<NonNullableProductScanSupplierEvaluation, 'evaluatedAt'> & {
    evaluatedAt?: string | null;
  }
): ProductScanSupplierEvaluation => ({
  ...input,
  evaluatedAt: input.evaluatedAt ?? new Date().toISOString(),
});

export const evaluate1688SupplierCandidateMatch = async (input: {
  scan: ProductScanRecord;
  product: ProductWithImages;
  parsedResult: SupplierScanRuntimeResult;
  run: Pick<PlaywrightEngineRunRecord, 'runId' | 'artifacts'>;
  evaluatorConfig: Extract<ProductScanner1688CandidateEvaluatorResolvedConfig, { enabled: true }>;
}): Promise<ProductScanSupplierEvaluation> => {
  const heuristicEvaluation = input.parsedResult.supplierEvaluation;
  if (
    input.evaluatorConfig.onlyForAmbiguousCandidates &&
    heuristicEvaluation?.status === 'approved' &&
    heuristicEvaluation.proceed &&
    typeof heuristicEvaluation.confidence === 'number' &&
    heuristicEvaluation.confidence >= Math.max(input.evaluatorConfig.threshold, 0.9)
  ) {
    return createSupplierEvaluation({
      ...heuristicEvaluation,
      status: 'skipped',
      proceed: true,
      modelId: input.evaluatorConfig.modelId,
    });
  }

  const productImageSource = resolveProductImageSources(input.scan, input.product)[0] ?? null;
  if (!productImageSource) {
    return createSupplierEvaluation({
      status: 'failed',
      sameProduct: null,
      imageMatch: null,
      titleMatch: null,
      confidence: null,
      proceed: false,
      reasons: [],
      mismatches: [],
      modelId: input.evaluatorConfig.modelId,
      error: '1688 candidate evaluator could not load a source product image.',
    });
  }

  const productImageDataUrl = await loadProductScanImageSourceAsDataUrl(productImageSource).catch((error) => {
    void ErrorSystem.captureException(error, {
      service: 'product-scan-1688-evaluator',
      action: 'loadProductImage',
      productId: input.product.id,
      source: productImageSource,
    });
    return null;
  });
  if (!productImageDataUrl) {
    return createSupplierEvaluation({
      status: 'failed',
      sameProduct: null,
      imageMatch: null,
      titleMatch: null,
      confidence: null,
      proceed: false,
      reasons: [],
      mismatches: [],
      modelId: input.evaluatorConfig.modelId,
      error: '1688 candidate evaluator could not read the source product image.',
    });
  }

  const screenshotArtifactName = resolveArtifactFileNameByKey(
    input.run,
    readOptionalString(input.parsedResult.supplierProbe?.artifactKey),
    'image/'
  );
  if (!screenshotArtifactName) {
    return createSupplierEvaluation({
      status: 'failed',
      sameProduct: null,
      imageMatch: null,
      titleMatch: null,
      confidence: null,
      proceed: false,
      reasons: [],
      mismatches: [],
      modelId: input.evaluatorConfig.modelId,
      error: '1688 candidate evaluator could not find the supplier page screenshot artifact.',
    });
  }

  const screenshotArtifact = await readPlaywrightEngineArtifact({
    runId: input.run.runId,
    fileName: screenshotArtifactName,
  }).catch((error) => {
    void ErrorSystem.captureException(error, {
      service: 'product-scan-1688-evaluator',
      action: 'readSupplierScreenshotArtifact',
      productId: input.product.id,
      fileName: screenshotArtifactName,
    });
    return null;
  });
  if (!screenshotArtifact) {
    return createSupplierEvaluation({
      status: 'failed',
      sameProduct: null,
      imageMatch: null,
      titleMatch: null,
      confidence: null,
      proceed: false,
      reasons: [],
      mismatches: [],
      modelId: input.evaluatorConfig.modelId,
      error: '1688 candidate evaluator could not read the supplier page screenshot artifact.',
    });
  }

  const heroImageSource =
    readOptionalString(input.parsedResult.supplierProbe?.heroImageUrl) ??
    readOptionalString(input.parsedResult.supplierDetails?.images?.[0]?.url);
  const heroImageDataUrl = heroImageSource
    ? await loadProductScanImageSourceAsDataUrl(heroImageSource).catch((error) => {
        void ErrorSystem.captureException(error, {
          service: 'product-scan-1688-evaluator',
          action: 'loadSupplierHeroImage',
          productId: input.product.id,
          source: heroImageSource,
        });
        return null;
      })
    : null;

  const sourceProductName = resolveSourceProductName(input.product, input.scan);
  const sourceProductDescription = resolveSourceProductDescription(input.product);
  const supplierDetails = input.parsedResult.supplierDetails;
  const supplierProbe = input.parsedResult.supplierProbe;

  const promptPayload = {
    sourceProduct: {
      name: sourceProductName,
      description: sourceProductDescription,
      ean: readOptionalString(input.product.ean),
      gtin: readOptionalString(input.product.gtin),
      supplierName: readOptionalString(input.product.supplierName),
      supplierLink: readOptionalString(input.product.supplierLink),
    },
    supplierCandidate: {
      url:
        readOptionalString(supplierProbe?.canonicalUrl) ??
        readOptionalString(supplierProbe?.candidateUrl) ??
        readOptionalString(input.parsedResult.url),
      title: readOptionalString(supplierProbe?.pageTitle) ?? readOptionalString(input.parsedResult.title),
      description:
        readOptionalString(supplierProbe?.descriptionSnippet) ??
        readOptionalString(input.parsedResult.description),
      supplierName: readOptionalString(supplierDetails?.supplierName) ?? readOptionalString(supplierProbe?.supplierName),
      supplierStoreUrl:
        readOptionalString(supplierDetails?.supplierStoreUrl) ??
        readOptionalString(supplierProbe?.supplierStoreUrl),
      priceText: readOptionalString(supplierDetails?.priceText) ?? readOptionalString(supplierProbe?.priceText),
      priceRangeText: readOptionalString(supplierDetails?.priceRangeText),
      moqText: readOptionalString(supplierDetails?.moqText),
      currency: readOptionalString(supplierDetails?.currency) ?? readOptionalString(supplierProbe?.currency),
      platformProductId: readOptionalString(supplierDetails?.platformProductId),
      supplierLocation: readOptionalString(supplierDetails?.supplierLocation),
      sourceLanguage:
        readOptionalString(supplierDetails?.sourceLanguage) ?? readOptionalString(supplierProbe?.pageLanguage),
      heuristicEvaluation: input.parsedResult.supplierEvaluation,
    },
    responseContract: {
      sameProduct: 'boolean',
      imageMatch: 'boolean | null',
      titleMatch: 'boolean | null',
      confidence: 'number between 0 and 1',
      proceed: 'boolean',
      reasons: 'string[]',
      mismatches: 'string[]',
    },
  };

  try {
    const userContent: ChatCompletionContentPart[] = [
      {
        type: 'text',
        text: [
          'Compare the source product and the 1688 supplier candidate.',
          'The first image is the source product image from the app.',
          heroImageDataUrl
            ? 'The second image is the supplier hero image from the 1688 page.'
            : null,
          heroImageDataUrl
            ? 'The third image is the supplier page screenshot.'
            : 'The second image is the supplier page screenshot.',
          JSON.stringify(promptPayload, null, 2),
        ]
          .filter(Boolean)
          .join('\n\n'),
      },
      buildProductScanImagePart(productImageDataUrl),
    ];
    if (heroImageDataUrl) {
      userContent.push(buildProductScanImagePart(heroImageDataUrl));
    }
    userContent.push(
      buildProductScanImagePart(
        productScanBufferToDataUrl(
          screenshotArtifact.content,
          readOptionalString(screenshotArtifact.artifact.mimeType) ?? 'image/png'
        )
      )
    );

    const completion = await runBrainChatCompletion({
      modelId: input.evaluatorConfig.modelId,
      temperature: 0.1,
      maxTokens: 500,
      jsonMode: true,
      messages: [
        {
          role: 'system',
          content: [
            input.evaluatorConfig.systemPrompt,
            'Return only JSON.',
            'Approve only when the 1688 supplier page clearly matches the same product or a clearly compatible sourcing equivalent.',
            'Reject mismatches in visible form factor, pack count, main material cues, or clearly divergent titles.',
          ].join('\n'),
        },
        {
          role: 'user',
          content: userContent,
        },
      ],
    });

    if (!PRODUCT_SCAN_SUPPORTED_IMAGE_RUNTIME_VENDORS.has(completion.vendor)) {
      return createSupplierEvaluation({
        status: 'failed',
        sameProduct: null,
        imageMatch: null,
        titleMatch: null,
        confidence: null,
        proceed: false,
        reasons: [],
        mismatches: [],
        modelId: completion.modelId,
        error:
          '1688 candidate evaluator selected a runtime that does not support image inputs in this flow.',
      });
    }

    const parsed = supplierEvaluatorResponseSchema.parse(JSON.parse(completion.text) as unknown);
    const approved =
      parsed.proceed &&
      parsed.sameProduct &&
      parsed.imageMatch !== false &&
      parsed.titleMatch !== false &&
      parsed.confidence >= input.evaluatorConfig.threshold;

    return createSupplierEvaluation({
      status: approved ? 'approved' : 'rejected',
      sameProduct: parsed.sameProduct,
      imageMatch: parsed.imageMatch,
      titleMatch: parsed.titleMatch,
      confidence: parsed.confidence,
      proceed: approved,
      reasons: [...parsed.reasons],
      mismatches: [...parsed.mismatches],
      modelId: completion.modelId,
      error: null,
    });
  } catch (error) {
    const message =
      error instanceof Error ? error.message : '1688 candidate evaluator failed.';
    return createSupplierEvaluation({
      status: 'failed',
      sameProduct: null,
      imageMatch: null,
      titleMatch: null,
      confidence: null,
      proceed: false,
      reasons: [],
      mismatches: [],
      modelId: input.evaluatorConfig.modelId,
      error: message,
    });
  }
};

